INSERT INTO public.photos VALUES (24773, 'Coromina Industrial c.1967', 'Vista aâ”śÂ®rea a finales de los aâ”śâ–’os sesenta de las instalaciones de Coromina Industrial en Zaragoza, una de las factorâ”śÂˇas de esta empresa con sede en Barcelona, "fâ”śĂ­brica de anhâ”śÂˇdridos carbâ”śâ”‚nico, sulfuroso y carbâ”śâ”‚nico sâ”śâ”‚lido (hielo seco)". Fue inaugurada en 1951 y desmantelada en los ochenta. En primer plano, avenida de San Juan de la Peâ”śâ–’a; a la derecha, Camino de Los Molinos. Fuente: www.facebook.com/photo.php?fbid=1022269901128968&set=...', 1967, 1967, 1967, 'Anos 60', 'EL RABAL', 41.67402500, -0.87077300, '0101000020E610000082ACA7565FDDEBBFDCD7817346D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22991688013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22991688013.webp', 'https://www.flickr.com/photos/zaragozaantigua/22991688013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24785, '&quot;Geplasmetal&quot; c.1990', 'Imagen en altura desde el nâ”¬â•‘ 7-9 de la calle Antonio Tramullas (antiguo Camino de Juslibol) del abandonado complejo industrial de "Geplasmetal" en el Picarral. Esta empresa fue creada en 1958, en el entonces extrarradio de la ciudad, y dedicada a la estampaciâ”śâ”‚n metâ”śĂ­lica e inyecciâ”śâ”‚n de plâ”śĂ­sticos. En los aâ”śâ–’os 60 la empresa creciâ”śâ”‚ y diversificâ”śâ”‚ producciâ”śâ”‚n, y al principio de los aâ”śâ–’os 80, la crisis del sector desembocâ”śâ”‚ en su cierre y traslado al Polâ”śÂˇgono de Cogullada, y al de Malpica. En la imagen, aspecto aâ”śÂ®reo de Geplasmetal, entre la calle de Somport (a la derecha, junto al "Grupo de Viviendas Francisco Franco"), Monte Perdido (al frente), y la calle Antonio Tramullas (en primer plano). A la izquierda, el alabeado linde con la tradicional transformadora industrial del maâ”śÂˇz "Campo Ebro", actual Tereos Syral, que sigue marcando impronta en el barrio. El enruinado solar de Geplasmetal luego fue urbanizado, y todavâ”śÂˇa queda una "pastilla" libre. Fuente visual: Banco de Imâ”śĂ­genes Picarral fotosdelpicarral.blogspot.com.es/', 1990, 1990, 1990, 'Anos 90', 'EL RABAL', 41.67500500, -0.87374400, '0101000020E61000006D7022FAB5F5EBBF78D1579066D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30006637060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30006637060.webp', 'https://www.flickr.com/photos/zaragozaantigua/30006637060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24786, '&quot;TUSA&quot; 1990', 'Imagen previa a la voladura controlada de los edificios principales de la empresa "Talleres Unidos S.A." (TUSA) del Picarral. Creada en 1956 como una de las numerosas empresas metalâ”śâ•‘rgicas que entonces se radicaban en esa zona de la ciudad, en 1965 fue absorbida por la francesa Proclain. Llegâ”śâ”‚ a tener algo mâ”śĂ­s de 1000 trabajadores, y fue la sâ”śÂ®ptima empresa del sector del metal de la provincia. La crisis del sector en el principio de los aâ”śâ–’os 80 terminâ”śâ”‚ con su cierre en 1984, previo acuerdo con la plantilla. Un par de aâ”śâ–’os despuâ”śÂ®s, una nueva "TUSA" (ahora Transportadores Universales S.A.) surgiâ”śâ”‚ en Malpica, de dimensiones mucho mâ”śĂ­s reducidas, que perdura. En la imagen, aspecto de la achaflanada fachada principal de la fâ”śĂ­brica ubicada en el Camino de Juslibol. A la derecha, la calle Monte Perdido, y al fondo, bloques de la Avenida de Salvador Allende. Sobre el enorme solar resultante poco despuâ”śÂ®s se construirâ”śÂˇan varias docenas de adosados, y en el edificio de la fotografâ”śÂˇa serâ”śÂˇa reivindicada vecinalmente una plaza que, denominada Juan Acha en recuerdo a un sacerdote de la vecina parroquia de Belâ”śÂ®n, serâ”śÂˇa inaugurada en 2005. Fuente visual: Banco de Imâ”śĂ­genes Picarral fotosdelpicarral.blogspot.com.es/', 1990, 1990, 1990, 'Anos 90', 'EL RABAL', 41.67082200, -0.87301400, '0101000020E610000094675E0EBBEFEBBFFAB7CB7EDDD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30266919286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30266919286.webp', 'https://www.flickr.com/photos/zaragozaantigua/30266919286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24802, 'Arrabal 1977', 'Imagen capturada desde la altura del paso para trâ”śĂ­fico rodado de la avenida Alcalde Caballero sobre el mar de vâ”śÂˇas y cargadero del Arrabal, y los apartaderos ferroviarios (centro de la imagen) en el entorno a las importantes empresas Fundiciâ”śâ”‚n Rico y Echevarrâ”śÂˇa, y la papelera SAICA. Al fondo, entre las emanaciones fabriles, una torre del Pilar, y la torre y cimborrio de la Seo. A la izquierda, polâ”śÂˇgono industrial Alcalde Caballero. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.67422800, -0.86544000, '0101000020E6100000C4CE143AAFB1EBBF1406651A4DD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33220625882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33220625882.webp', 'https://www.flickr.com/photos/zaragozaantigua/33220625882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24803, 'Avenida Cataluâ”śâ–’a 2010', 'Foto: Pedro Etura. El 26 de octubre de 2010, la primera unidad del nuevo tranvâ”śÂˇa de Zaragoza fue transportada desde la factorâ”śÂˇa de Construcciones y Auxiliar de Ferrocarriles (CAF), en la avenida de Cataluâ”śâ–’a 299, hasta las cocheras de Valdespartera. Se trata del modelo Urbos 3. El 19 de abril de 2011 se inaugurâ”śâ”‚ la primera fase de la lâ”śÂˇnea 1. En la foto, al fondo, el Pilar, con sus dos torres norte en restauraciâ”śâ”‚n. A la derecha, el bloque de la avenida de Cataluâ”śâ–’a 253. Fuente: Heraldo de Aragâ”śâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'EL RABAL', 41.67060800, -0.84497300, '0101000020E6100000A41820D1040AEBBFCE37A27BD6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33387254830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33387254830.webp', 'https://www.flickr.com/photos/zaragozaantigua/33387254830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24807, 'Azucarera del Gâ”śĂ­llego 1931', 'Vista general del complejo fabril de la Azucarera del Gâ”śĂ­llego, entre la carretera de Barcelona (a la izquierda, fuera de plano), el camino de Valimaâ”śâ–’a (a la derecha, fuera de plano) y el râ”śÂˇo Gâ”śĂ­llego (al fondo). Fuente visual: "A Don Benito Lewin y Auser como testimonio de sincero cariâ”śâ–’o y admiraciâ”śâ”‚n, con motivo del XXV Aniversario de su matrimonio le dedican este homenaje sus subordinados: Madrid, a 25 de Diciembre de 1931", en bibliotecavirtualmadrid.org/', 1931, 1931, 1931, 'Anos 30', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34372598115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34372598115.webp', 'https://www.flickr.com/photos/zaragozaantigua/34372598115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24809, 'Camino de la Corbera 1977', 'Vista aâ”śÂ®rea de la factorâ”śÂˇa de la empresa Usâ”śâ”‚n S.A. en el camino de la Corbera Baja, donde se producâ”śÂˇan hierros, aceros, ferreterâ”śÂˇa y maquinaria. Esta empresa habâ”śÂˇa sido fundada en 1790, y en las primeras dâ”śÂ®cadas del siglo XX estaba ubicada, como Antonio Usâ”śâ”‚n, y luego Viuda e Hijos de Antonio Usâ”śâ”‚n, en la avenida de Madrid, con acceso ferroviario a la estaciâ”śâ”‚n de Campo Sepulcro. Aâ”śâ–’os despuâ”śÂ®s, en la ubicaciâ”śâ”‚n de la imagen se situâ”śâ”‚ la empresa Vehizasa. Al norte de la factorâ”śÂˇa circula la carretera de los enlaces, que aâ”śâ–’os despuâ”śÂ®s serâ”śÂˇa denominada avenida de Salvador Allende. A la derecha, enlace con el complejo ferroviario de Arrabal mercancâ”śÂˇas. Fuente visual: revista "Aragâ”śâ”‚n turâ”śÂˇstico y monumental", SIPA.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.67525300, -0.86639500, '0101000020E61000009A5FCD0182B9EBBF50C3B7B06ED64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34799586745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34799586745.webp', 'https://www.flickr.com/photos/zaragozaantigua/34799586745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24810, 'Puente sobre el Gâ”śĂ­llego 1929', 'Imagen capturada desde la margen izquierda izquierda del râ”śÂˇo Gâ”śĂ­llego, y centrada en el estado de la obra de construcciâ”śâ”‚n del nuevo puente tendido entre el desaparecido puente medieval (restos a la derecha), y el veterano puente colgante (a la izquierda), que serâ”śÂˇa desmantelado una vez entrara en servicio el metâ”śĂ­lico nuevo puente. Se trataba de una obra importante, en la estratâ”śÂ®gica carretera nacional de Madrid a Francia. La obra comenzâ”śâ”‚ en 1926 con diseâ”śâ–’o de Primitivo Sagasta, ingeniero de la Jefatura de Obras pâ”śâ•‘blicas de Zaragoza, y en el momento de realizar la imagen estaban bien finalizados los cimientos y alzados, si bien las partes metâ”śĂ­licas sufrâ”śÂˇan un notable retraso que dilatarâ”śÂˇa su inauguraciâ”śâ”‚n y apertura al trâ”śĂ­nsito hasta 1930. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34836131120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34836131120.webp', 'https://www.flickr.com/photos/zaragozaantigua/34836131120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25416, 'Puente sobre el Gâ”śĂ­llego c.1924', 'Imagen del puente colgante sobre el râ”śÂˇo Gâ”śĂ­llego, pero desde abajo, junto a la ribera de este râ”śÂˇo. Por encima, el camino de Barcelona supera esta trinchera, y llega al barrio de Santa Isabel, al fondo. Al poco (1927), este puente serâ”śÂˇa sustituido por otro mâ”śĂ­s resistente (el actual), porque el Gâ”śĂ­llego cada cierto tiempo bajaba con aguas turbulentas que afectaban mucho tambiâ”śÂ®n a los sucesivos puentes que aquâ”śÂˇ se fueron habilitando. Fuente: Instituto Amatller de Arte Hispâ”śĂ­nico (Arxiu Mas).', 1924, 1924, 1924, 'Anos 20', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704095408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704095408.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704095408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25436, 'Puente de Santa Isabel c.1920', 'Puente del Santa Isabel sobre el râ”śÂˇo Gâ”śĂ­llego. Al fondo, el barrio de Santa Isabel. Fuente: Foto Jesâ”śâ•‘s Cormâ”śĂ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24821682231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24821682231.webp', 'https://www.flickr.com/photos/zaragozaantigua/24821682231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25438, 'Puente de Santa Isabel c.1920', 'Paso de ganado ovino ante el puente de Santa Isabel sobre el râ”śÂˇo Gâ”śĂ­llego. Al fondo, el barrio de Santa Isabel. Fuente: Foto Jesâ”śâ•‘s Cormâ”śĂ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24914639425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24914639425.webp', 'https://www.flickr.com/photos/zaragozaantigua/24914639425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25454, 'Ribera del Gâ”śĂ­llego c.1920', 'Imagen capturada en la ribera del râ”śÂˇo Gâ”śĂ­llego mientras un rebaâ”śâ–’o de cabras pasa junto a la arcada superviviente del antiguo puente medieval de piedra del camino de Madrid a Barcelona. Al fondo, depâ”śâ”‚sitos de la azucarera del Gâ”śĂ­llego. El puente colgante sobre el râ”śÂˇo queda hacia la derecha, fuera de plano, y por donde asciende el pastor serâ”śĂ­ construido unos aâ”śâ–’os despuâ”śÂ®s el nuevo puente de hierro que vendrâ”śÂˇa a sustituirlo. Fuente visual: colecciâ”śâ”‚n Jesâ”śâ•‘s Corman, en AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.67127100, -0.84260900, '0101000020E6100000A5164A26A7F6EABF69E04735ECD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40141577071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40141577071.webp', 'https://www.flickr.com/photos/zaragozaantigua/40141577071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25901, 'Trolebuses 1954', 'Imagen de la inauguraciâ”śâ”‚n del nuevo servicio de trolebuses de la linea "Gâ”śĂ­llego", entre el Coso, esquina calle de Blancas, y hasta el puente del Gâ”śĂ­llego. La captura se ha realizado en el final de lâ”śÂˇnea, en la avenida de Cataluâ”śâ–’a. Las mâ”śĂ­quinas estâ”śĂ­n recibiendo una bendiciâ”śâ”‚n conforme a la ortodoxia cristiana catâ”śâ”‚lica por parte del pâ”śĂ­rroco de Altabâ”śĂ­s, Pedro Martâ”śÂˇnez. El alcalde, Luis Gâ”śâ”‚mez Laguna, con gafas de sol. A su izquierda, altâ”śÂˇsimo y entrevâ”śÂˇas, el seâ”śâ–’or gobernador givil de la provincia, Josâ”śÂ® Manuel Pardo de Santayana. A su derecha, el gobernador militar, general Arteaga. Fuente visual: â”śĂĽngel de Uâ”śâ–’a, "Luis Gâ”śâ”‚mez Laguna", DGA, 1993.', 1954, 1954, 1954, 'Anos 50', 'EL RABAL', 41.67100400, -0.84390800, '0101000020E610000009A69A594B01EBBF1BBE8575E3D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19318260688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19318260688.webp', 'https://www.flickr.com/photos/zaragozaantigua/19318260688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25917, 'San Juan de la Peâ”śâ–’a 1969', 'Excepcional imagen capturada desde el interior de una de las cinco unidades de los tranvâ”śÂˇas articulados (serie 251-255), que prestaban servicio en la lâ”śÂˇnea 10 "Academia", un poco antes de cruzarse con la unidad 254. Posiblemente, el escenario sea la calle de San Juan de la Peâ”śâ–’a, direcciâ”śâ”‚n AGM, poco despuâ”śÂ®s del arranque del camino de los Molinos, y tras haber pasado junto a "Coromina Industrial". A la izquierda, viviendas inmediatas a Campo Ebro Industrial. Tras la clausura de esta lâ”śÂˇnea, en enero de 1971, las cinco unidades referidas fueron desguazadas. El conductor, al mando del regulador que controlaba la marcha y frenado del tranvâ”śÂˇa. Destaca la caracterâ”śÂˇstica manivela. Fuente visual: Foto John Scragg, a travâ”śÂ®s de www.forotrenes.com/', 1969, 1969, 1969, 'Anos 60', 'EL RABAL', 41.67500500, -0.87120100, '0101000020E610000087C267EBE0E0EBBF78D1579066D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31030868792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31030868792.webp', 'https://www.flickr.com/photos/zaragozaantigua/31030868792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26001, 'Azucarera Gâ”śĂ­llego 1957', 'Vista en altura del complejo fabril de la Azucarera del Gâ”śĂ­llego, entre la carretera de Barcelona, en primer plano, y el camino de Valimaâ”śâ–’a y el râ”śÂˇo Gâ”śĂ­llego al fondo. Muy cerca, a la izquierda, queda el puente de Santa Isabel, de acceso al barrio del mismo nombre, visible al otro lado del râ”śÂˇo. Movera, a la derecha. Fuente: Foto Marâ”śÂˇn Chivite.', 1957, 1957, 1957, 'Anos 50', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21943727798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21943727798.webp', 'https://www.flickr.com/photos/zaragozaantigua/21943727798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26018, 'Râ”śÂˇo Gâ”śĂ­llego 1974', 'Imagen en altura desde los recientes bloques de viviendas cercanos al puente del râ”śÂˇo Gâ”śĂ­llego, ya en el barrio de Santa Isabel, con una panorâ”śĂ­mica vista dirigiendo el objetivo hacia la ciudad. En primer tâ”śÂ®rmino, el râ”śÂˇo. En la margen derecha, el solar donde estuviera la Azucarera del Gâ”śĂ­llego entre 1913 y 1967. Detrâ”śĂ­s, la carretera de Barcelona como uno de los nuevos ejes de desarrollo industrial, y algâ”śâ•‘n extraâ”śâ–’o bloque de viviendas en medio de la nada. El "ferroducto" sobre la huerta antecede a los primeros megabloques de Vadorrey. Al fondo, chimeneas (azucarera del Arrabal) y torres (Pilar, Seo...) anuncian a la vieja ciudad. Fuente: Gerardo Sancho Ramo (Archivo Pâ”śâ•‘blico Municipal).', 1974, 1974, 1974, 'Anos 70', 'EL RABAL', 41.66990800, -0.84194400, '0101000020E61000009207228B34F1EABF15AA9B8BBFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23860348119.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23860348119.webp', 'https://www.flickr.com/photos/zaragozaantigua/23860348119/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26072, 'Picarral 1955', 'Vista aâ”śÂ®rea del Picarral sobrevolando el entorno de las instalaciones del Consorcio Agrâ”śÂˇcola Industrial Textil Aragonâ”śÂ®s, S.A., Caitasa, que en esta imagen queda en segundo plano, tras el camino de Juslibol. En primer tâ”śÂ®rmino, el pionero bloque de viviendas de la primera fase del Grupo de Viviendas "Francisco Franco", en esta despejada y agrâ”śÂˇcola zona del Picarral delimitada entre el camino de Juslibol, el brazal del Canal de Piedra del escorredero de Juslibol, y la carretera de Huesca, que aquâ”śÂˇ queda a la izquierda y fuera de plano. Este bloque fue proyectado por los arquitectos Josâ”śÂ® de Yarza y Josâ”śÂ® Beltrâ”śĂ­n, y constaba de 120 viviendas de 45 a 50 m2, modestas porque sus habitantes serâ”śÂˇan familias de trabajadores, y 8 tiendas con acceso por la nueva calle de Anzâ”śĂ­nigo. Aunque este bloque fue terminado en 1949, sâ”śâ”‚lo empezâ”śâ”‚ a ser ocupado en 1952. Los otros bloques del grupo serâ”śÂˇan construido a partir de 1957, y este entorno comenzarâ”śÂˇa entonces a transformarse radicalmente.', 1955, 1955, 1955, 'Anos 50', 'EL RABAL', 41.67429800, -0.87362700, '0101000020E610000009E23C9CC0F4EBBF0DE198654FD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50839765593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50839765593.webp', 'https://www.flickr.com/photos/zaragozaantigua/50839765593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21023, 'Balsas de Ebro Viejo 1867', '"Plano topogrâ”śĂ­fico de las balsas denominadas de Ebro biejo y proyecto para su desecaciâ”śâ”‚n", Segundo Dâ”śÂˇaz, Zaragoza, 20 de julio de 1867. Plano de la Margen Izquierda de Zaragoza, orientado con el norte a la derecha. Se inicia en el puente de Piedra (abajo a la izquierda). Mâ”śĂ­s arriba el escorredero principal de las balsas de Ebro viejo, antes de llegar a la arboleda de Macanaz. La representaciâ”śâ”‚n grâ”śĂ­fica limita al norte con el camino de la Hortilla y al sur con el de Juslibol. Fuente: AMZ.', 1867, 1867, 1867, 'Siglo XIX', 'EL RABAL', 41.66026200, -0.87538900, '0101000020E61000008EE6C8CA2F03ECBF5265187783D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21039158291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21039158291.webp', 'https://www.flickr.com/photos/zaragozaantigua/21039158291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21196, 'Lavandera c.1890', 'â”śĂ´leo titulado "Lavandera a las afueras de Zaragoza" realizado por Joaquâ”śÂˇn Pallarâ”śÂ®s y Allustante durante su etapa como profesor de "Dibujo del Antiguo" de la Escuela de Bellas Artes, y a la vez conservador de los fondos pictâ”śâ”‚ricos del Museo Provincial en el antiguo convento de Santa Fe. El fondo reconocible de las torres de Santa Marâ”śÂˇa Magdalena, de la Seo, y de la inconclusa de Santiago del templo del Pilar, nos sitâ”śâ•‘a probablemente en el entorno del râ”śÂˇo Gâ”śĂ­llego.', 1890, 1890, 1890, 'Siglo XIX', 'EL RABAL', 41.66268500, -0.84556100, '0101000020E6100000E0BC38F1D50EEBBF5F46B1DCD2D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50973718003.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50973718003.webp', 'https://www.flickr.com/photos/zaragozaantigua/50973718003/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21213, 'Estaciâ”śâ”‚n del Norte 1900', 'Equipo laboral de la estaciâ”śâ”‚n ferroviaria del Norte o Arrabal, en 1900. Habâ”śÂˇa sido inaugurada en 1861. Fuente visual: Archivo Asociaciâ”śâ”‚n de vecinos Tâ”śÂˇo Jorge Arrabal, en Cristina Mâ”¬Â¬ Palacio Jaâ”śÂ®n, El re-uso de la arquitectura industrial: a propâ”śâ”‚sito de las harineras, fundiciones y azucareras en Aragâ”śâ”‚n en el cambio de siglo, Universidad de Zaragoza, 2013.', 1900, 1900, 1900, 'Anos 1900', 'EL RABAL', 41.66012000, -0.87145900, '0101000020E610000072C119FCFDE2EBBFBFB7E9CF7ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15037805385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15037805385.webp', 'https://www.flickr.com/photos/zaragozaantigua/15037805385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21412, 'Nueva Harinera 1913', 'En 1910 fue constituida la sociedad "Hijos y sobrino de Juan Solans (Lerâ”śÂˇn)", que construyâ”śâ”‚ la fâ”śĂ­brica "Nueva Harinera" en la calle Arrabal nâ”¬â•‘ 260, junto a la carretera de Barcelona y la estaciâ”śâ”‚n de ferrocarril Norte, con apartadero propio. Muy cerca, con diseâ”śâ–’o de Miguel â”śĂĽngel Navarro, fue construido un "hotel", o villa, del propietario harinero, Juan Solans. Esta harinera era, por su capacidad productiva, la mayor de la ciudad. Pocos aâ”śâ–’os despuâ”śÂ®s de la muerte de Juan Solans (1926), en 1931 una nueva sociedad capitalista (Harinas Solans, S.A.) se hizo con las riendas de esta harinera, que fue redenominada "Harinas Solans". Estuvo activa hasta su cierre en 1985. En 1998 fue derribada, y el entorno reurbanizado. Fuente visual: "Heraldo de Madrid", octubre 1913.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.66204400, -0.87001200, '0101000020E6100000E814E46723D7EBBFAB4198DBBDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27907331021.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27907331021.webp', 'https://www.flickr.com/photos/zaragozaantigua/27907331021/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21653, 'Balsas de Ebro Viejo 1923', 'Imagen capturada en las Balsas de Ebro Viejo con un entraâ”śâ–’able posado del castizo y tradicionalista poeta Alberto Casaâ”śâ–’al Shakery con motivo de su doble reconocimiento municipal tras la imposiciâ”śâ”‚n de la Medalla de Oro de la ciudad y la entrega del tâ”śÂˇtulo de Hijo Adoptivo. Al fondo, como no podâ”śÂˇa ser de otra forma, el templo del Pilar al otro lado del Ebro.', 1923, 1923, 1923, 'Anos 20', 'EL RABAL', 41.66231600, -0.87684600, '0101000020E6100000FC1BB4571F0FECBF0BCF4BC5C6D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52130179262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52130179262.webp', 'https://www.flickr.com/photos/zaragozaantigua/52130179262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21661, 'Arrabal 1921', 'Fotograma de un reportaje realizado durante el breve paso por Zaragoza del Ministro de Fomento Juan de la Cierva Peâ”śâ–’afiel a principios de junio de ese aâ”śâ–’o y centrado en la visita a la Nueva Harinera de Hijos y Sobrino de Solans sita en el Arrabal, en las traseras del depâ”śâ”‚sito de locomotoras de la Estaciâ”śâ”‚n del Norte. Aquâ”śÂˇ figura Juan Solans Solans (sobrino del fundador de la empresa precedente Juan Solans Lerâ”śÂˇn), tras el caballero que seâ”śâ–’ala al ministro varios montones de harina procesada en la fâ”śĂ­brica segâ”śâ•‘n distintos tipos de molienda. A su paso por la ciudad el ministro fue acompaâ”śâ–’ado en todo momento por sus fervientes partidarios del "comitâ”śÂ® ciervista de Zaragoza", câ”śÂ®lula local de la facciâ”śâ”‚n polâ”śÂˇtica considerada de extrema derecha dentro del conservadurismo autoritario, que bajo la etiqueta de "Conservadores ciervistas" por el apellido de este polâ”śÂˇtico murciano, en las elecciones a Cortes de diciembre del aâ”śâ–’o anterior habâ”śÂˇa logrado 23 diputados en todo el paâ”śÂˇs.', 1921, 1921, 1921, 'Anos 20', 'EL RABAL', 41.66152300, -0.86935700, '0101000020E6100000B98E71C5C5D1EBBFA24621C9ACD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54691566687.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54691566687.webp', 'https://www.flickr.com/photos/zaragozaantigua/54691566687/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21947, 'Estaciâ”śâ”‚n del Norte c.1940', 'Imagen, con el telâ”śâ”‚n de fondo de las torres de la Seo, Altabâ”śĂ­s, y el Pilar, de buena parte del complejo ferroviario de la antigua estaciâ”śâ”‚n del Norte, que fuera la primera inaugurada de la ciudad, en 1861. El â”śâ•‘ltimo tren de pasajeros circulâ”śâ”‚ por aquâ”śÂˇ en los aâ”śâ–’os 70 del pasado siglo, quedando unos aâ”śâ–’os como terminal de mercancâ”śÂˇas, hasta su clausura a principios de los aâ”śâ–’os 80. Desde diciembre de 2004 uno de los dos edificios principales de la estaciâ”śâ”‚n del Norte (el de al izquierda de la imagen) funciona como centro câ”śÂˇvico "Estaciâ”śâ”‚n del Norte" del Arrabal. Fuente visual: Fundaciâ”śâ”‚n de los Ferrocarriles Espaâ”śâ–’oles.', 1940, 1940, 1940, 'Anos 40', 'EL RABAL', 41.66004600, -0.87178000, '0101000020E6100000F6D1A92B9FE5EBBF85ED27637CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16370172684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16370172684.webp', 'https://www.flickr.com/photos/zaragozaantigua/16370172684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22164, 'Arrabal 1958', 'Aâ”śÂ®rea visual de la Maquinista y Fundiciones del Ebro, S.A. tras la ampliaciâ”śâ”‚n acometida en los aâ”śâ–’os 50, donde se construyeron algunos de sus mâ”śĂ­s representativos edificios, hasta su derribo: el gran almacâ”śÂ®n de modelos con su referente torre, y las grandes naves de fundiciâ”śâ”‚n y caldererâ”śÂˇa. Bajo ellas, andamios para levantar las nuevas naves de montaje. Los nuevos edificios destacan de los anteriores, por su escala. A la izquierda de la fâ”śĂ­brica, vâ”śÂˇas y depâ”śâ”‚sito de locomotoras de la estaciâ”śâ”‚n del Norte. Al norte, la Nueva Harinera de Solans, y los primeros depâ”śâ”‚sitos de remolacha de la azucarera del Arrabal, cuyos edificios principales y chimeneas quedan fuera de plano. Fuente visual: aportaciâ”śâ”‚n personal de Arturo Bressel Viâ”śâ–’uales.', 1958, 1958, 1958, 'Anos 50', 'EL RABAL', 41.66099500, -0.87094900, '0101000020E6100000247CEF6FD0DEEBBFE6E8F17B9BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30819725756.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30819725756.webp', 'https://www.flickr.com/photos/zaragozaantigua/30819725756/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22353, 'Alcoholera Ebro 1960', 'Alcoholera del Arrabal en una imagen de sus pequeâ”śâ–’as instalaciones fabriles ubicadas frente al â”śĂ­rea sur del Polâ”śÂˇgono Ebro Viejo. Fue fundada en 1911 como Azucarera del Ebro S.A., asociada luego con la Compaâ”śâ–’â”śÂˇa de Alcoholes de Bilbao S.A., a la que absorbiâ”śâ”‚ formando Ebro Compaâ”śâ–’â”śÂˇa de Azâ”śâ•‘cares y Alcoholes, Ecaya. En los aâ”śâ–’os treinta fue Compaâ”śâ–’â”śÂˇa de Alcoholes de Aragâ”śâ”‚n, y en su â”śâ•‘ltima etapa, hasta cerrar en 1971, Alcoholera Ebro S.A. La escena estâ”śĂ­ tomada en el patio de ingreso desde la avenida de San Juan de la Peâ”śâ–’a nâ”¬â•‘ 24-32. A la izquierda, zona de jardines y â”śĂ­rboles. Tras los edificios de la fâ”śĂ­brica de la imagen estaban los depâ”śâ”‚sitos de alcohol y un apartadero propio que conectaba con la red ferroviaria. La lâ”śÂˇnea 4. Arrabal del tranvâ”śÂˇa tenâ”śÂˇa su terminal justo al lado. Tras su clausura, fue derribada, y el entorno profundamente reurbanizado. Fuente visual: "150 aâ”śâ–’os de ferrocarril en Zaragoza", 2011.', 1960, 1960, 1960, 'Anos 60', 'EL RABAL', 41.66335000, -0.87212000, '0101000020E61000002A00C63368E8EBBF9BE61DA7E8D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20615409492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20615409492.webp', 'https://www.flickr.com/photos/zaragozaantigua/20615409492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22506, 'Av. de Cataluâ”śâ–’a 1960', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 42 de la avenida de Cataluâ”śâ–’a, esquinero con la avenida del Puente del Pilar, y centrada en el ingreso a la fâ”śĂ­brica de Maquinista y Fundiciones del Ebro sita en el nâ”¬â•‘ 17-23 de la avenida de Cataluâ”śâ–’a, con detalle de las modernas naves de caldererâ”śÂˇa y fundiciâ”śâ”‚n de esta factorâ”śÂˇa. Tras ellas despunta la referencial torre de los almacenes de modelos, lindantes con los andenes de la estaciâ”śâ”‚n del Arrabal. En primer tâ”śÂ®rmino, postes de suministro elâ”śÂ®ctrico de los tranvâ”śÂˇas de las lâ”śÂˇneas del Gâ”śĂ­llego y del Barrio de Jesâ”śâ•‘s.', 1960, 1960, 1960, 'Anos 60', 'EL RABAL', 41.66040800, -0.86967900, '0101000020E61000005393E00D69D4EBBF2502D53F88D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50325635123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50325635123.webp', 'https://www.flickr.com/photos/zaragozaantigua/50325635123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22550, 'Barrio de La Jota c.1978', 'Vista del Barrio de La Jota, vertebrada en torno a la avenida de Cataluâ”śâ–’a (izquierda). En primer plano, la chimenea y complejo de CLUZASA. Detrâ”śĂ­s de los altos bloques, el extenso Grupo de Viviendas "Parcelaciâ”śâ”‚n Damâ”śĂ­n", asâ”śÂˇ llamadas por el nombre de la constructora que las realizâ”śâ”‚ (Obras y Construcciones Damâ”śĂ­n), con viviendas de una planta con espacio posterior para jardâ”śÂˇn y corral... la "Ciudad Jardâ”śÂˇn" de la Margen Izquierda.', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.66077700, -0.86510800, '0101000020E61000004641F0F8F6AEEBBF79793A5794D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15024300906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15024300906.webp', 'https://www.flickr.com/photos/zaragozaantigua/15024300906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22553, 'La Azucarera c.1971', 'Con las siglas de la SGAE, Sociedad General Azucarera de Espaâ”śâ–’a, puerta de entrada a la Azucarera del Arrabal. Esta factorâ”śÂˇa transformadora de remolacha, construida en 1893 a espaldas de la homâ”śâ”‚nima estaciâ”śâ”‚n de tren con el nombre de La Azucarera de Aragâ”śâ”‚n, dejâ”śâ”‚ de cumplir su funciâ”śâ”‚n en 1966. Tras la radical transformaciâ”śâ”‚n del edificio y su entorno, esta es la actual calle de las Chimeneas, que confluye a la derecha con la de Mas de las Matas.', 1971, 1971, 1971, 'Anos 70', 'EL RABAL', 41.66411600, -0.86810200, '0101000020E61000003DF372D87DC7EBBF0B60CAC001D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15035027551.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15035027551.webp', 'https://www.flickr.com/photos/zaragozaantigua/15035027551/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22576, 'Valle de Oza 1970', 'Archivo Municipal. Gerardo Sancho Ramo. 1970. Esperando el bus. Imagen de la calle Valle de Oza.', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.66389500, -0.87533700, '0101000020E6100000F0517FBDC202ECBF2C7DE882FAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15428414889.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15428414889.webp', 'https://www.flickr.com/photos/zaragozaantigua/15428414889/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22648, 'Alcalde Caballero 1979', 'Comienzo de las obras de construcciâ”śâ”‚n del colegio pâ”śâ•‘blico La Estrella, en la avenida Alcalde Caballero (abajo). A la derecha, la calle Pedro Lâ”śĂ­zaro. Al fondo, el Pilar y las chimeneas de la Azucarera del Arrabal. Fuente: www.facebook.com/photo.php?fbid=10206445882658631&set...', 1979, 1979, 1979, 'Anos 70', 'EL RABAL', 41.66339700, -0.85795300, '0101000020E6100000AE2990D95974EBBFDCA16131EAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20937137925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20937137925.webp', 'https://www.flickr.com/photos/zaragozaantigua/20937137925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22656, 'CAMPSA c.1975', 'Aâ”śÂ®rea visual de la instalaciâ”śâ”‚n de almacenamiento y distribuciâ”śâ”‚n de gasolina de Campsa, ubicada en 1945 entre la carretera de Huesca y el ferrocarril que llegaba hasta la estaciâ”śâ”‚n del Arrabal. En la imagen y a la izquierda, la avenida de San Juan de la Peâ”śâ–’a, remodelada y asfaltada tras la supresiâ”śâ”‚n de la tranviaria lâ”śÂˇnea 4. Arrabal. A la derecha, vâ”śÂˇas del ferrocarril y Polâ”śÂˇgono Industrial Cogullada. En la parte superior, Hierros Alfonso S.A., la fâ”śĂ­brica de la Uniâ”śâ”‚n Alcoholera Espaâ”śâ–’ola, y la papelera Saica. Poco despuâ”śÂ®s, estos depâ”śâ”‚sitos serâ”śĂ­n desmantelados por razones de seguridad, en cumplimiento de la ordenanza sobre almacenamiento y transporte de productos peligrosos. En 1976, la empresa inaugurarâ”śĂ­ una nueva instalaciâ”śâ”‚n en Monzalbarba. Parte del solar se habilitarâ”śĂ­ para prolongar la calle Marquâ”śÂ®s de la Cadena y dar continuidad a la calle del Valle de Broto.', 1975, 1975, 1975, 'Anos 70', 'EL RABAL', 41.66580500, -0.87068600, '0101000020E6100000C7B8E2E2A8DCEBBFB341261939D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21810662093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21810662093.webp', 'https://www.flickr.com/photos/zaragozaantigua/21810662093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22709, 'San Juan de la Peâ”śâ–’a 1971', 'Imagen del arranque de la calle de San Juan de la Peâ”śâ–’a, con la pareja de unidades de la serie 200 (la 228, de regreso al "centro", y la 223, en direcciâ”śâ”‚n a la terminal de la lâ”śÂˇnea) que entonces prestaban servicio en el tranvâ”śÂˇa del "Arrabal", o Lâ”śÂˇnea 4. A la derecha, muros del antiguo depâ”śâ”‚sito de "Hierros Alfonso S.A.", cuyas traseras eran recayentes a las vâ”śÂˇas del ferrocarril que llegaba a la estaciâ”śâ”‚n del Arrabal, y en el centro, el moderno, pionero y alpino bloque del nâ”¬â•‘ 10 de San Juan de la Peâ”śâ–’a. A la izquierda, fuera de plano, la calle valle de Zuriza, conducente al reciente parque del Tâ”śÂˇo Jorge, antiguo de Jorge Ibort. Apenas dos meses despuâ”śÂ®s de esta imagen, la lâ”śÂˇnea del "Arrabal" fue clausurada. Fuente visual: www.ebay.es/', 1971, 1971, 1971, 'Anos 70', 'EL RABAL', 41.66194900, -0.87292900, '0101000020E6100000075C57CC08EFEBBF594FADBEBAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28746247930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28746247930.webp', 'https://www.flickr.com/photos/zaragozaantigua/28746247930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22712, 'San Juan de la Peâ”śâ–’a 1971', 'Imagen de la unidad 223 de la lâ”śÂˇnea 4 del tranvâ”śÂˇa ("Arrabal") regresando a la ciudad desde su norteâ”śâ–’a terminal por la calle de San Juan de la Peâ”śâ–’a, capturada a su paso por las antiguas instalaciones de almacenamiento de la empresa CAMPSA. A la izquierda, fuera de plano, el Grupo de Viviendas "Balsas de Ebro Viejo", y al fondo, tras los depâ”śâ”‚sitos, emergen las pareadas chimeneas de la veterana "Alcoholera". A la derecha, tambiâ”śÂ®n fuera de plano, las vâ”śÂˇas del ferrocarril que conduce a la estaciâ”śâ”‚n "Norte", y el desarrollista polâ”śÂˇgono industrial Cogullada. Este entorno fue luego notablemente modificado, incluyendo la clausura y desmantelamiento del servicio pâ”śâ•‘blico tranviario. Fuente visual: www.ebay.es/', 1971, 1971, 1971, 'Anos 70', 'EL RABAL', 41.66566800, -0.87153400, '0101000020E61000001C446B459BE3EBBF32FFE89B34D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29009419816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29009419816.webp', 'https://www.flickr.com/photos/zaragozaantigua/29009419816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22720, 'Estaciâ”śâ”‚n del Norte 1974', 'Imagen de una locomotora a vapor "Mikado" reciâ”śÂ®n salida de la estaciâ”śâ”‚n del Arrabal, en direcciâ”śâ”‚n norte. Al fondo, el complejo de la Maquinista y Fundiciones del Ebro S.A. Estos artefactos estuvieron prestando servicio desde 1953, y hasta 1975, cuando en Espaâ”śâ–’a se dio punto final a la utilizaciâ”śâ”‚n comercial de las locomotoras de vapor. Fuente visual: es.slideshare.net/', 1974, 1974, 1974, 'Anos 70', 'EL RABAL', 41.66086400, -0.87125700, '0101000020E610000080272D5C56E1EBBF478D093197D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30165423083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30165423083.webp', 'https://www.flickr.com/photos/zaragozaantigua/30165423083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22721, 'Arrabal 1970', 'Imagen de un coche de viajeros tipo "Costa" de la MZA estacionado en una de las vâ”śÂˇas del complejo de la estaciâ”śâ”‚n del Norte. La captura se ha realizado a la altura del gran depâ”śâ”‚sito de locomotoras. A la derecha, nave de los talleres Izuzquiza-Arana, y a la izquierda, chimeneas de la Alcoholera del Ebro. La entrada a ambas instalaciones estaba en la calle de San Juan de la Peâ”śâ–’a, y ambas tenâ”śÂˇan muelle ferroviario. Fuente visual: Foto Josep Ferratâ”śÂ®, en www.spanishrailway.com/', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.66327200, -0.87127600, '0101000020E61000003145B9347EE1EBBF1F2DCE18E6D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30186919393.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30186919393.webp', 'https://www.flickr.com/photos/zaragozaantigua/30186919393/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22732, 'Estaciâ”śâ”‚n Norte 1974', 'Imagen de una vaporosa locomotora "Mikado" maniobrando en el mar de vâ”śÂˇas de la estaciâ”śâ”‚n del Norte. A la derecha, el enorme almacâ”śÂ®n de modelos y la torre de Maquinista y Fundiciones del Ebro, y la pareja de chimeneas de la azucarera del Arrabal. Al fondo, los antiguos talleres, chimenea, y depâ”śâ”‚sito de locomotoras. A la izquierda, enlaces ferroviarios a los muelles de las instalaciones industriales de la zona. La imagen se ha capturado desde el andâ”śÂ®n central de la estaciâ”śâ”‚n, que queda justo a la espalda del fotâ”śâ”‚grafo. Fuente visual: Foto Escudâ”śÂ®, a travâ”śÂ®s de www.forotrenes.com/', 1974, 1974, 1974, 'Anos 70', 'EL RABAL', 41.66089100, -0.87165200, '0101000020E610000097C62FBC92E4EBBF419C871398D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31142919896.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31142919896.webp', 'https://www.flickr.com/photos/zaragozaantigua/31142919896/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22764, 'Camino de Juslibol 1978', 'Imagen capturada en un luminoso sector del salvaje oeste del Picarral, en paralelo al antiguo y arbolado camino de Juslibol, donde los grupos de viviendas "Balsas de Ebro Viejo" (inmediato), "Teniente Ortiz de Zâ”śĂ­rate" (detrâ”śĂ­s), y "Teniente Polanco" (a continuaciâ”śâ”‚n). Al fondo, instalaciones de los Talleres Unidos SA, y las traseras de algunos bloques recayentes a la avenida de San Juan de la Peâ”śâ–’a. La acumulaciâ”śâ”‚n de accidentes orogâ”ĽĂ˛â”śĂ­ficos artificiales parece no suponer impedimento serio para la movilidad de los montaraces vecinos del entorno. Tiempo despuâ”śÂ®s, aquâ”śÂˇ se construirâ”śÂˇa el moderno y municipal parque de bomberos nâ”¬â•‘ 1, con entrada principal por Valle de Broto, hasta entonces ubicado provisionalmente en el antiguo cuartel de Pontoneros de Madre Rafols. Fuente visual: Banco de Imâ”śĂ­genes/Asociaciâ”śâ”‚n de Vecinos Barrio de San Josâ”śÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.66782400, -0.87518200, '0101000020E61000002B8881AE7D01ECBFF1BDBF417BD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33051240092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33051240092.webp', 'https://www.flickr.com/photos/zaragozaantigua/33051240092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22844, 'CLUZASA 1989', 'Demoliciâ”śâ”‚n de las instalaciones de Cluzasa, Centrales Lecheras Unidas de Zaragoza S.A., donde la calle del Marquâ”śÂ®s de la Cadena intersecciona con las calles de Josâ”śÂ® Oto y del Molino de las Armas, en el barrio de La Jota. Esta empresa lâ”śĂ­ctea habâ”śÂˇa sido fundada en 1956 mediante la uniâ”śâ”‚n de varias granjas dedicadas al reparto del producto a domicilio. Por aquâ”śÂˇ pasarâ”śĂ­ luego el trâ”śĂ­fico rodado del Segundo Cinturâ”śâ”‚n, procedente del puente de la Uniâ”śâ”‚n y de la plaza de Mozart.', 1989, 1989, 1989, 'Anos 80', 'EL RABAL', 41.66096900, -0.86444300, '0101000020E61000003332C85D84A9EBBFBD55D7A19AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15131276905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15131276905.webp', 'https://www.flickr.com/photos/zaragozaantigua/15131276905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22909, 'Marquâ”śÂ®s de la Cadena 1985', 'Ruinas de algunas naves de la empresa de transformaciâ”śâ”‚n metâ”śĂ­lica Hierros Alfonso, con el muro que las separaba a la izquierda de los antiguos depâ”śâ”‚sitos de Campsa y donde en 2007 se inaugurâ”śâ”‚ el Instituto de Educaciâ”śâ”‚n Secundaria La Azucarera, en una industrial zona embuchada entre la avenida de San Juan de la Peâ”śâ–’a y las vâ”śÂˇas del ferrocarril que desde la estaciâ”śâ”‚n del arrabal se dirigâ”śÂˇan a Huesca. Al fondo y la izquierda, esquinero bloque con la calle del Valle de Broto integrado en el Grupo de Viviendas Balsas de Ebro Viejo. La orientaciâ”śâ”‚n de los esqueletos de las naves de primer tâ”śÂ®rmino indica el sentido que aâ”śâ–’os despuâ”śÂ®s seguirâ”śĂ­ la prolongaciâ”śâ”‚n del camino del Marquâ”śÂ®s de la Cadena, cuando desde el Puente de la Uniâ”śâ”‚n conforme aquâ”śÂˇ su â”śâ•‘ltimo tramo dentro del segundo cinturâ”śâ”‚n de ronda. Nuevas y mâ”śĂ­s modernas naves de la misma empresa sustituirâ”śĂ­n a las de la imagen, inmediatas a la factorâ”śÂˇa de Saica. Fuente visual: "Banco de imâ”śĂ­genes del Picarral" (As. de Vecinos del Picarral).', 1985, 1985, 1985, 'Anos 80', 'EL RABAL', 41.66622900, -0.87033200, '0101000020E61000005531957EC2D9EBBFCA52EBFD46D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22444402862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22444402862.webp', 'https://www.flickr.com/photos/zaragozaantigua/22444402862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22922, 'Picarral 1983', 'Panorama del Picarral desde la torre del nuevo Parque de Bomberos de la calle del Valle de Broto. Tras la inmediata calle del Pantano de Yesa, grâ”śâ•‘as de construcciâ”śâ”‚n de los bloques recayentes a la calle Sotonera, y detrâ”śĂ­s el extenso complejo fabril textil de Caitasa, del que emerge su chimenea. A la derecha y tras el camino de Juslibol, la fâ”śĂ­brica de maquinaria pesada Proclain-TUSA, que cesâ”śâ”‚ actividad a finales de 1984 dejando en el paro a sus 424 trabajadores. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1983, 1983, 1983, 'Anos 80', 'EL RABAL', 41.66834500, -0.87523500, '0101000020E6100000E010AAD4EC01ECBFFAB836548CD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29674484854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29674484854.webp', 'https://www.flickr.com/photos/zaragozaantigua/29674484854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22923, 'Calle Gracia Gazulla 1983', 'Imagen del antiguo nâ”¬â•‘ 7 de la calle Fernando Gracia Gazulla, edificio propiedad del Ministerio de Obras Pâ”śâ•‘blicas y Urbanismo, que fue la provisional sede del Consejo Municipal de Distrito nâ”¬â•‘ 10, entidad que abarcaba todos los barrios de la margen izquierda del Ebro, y que tras la recuperaciâ”śâ”‚n de la democracia municipal fue el antecedente inmediato de la posterior Junta de Distrito del Rabal. Esta pequeâ”śâ–’a manzana de edificios fue luego derribada, y su espacio incorporado al parque del Tâ”śÂˇo Jorge, antiguo de Jorge Ibort. Fuente visual: revista Nuestra Zaragoza.', 1983, 1983, 1983, 'Anos 80', 'EL RABAL', 41.66254200, -0.87822900, '0101000020E6100000D7C22CB4731AECBFFC1C1F2DCED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29913294004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29913294004.webp', 'https://www.flickr.com/photos/zaragozaantigua/29913294004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22924, 'Barrionuevo 1983', 'Josâ”śÂ® Barrionuevo Peâ”śâ–’a, ministro del Interior en el primer gobierno del PSOE salido de las elecciones generales de octubre de 1982, en una imagen capturada durante la inauguraciâ”śâ”‚n oficial del nuevo Parque de Bomberos sito en la calle del Valle de Broto, la vâ”śÂˇspera del 23 de abril de ese aâ”śâ–’o. A la izquierda, el alcalde Ramâ”śâ”‚n Sainz de Varanda. Casualmente, en 1983 comenzaron su andadura los parapoliciales y autodenominados Grupos Antiterroristas de Liberaciâ”śâ”‚n, GAL. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1983, 1983, 1983, 'Anos 80', 'EL RABAL', 41.66747200, -0.87561100, '0101000020E61000004792205C0105ECBF737FF5B86FD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29990562340.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29990562340.webp', 'https://www.flickr.com/photos/zaragozaantigua/29990562340/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22926, 'Salvador Allende 1983', 'Imagen capturada desde la torre del nuevo Parque de Bomberos sito en la calle Valle de Broto, con interesante visual del desarrollo urbanâ”śÂˇstico en la zona delimitada por la Avenida de Salvador Allende, las calles Isla Graciosa, e Isla de Gran Canaria, donde los bloques en construcciâ”śâ”‚n inmediatos, y detrâ”śĂ­s, la calle Violeta Parra, y al fondo, la Avenida de los Pirineos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1983, 1983, 1983, 'Anos 80', 'EL RABAL', 41.66847100, -0.87659200, '0101000020E61000006CED7DAA0A0DECBF86A92D7590D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30253047606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30253047606.webp', 'https://www.flickr.com/photos/zaragozaantigua/30253047606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22978, 'Casa Solans aâ”śâ–’os 90', 'La modernista Casa Solans (Miguel â”śĂĽngel Navarro, 1921) en los aâ”śâ–’os 90 del siglo XX, en estado de abandono, con las ventanas tapiadas. Sita en la avenida de Cataluâ”śâ–’a 60. En 2003 comenzâ”śâ”‚ a restaurarse. Posteriormente se ha habilitado como Oficina de Naciones Unidas de apoyo al Decenio del Agua 2005-2015. Fuente: www.facebook.com/ZGZayeryhoy/photos/pcb.1568456450051281/...', 1990, 1990, 1999, 'Anos 90', 'EL RABAL', 41.66079000, -0.86767500, '0101000020E61000004ED1915CFEC3EBBF0DC347C494D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15656696691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15656696691.webp', 'https://www.flickr.com/photos/zaragozaantigua/15656696691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22983, 'Estaciâ”śâ”‚n del Norte 1997', 'Pintura de Eduardo Laborda que captura un paisaje irrepetible de la antigua Zaragoza industrial: la Estaciâ”śâ”‚n del Norte, la "Maquinista y Fundiciones del Ebro" y, al fondo, la pareja de chimeneas que anuncia la Azucarera de Aragâ”śâ”‚n o del Arrabal. La niebla se estâ”śĂ­ echando, y la excavadora anuncia la inminencia de unos cambios que recompondrâ”śĂ­n esta zona de forma muy intensa, fundamentalmente en forma de nuevos bloques de viviendas, anunciados tambiâ”śÂ®n por los que emergen al fondo, en la Avenida de Cataluâ”śâ–’a. Fuente visual: "Eduardo Laborda. Simbolismo barroco", Cajalâ”śâ”‚n, 2006.', 1997, 1997, 1997, 'Anos 90', 'EL RABAL', 41.66049700, -0.87181400, '0101000020E6100000FB3C4679E6E5EBBF950D6B2A8BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18932311193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18932311193.webp', 'https://www.flickr.com/photos/zaragozaantigua/18932311193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23078, 'Estaciâ”śâ”‚n del Norte c.2000', 'El edificio de la Estaciâ”śâ”‚n del Norte de Zaragoza, con el aspecto que presentaba de abandono hacia el aâ”śâ–’o 2000. En la primera mitad de la dâ”śÂ®cada siguiente, fue rehabilitado como Centro Câ”śÂˇvico. Fuente visual: www.zaragoza.es/ciudad/actividades/ficha_Agenda?codigo=13...', 2000, 2000, 2000, 'Siglo XXI', 'EL RABAL', 41.66004600, -0.87178000, '0101000020E6100000F6D1A92B9FE5EBBF85ED27637CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15915688505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15915688505.webp', 'https://www.flickr.com/photos/zaragozaantigua/15915688505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23962, 'Casa cuartel de la Guardia Civil 1987', 'El 11 de diciembre de 1987, el comando Argala de la organizaciâ”śâ”‚n terrorista ETA, dirigido por Henri Parot, colocâ”śâ”‚ un coche bomba cargado con 250 kilos de amonal en un lateral de la casa cuartel y Comandancia de la Guardia Civil en Zaragoza, donde vivâ”śÂˇan 40 familias de guardiaciviles y 40 estudiantes que preparar su ingreso en el Cuerpo. La explosiâ”śâ”‚n produjo el asesinato de 11 personas y heridas en otras 88, y ademâ”śĂ­s causâ”śâ”‚ el derrumbe parcial del edificio y graves daâ”śâ–’os en los inmuebles de alrededor. En el solar que dejâ”śâ”‚ el posterior derribo del edificio se habilitâ”śâ”‚ luego una plaza denominada Parque de la Esperanza, a la altura del nâ”śâ•‘mero 76 de la avenida de Cataluâ”śâ–’a. En la imagen, capturada en altura desde la calle del Marquâ”śÂ®s de la Cadena, estado de la casa cuartel tras la explosiâ”śâ”‚n, con la calle de Josâ”śÂ® Oto a la izquierda y las chimeneas de la Azucarera del Arrabal al fondo y a la derecha.', 1987, 1987, 1987, 'Anos 80', 'EL RABAL', 41.66155800, -0.86572600, '0101000020E61000002C80290307B4EBBF1E34BBEEADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938457215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938457215.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938457215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23978, 'Fiestas del Pilar 1907', 'Archivo Municipal de Zaragoza. Cartel de las "Fiestas y Ferias a Nuestra Seâ”śâ–’ora del Pilar 1907", Victoriano Balasanz. En la imagen se reproduce el espacio cubierto de los andenes de la Estaciâ”śâ”‚n del Norte en el Arrabal, con vistas a la Seo y el Pilar. La â”śÂ®poca era propicia para representar temas ferroviarios, dado que la implantaciâ”śâ”‚n de los trenes en Europa era signo de modernidad, del mismo modo que lo es ahora arrasar con ellos. Para mâ”śĂ­s informaciâ”śâ”‚n sobre los trayectos ferroviarios abandonados de la ciudad de Zaragoza, ver el documental "Las lâ”śÂˇneas perdidas" (Josâ”śÂ® Marâ”śÂˇa Ballestin y Antonio Tausiet, 2014), pulsando aquâ”śÂˇ: www.youtube.com/watch?v=IOx2B3NQ7zg', 1907, 1907, 1907, 'Anos 1900', 'EL RABAL', 41.65996400, -0.87169400, '0101000020E610000052D2C3D0EAE4EBBFC8444AB379D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15260378959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15260378959.webp', 'https://www.flickr.com/photos/zaragozaantigua/15260378959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24123, 'Av. de Cataluâ”śâ–’a 1987', 'Imagen capturada a la altura del nâ”śâ•‘mero 78 de la avenida de Cataluâ”śâ–’a y centrada en la fachada principal de la casa cuartel de la Guardia Civil allâ”śÂˇ ubicada, tras el atentado de que fue objeto el 11 de diciembre de ese aâ”śâ–’o por parte de la organizaciâ”śâ”‚n terrorista ETA. Esta casa cuartel habâ”śÂˇa sido inaugurada el 12 de noviembre de 1955, y tras este trâ”śĂ­gico atentado fue demolida dejando un solar donde fue proyectado el Parque de la Esperanza. En primer tâ”śÂ®rmino diversos vehâ”śÂˇculos y ambulancias estacionadas ante la casa cuartel. A la izquierda, grâ”śâ•‘a maniobrando en la calle de la Villa de Ruesta donde estallâ”śâ”‚ el coche bomba. A la derecha, el vecino inmueble del nâ”śâ•‘mero 74 de la avenida.', 1987, 1987, 1987, 'Anos 80', 'EL RABAL', 41.66155800, -0.86572600, '0101000020E61000002C80290307B4EBBF1E34BBEEADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54298439145.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54298439145.webp', 'https://www.flickr.com/photos/zaragozaantigua/54298439145/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24182, 'Estaciâ”śâ”‚n del Norte 1861', 'Bendiciâ”śâ”‚n de las locomotoras en la inauguraciâ”śâ”‚n del ferrocarril entre Barcelona y Zaragoza en la Estaciâ”śâ”‚n del Norte el 16 de septiembre de 1861. El Museo Universal, 1861. Dibujo alusivo al acto referido, que contâ”śâ”‚ con la presencia del rey consorte, Francisco de Asâ”śÂˇs de Borbâ”śâ”‚n, primo hermano y esposo de Isabel II, procedente de Barcelona en el tren que se inauguraba. Fuente: www.facebook.com/photo.php?fbid=10204467950912407&set...', 1861, 1861, 1861, 'Siglo XIX', 'EL RABAL', 41.66018100, -0.87150500, '0101000020E6100000889D29745EE3EBBF65389ECF80D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15833898326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15833898326.webp', 'https://www.flickr.com/photos/zaragozaantigua/15833898326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24198, 'Arrabal 1939', 'En 1911, Albert Bressel Mâ”śâ•ťller abriâ”śâ”‚ un taller en la calle Policarpo Romea, muy cerca del Coso, donde producir piezas de repuesto para la maquinaria del floreciente sector de las azucareras. Dos aâ”śâ–’os mâ”śĂ­s tarde, trasladâ”śâ”‚ la producciâ”śâ”‚n a una nueva gran superficie en la avenida de Cataluâ”śâ–’a, y en 1918 la ampliada empresa fue denominada Maquinista y Fundiciones del Ebro, S.A. En la imagen, aâ”śÂ®rea visual centrada en el entorno de esta fâ”śĂ­brica en 1939. A la izquierda, la blanca fachada de la estaciâ”śâ”‚n del Norte, su gran plaza de acceso, y el ancho mar de vâ”śÂˇas que desde ella se abrâ”śÂˇa. De izquierda a derecha, el corte de la avenida de Cataluâ”śâ–’a, con el emboque a la calle Norte, y el solar de la desaparecida harinera de Gavâ”śÂˇn, a su izquierda, por donde poco despuâ”śÂ®s se abrirâ”śÂˇa la nueva calle de Santiago Lapuente. En el irregular trapecio del terreno ocupado por la Maquinista, pocos aâ”śâ–’os despuâ”śÂ®s se edificarâ”śÂˇan nuevos edificios que conformarâ”śÂˇan su identitario perfil, hasta su derribo casi integral a finales de los aâ”śâ–’os 90. En la parte superior, el depâ”śâ”‚sito de locomotoras de la estaciâ”śâ”‚n del Norte, la Nueva Harinera de Solans, y los primeros depâ”śâ”‚sitos de remolacha de la azucarera "vieja", o del Arrabal. Fuente visual: aportaciâ”śâ”‚n personal de Arturo Bressel Viâ”śâ–’uales.', 1939, 1939, 1939, 'Anos 30', 'EL RABAL', 41.66056300, -0.87033200, '0101000020E61000005531957EC2D9EBBF4DF910548DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30184299684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30184299684.webp', 'https://www.flickr.com/photos/zaragozaantigua/30184299684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24200, 'San Juan de la Peâ”śâ–’a 1954', 'Aâ”śÂ®rea vista del antiguo entorno de la avenida de San Juan de la Peâ”śâ–’a (antigua carretera de Huesca), a la altura donde se ubicaban los depâ”śâ”‚sitos de la empresa CAMPSA, en primer plano. En el centro de la imagen, la fâ”śĂ­brica de la Uniâ”śâ”‚n Alcoholera Espaâ”śâ–’ola. A la derecha, las vâ”śÂˇas del ferrocarril que culminaba en la estaciâ”śâ”‚n del Norte. Entre ambas instalaciones, varias dâ”śÂ®cadas despuâ”śÂ®s se abrirâ”śÂˇa la prolongaciâ”śâ”‚n de la calle Valle de Broto. Fuente visual: Arxiu Nacional de Catalunya', 1954, 1954, 1954, 'Anos 50', 'EL RABAL', 41.66580500, -0.87068600, '0101000020E6100000C7B8E2E2A8DCEBBFB341261939D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31647533841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31647533841.webp', 'https://www.flickr.com/photos/zaragozaantigua/31647533841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24206, 'Alcoholera Arrabal 1931', 'Imagen de la "Compaâ”śâ–’â”śÂˇa de Alcoholes S.A." del Arrabal, al fondo, en una vista general que captura en primer plano la zona recayente al mar de vâ”śÂˇas de la estaciâ”śâ”‚n Norte, muy activa como zona de carga y descarga de mercancâ”śÂˇas. Fuente visual: "A Don Benito Lewin y Auser como testimonio de sincero cariâ”śâ–’o y admiraciâ”śâ”‚n, con motivo del XXV Aniversario de su matrimonio le dedican este homenaje sus subordinados: Madrid, a 25 de Diciembre de 1931", en bibliotecavirtualmadrid.org/', 1931, 1931, 1931, 'Anos 30', 'EL RABAL', 41.66282300, -0.87110500, '0101000020E6100000003ACC9717E0EBBFB0045262D7D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33570560804.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33570560804.webp', 'https://www.flickr.com/photos/zaragozaantigua/33570560804/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24210, 'Estaciâ”śâ”‚n del Norte 1937', 'Tren de la lâ”śÂˇnea del Norte con locomotora engalanada con motivos nazis y fascistas, con motivo de la toma de Bilbao por las tropas franquistas. Estâ”śĂ­ situado en la Estaciâ”śâ”‚n del Norte o Arrabal de Zaragoza, el 22 de junio de 1937. Fuente: Foto de Francisco Martâ”śÂˇnez Gascâ”śâ”‚n, colecciâ”śâ”‚n de Mariano Rodrâ”śÂˇguez, a travâ”śÂ®s de www.facebook.com/RevistaTREN/', 1937, 1937, 1937, 'Anos 30', 'EL RABAL', 41.66018100, -0.87206100, '0101000020E6100000ECBE6378ECE7EBBF65389ECF80D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36898404976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36898404976.webp', 'https://www.flickr.com/photos/zaragozaantigua/36898404976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24215, 'Estaciâ”śâ”‚n del Norte 1916', 'Imagen capturada con motivo de la llegada a la ciudad de una excursiâ”śâ”‚n comercial easonense en el râ”śĂ­pido del Norte, en cuya estaciâ”śâ”‚n se congregâ”śâ”‚ buen nâ”śâ•‘mero de autoridades y representantes para recibir a los expedicionarios.', 1916, 1916, 1916, 'Anos 10', 'EL RABAL', 41.66015200, -0.87205000, '0101000020E6100000F241CF66D5E7EBBFCA3159DC7FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53495184403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53495184403.webp', 'https://www.flickr.com/photos/zaragozaantigua/53495184403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24442, 'Azucarera del Arrabal 1912', 'Imagen del camino de acceso a la puerta principal de la Azucarera de Aragâ”śâ”‚n o del Arrabal (1893). Fuente visual: El fotâ”śâ”‚grafo Luis Gandâ”śâ•‘ Mercadal.', 1912, 1912, 1912, 'Anos 10', 'EL RABAL', 41.66350700, -0.86804800, '0101000020E610000071766B990CC7EBBF63D520CCEDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15031866124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15031866124.webp', 'https://www.flickr.com/photos/zaragozaantigua/15031866124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24491, 'Carretera de Cataluâ”śâ–’a c.1945', 'Tras el "boom" de 1936-1939, cuando la militarizaciâ”śâ”‚n de la producciâ”śâ”‚n industrial de Zaragoza la convirtiâ”śâ”‚ en una de las principales madres nutricias abastecedoras del bando nacionalista, el desolador panorama postbâ”śÂ®lico, y el manifiesto alineamiento con las potencias del Eje, revirtieron la tendencia, sâ”śâ”‚lo rota por esporâ”śĂ­dicos nuevos proyectos de corte industrial, como el de "Talleres Jordâ”śĂ­". La cercanâ”śÂˇa de la estaciâ”śâ”‚n del Norte, y el acceso tranviario, orientaron su ubicaciâ”śâ”‚n en el "polo de desarrollo" (avant la lettre) de la carretera de Cataluâ”śâ–’a, junto a la Sociedad Maquinista, como fundiciâ”śâ”‚n orientada a la producciâ”śâ”‚n de mâ”śĂ­quinas herramienta, suministro de piezas a ENASA (Empresa Nacional de Autocamiones, S.A.), e incluso, el desarrollo aventurero de proyectos como el del microcoche "Sider". A mediados de los aâ”śâ–’os 50, Talleres Jordâ”śĂ­ era la sâ”śÂ®ptima empresa del metal en la ciudad, ocupando a 204 trabajadores. Una dâ”śÂ®cada mâ”śĂ­s tarde, sin embargo, la encontramos en suspensiâ”śâ”‚n de pagos, y embargada, y en los aâ”śâ–’os 70 este entorno fabril fue derribado, vendido, y sobre su solar se levantaron varios altos bloques de viviendas. Los actuales. En el dibujo promocional, a la izquierda, la fachada a la carretera de Cataluâ”śâ–’a, con las vâ”śÂˇas de la tranviaria lâ”śÂˇnea del Gâ”śĂ­llego. Fuente visual: www.todocoleccion.net/', 1945, 1945, 1945, 'Anos 40', 'EL RABAL', 41.66081100, -0.86881900, '0101000020E6100000EE96E4805DCDEBBF25EB707495D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25066475153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25066475153.webp', 'https://www.flickr.com/photos/zaragozaantigua/25066475153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24494, 'Vista Arrabal 1991', 'Foto: Rafael Margalâ”śÂ®. Vista aâ”śÂ®rea del conjunto de edificaciones fabriles junto a la Estaciâ”śâ”‚n del Norte (abajo a la izquierda) en el Arrabal. Arriba a la derecha, Azucarera del Arrabal. Fuente: www.facebook.com/photo.php?fbid=1691428257747540&set=...', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.66086400, -0.87125700, '0101000020E610000080272D5C56E1EBBF478D093197D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27997746345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27997746345.webp', 'https://www.flickr.com/photos/zaragozaantigua/27997746345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24495, 'Alcoholera Ebro 1924', 'Junto a los grandes "Talleres de Izuzquiza-Arana", al norte de la estaciâ”śâ”‚n del Arrabal, donde la calle de Sobrarbe continuaba ya como carretera de Francia, en 1911 fue constituida la "Azucarera del Ebro S.A.", pronto asociada con la "Compaâ”śâ–’â”śÂˇa de Alcoholes de Bilbao S.A." a la que en 1923 absorbiâ”śâ”‚ conformando una gran empresa denominada "Ebro Compaâ”śâ–’â”śÂˇa de Azâ”śâ•‘cares y Alcoholes", por su siglas, "ECAYA". En el plano topogrâ”śĂ­fico de 1933, esta fâ”śĂ­brica aparece denominada como "Compaâ”śâ–’â”śÂˇa de Alcoholes de Aragâ”śâ”‚n". Asâ”śÂˇ las cosas, la fotografâ”śÂˇa muestra una vista parcial de las pequeâ”śâ–’as instalaciones referidas, entre el depâ”śâ”‚sito de locomotoras de la estaciâ”śâ”‚n Norte, que queda justo detrâ”śĂ­s, y el acceso desde la carretera de Huesca, desde donde se ha capturado la imagen. Esta fâ”śĂ­brica enlazaba con el ferrocarril mediante un apartadero propio, y el tranvâ”śÂˇa "Arrabal" tenâ”śÂˇa entonces su â”śâ•‘ltima parada justo al lado. Con el tiempo, los edificios de la imagen fueron recredidos en altura, y esta industria estuvo activa hasta que en 1971 cesâ”śâ”‚ en su actividad. Mâ”śĂ­s tarde, fue derribada, y el entorno reurbanizado. No perdura ninguna huella edilicia. Fuente visual: Francisco Gâ”śâ”‚rriz, Archivo Municipal de Zaragoza', 1924, 1924, 1924, 'Anos 20', 'EL RABAL', 41.66335000, -0.87212000, '0101000020E61000002A00C63368E8EBBF9BE61DA7E8D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28574018751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28574018751.webp', 'https://www.flickr.com/photos/zaragozaantigua/28574018751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24498, 'Valle de Zuriza 1982', 'Recientes bloques de viviendas construidas entre la calle del Valle de Zuriza, desde donde se ha capturado esta imagen, la paralela de los Almadieros del Roncal, y la perpendicular del Valle del Roncal. Al fondo, la avenida de San Juan de la Peâ”śâ–’a, y tras el desecado mar de vâ”śÂˇas de la antigua estaciâ”śâ”‚n del Arrabal, el emblemâ”śĂ­tico edificio de carpinterâ”śÂˇa y almacâ”śÂ®n de modelos, rematado en torre, de la metalâ”śâ•‘rgica Maquinista y Fundiciones del Ebro, S.A. Fuente visual: Antonio Calvo Pedrâ”śâ”‚s, AMZ.', 1982, 1982, 1982, 'Anos 80', 'EL RABAL', 41.66215000, -0.87489200, '0101000020E61000006806F1811DFFEBBFF085C954C1D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30408649890.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30408649890.webp', 'https://www.flickr.com/photos/zaragozaantigua/30408649890/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24499, 'La Nueva Harinera 1917', 'Cabecera de una factura de "La Nueva Harinera" de la familia Solâ”śĂ­ns, construida en 1910 en la calle Arrabal 260, junto a la estaciâ”śâ”‚n del Norte. La ilustraciâ”śâ”‚n reproduce las instalaciones de la fâ”śĂ­brica. Fuente: www.todocoleccion.net', 1917, 1917, 1917, 'Anos 10', 'EL RABAL', 41.66204400, -0.87001200, '0101000020E6100000E814E46723D7EBBFAB4198DBBDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30607099125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30607099125.webp', 'https://www.flickr.com/photos/zaragozaantigua/30607099125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24508, 'Av. de Cataluâ”śâ–’a 1948', 'Dibujo promocional de las nuevas instalaciones de los talleres de "Marino Goâ”śâ–’i S.A." en la avenida de Cataluâ”śâ–’a. Esta empresa naciâ”śâ”‚ como distribuidora de maquinaria centroeuropea para la industria molinera y harinera, y con la denominaciâ”śâ”‚n "Bednars y Goâ”śâ–’i", una sucursal se instalâ”śâ”‚ en Zaragoza hacia 1932, con oficinas y talleres en el camino de San Josâ”śÂ®. En 1934 participâ”śâ”‚ con stand propio en la I Feria de Muestras Regional Aragonesa, celebrada en la Lonja. La vitalidad del sector harinero permitiâ”śâ”‚ ampliar negocio e instalaciones, de forma que hacia 1945 se inaugurâ”śâ”‚ la planta del dibujo, en una despejada zona donde pocos aâ”śâ–’os despuâ”śÂ®s se levantarâ”śÂˇa, al otro lado de la avenida, el grupo de viviendas Parcelaciâ”śâ”‚n Damâ”śĂ­n. En 1952, tenâ”śÂˇa 85 empleados, y era la 16â”¬â•‘ empresa del sector del metal de la ciudad. En el dibujo, una unidad de la serie 40 transita por la lâ”śÂˇnea 9, o "Gâ”śĂ­llego", hacia el final de la avenida de Cataluâ”śâ–’a. A mediados de la primera dâ”śÂ®cada del presente siglo, en este emplazamiento se ubicâ”śâ”‚ la empresa "Qualimax International", hasta que en 2007 se trasladâ”śâ”‚ a PLAZA. Desde entonces, este espacio permanece en barbecho. Fuente visual: harineras.blogspot.com.es/', 1948, 1948, 1948, 'Anos 40', 'EL RABAL', 41.66332800, -0.86261800, '0101000020E6100000151C5E10919AEBBFB34291EEE7D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32047687261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32047687261.webp', 'https://www.flickr.com/photos/zaragozaantigua/32047687261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24512, 'Av. de Cataluâ”śâ–’a 1945', 'Dibujo del proyecto arquitectâ”śâ”‚nico de Alberto Huertas representando la fachada de la nueva fâ”śĂ­brica de relojes de los hermanos Coll, sita en la avenida de Cataluâ”śâ–’a, junto a la calle Mallorca, y frente al nuevo convento de San Josâ”śÂ® de las MM. Carmelitas Descalzas. Trasladada desde Lascellas (Huesca), esta prestigiosa empresa se especializâ”śâ”‚ de forma destacada en la fabricaciâ”śâ”‚n de relojes para las torres de las iglesias de los nuevos pueblos construidos por el Instituto Nacional de Colonizaciâ”śâ”‚n, en Aragâ”śâ”‚n, Galicia y Extremadura. La inmediata parada del tranvâ”śÂˇa "Gâ”śĂ­llego" a esta fâ”śĂ­brica parece ser que era denominada, por ello, "parada del reloj". Estuvo activa hasta finales de los aâ”śâ–’os setenta. Mâ”śĂ­s tarde fue derribada. Fuente visual: Joaquâ”śÂˇn Coll Clavero, "En torno a la relojerâ”śÂˇa de Lascellas (1870-1978)", Centro de Estudios del Somontano de Barbastro, 2014.', 1945, 1945, 1945, 'Anos 40', 'EL RABAL', 41.66561200, -0.85659900, '0101000020E61000006729594E4269EBBF9FE925C632D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33952731214.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33952731214.webp', 'https://www.flickr.com/photos/zaragozaantigua/33952731214/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24513, 'Av. de la Jota 1963', 'Vista aâ”śÂ®rea de la empresa Amado Laguna de Rins S.A. en sus nuevas instalaciones de la avenida de la Jota 34-42. Fundada en 1880 en el camino de los Cubos por Amado Laguna de Rins, comenzâ”śâ”‚ produciendo materiales topogrâ”śĂ­ficos de precisiâ”śâ”‚n, a los que se sumâ”śâ”‚ luego la estampaciâ”śâ”‚n y tornillerâ”śÂˇa. Entre 1936-39 produjo materiales de guerra para los nacionalistas. En 1962 fue trasladada a esta ubicaciâ”śâ”‚n, donde ademâ”śĂ­s de las producciones tradicionales (material de guerra, material de topografâ”śÂˇa y telegrafâ”śÂˇa, metalisterâ”śÂˇa, tornillerâ”śÂˇa, estampaciones, fundiciâ”śâ”‚n de toda clase de metales), iniciâ”śâ”‚ la fabricaciâ”śâ”‚n de materiales auxiliares para la industria del automâ”śâ”‚vil, siempre asociada a dos de las mâ”śĂ­s destacadas familias del poder polâ”śÂˇtico local: los Laguna de Rins y los Almarza Laguna de Rins. En la imagen, la gran factorâ”śÂˇa fabril centra la captura. Al sur, la avenida de la Jota y una vista parcial del Grupo de Viviendas de la Parcelaciâ”śâ”‚n Daman. Tras su cierre y desmantelamiento, su solar serâ”śĂ­ remodelado y urbanizado en torno a los nuevos viales de Balbino Orensanz, Felisa Galâ”śÂ®, Baluarte Aragonâ”śÂ®s y Velilla de Ebro. Fuente visual: revista "Aragâ”śâ”‚n turâ”śÂˇstico y monumental", SIPA.', 1963, 1963, 1963, 'Anos 60', 'EL RABAL', 41.66111600, -0.85953900, '0101000020E6100000925ED4EE5781EBBF616EF7729FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34393069760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34393069760.webp', 'https://www.flickr.com/photos/zaragozaantigua/34393069760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24514, 'Alcoholera Arrabal 1931', 'Imagen de la "Compaâ”śâ–’â”śÂˇa de Alcoholes de Aragâ”śâ”‚n" del Arrabal, centrada en los edificios de la fâ”śĂ­brica, a la izquierda, almacenes, a la derecha, y en los barriles preparados para ser embarcados en el apeadero ferroviario que enlazaba con el mar de vâ”śÂˇas de la estaciâ”śâ”‚n Norte, cuyo depâ”śâ”‚sito de locomotoras queda justo detrâ”śĂ­s. Fuente visual: "A Don Benito Lewin y Auser como testimonio de sincero cariâ”śâ–’o y admiraciâ”śâ”‚n, con motivo del XXV Aniversario de su matrimonio le dedican este homenaje sus subordinados: Madrid, a 25 de Diciembre de 1931", en bibliotecavirtualmadrid.org/', 1931, 1931, 1931, 'Anos 30', 'EL RABAL', 41.66335000, -0.87212000, '0101000020E61000002A00C63368E8EBBF9BE61DA7E8D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34393330675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34393330675.webp', 'https://www.flickr.com/photos/zaragozaantigua/34393330675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24520, 'Arrabal 1910', 'Imagen de la fachada norte de la Nueva Harinera de Zaragoza, denominaciâ”śâ”‚n de la fâ”śĂ­brica de harinas de Hijos y Sobrino de Juan Solans en el Arrabal, junto a la Estaciâ”śâ”‚n del Norte (a la derecha, fuera de plano), con capacidad de moler cuarenta toneladas de trigo al dâ”śÂˇa. Al fondo, a la izquierda, barroca torre de la Seo en la margen derecha del râ”śÂˇo Ebro. Fuente visual: www.todocoleccion.net/', 1910, 1910, 1910, 'Anos 10', 'EL RABAL', 41.66204400, -0.87001200, '0101000020E6100000E814E46723D7EBBFAB4198DBBDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39177625765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39177625765.webp', 'https://www.flickr.com/photos/zaragozaantigua/39177625765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24536, 'Azucarera del Arrabal 1995', 'Las abandonadas desde el aâ”śâ–’o 1966 y enormes instalaciones de la antigua Azucarera de Aragâ”śâ”‚n, o del Arrabal, en una imagen capturada desde sus traseras recayentes al tambiâ”śÂ®n desmantelado y abandonado tendido ferroviario que desde la estaciâ”śâ”‚n del Arrabal condujera hacia norteâ”śâ–’os destinos. Al fondo y a la derecha, una leve vista de los grandes bloques de la avenida de Cataluâ”śâ–’a a la altura de la calle de los Jardines Aguilar de Ebro, pioneros en la moderna urbanizaciâ”śâ”‚n de esta extensa y antigua zona industrial de la ciudad.', 1995, 1995, 1995, 'Anos 90', 'EL RABAL', 41.66437600, -0.86914300, '0101000020E6100000B68311FB04D0EBBFA71FD4450AD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50433614616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50433614616.webp', 'https://www.flickr.com/photos/zaragozaantigua/50433614616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24538, 'Harinas Solans S.A., 1938', 'Dibujo de la fâ”śĂ­brica Harinas Solans S.A. donde su perâ”śÂˇmetro delimitado entre la avenida de Cataluâ”śâ–’a, a la izquierda, y el depâ”śâ”‚sito de mâ”śĂ­quinas locomotoras de la estaciâ”śâ”‚n del Arrabal, a la derecha, se centra en el gran edificio central construido con proyecto del arquitecto Miguel â”śĂĽngel Navarro Pâ”śÂ®rez al comienzo de la dâ”śÂ®cada de 1910. A la derecha, un convoy ferroviario seâ”śâ–’ala la presencia del apartadero propio que conectaba a la factorâ”śÂˇa con la estaciâ”śâ”‚n del Arrabal.', 1938, 1938, 1938, 'Anos 30', 'EL RABAL', 41.66152300, -0.86935700, '0101000020E6100000B98E71C5C5D1EBBFA24621C9ACD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50600959053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50600959053.webp', 'https://www.flickr.com/photos/zaragozaantigua/50600959053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24744, 'Cincomarzada 1991', 'Foto Rogelio Allepuz, 1991. Celebraciâ”śâ”‚n de la Cincomarzada, el 5 de marzo de 1991, en el parque del Tâ”śÂˇo Jorge de Zaragoza. En primer plano, peâ”śâ–’istas y rancho. Al fondo, internacionalistas. Fuente: www.facebook.com/photo.php?fbid=573197456109890&set=p...', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.66409300, -0.87669800, '0101000020E6100000D6FECEF6E80DECBF5340DAFF00D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15665639998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15665639998.webp', 'https://www.flickr.com/photos/zaragozaantigua/15665639998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24746, 'Calle Villacampa 1990', 'Foto Galagar, 1990. Calle de Pedro Villacampa, en el barrio del Arrabal de Zaragoza. Hacia el fondo, direcciâ”śâ”‚n Sixto Celorrio; a la espalda, direcciâ”śâ”‚n Sobrarbe. A la izquierda queda la plaza del Rosario, fuera de la toma. Fuente: www.facebook.com/photo.php?fbid=973598639333260&set=o...', 1990, 1990, 1990, 'Anos 90', 'EL RABAL', 41.66027900, -0.87478700, '0101000020E610000014E97E4E41FEEBBF289EB30584D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15728601996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15728601996.webp', 'https://www.flickr.com/photos/zaragozaantigua/15728601996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24748, 'Monumento al Tâ”śÂˇo Jorge 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Junio 1968. Instalaciâ”śâ”‚n del "Monumento al Tâ”śÂˇo Jorge", de â”śĂĽngel Orensanz, en el Parque del Tâ”śÂˇo Jorge. La realizaciâ”śâ”‚n de la obra estaba relacionada con la construcciâ”śâ”‚n del Parque del Tâ”śÂˇo Jorge en el Rabal, y la voluntad de que fuera su principal seâ”śâ–’a de identidad. El monumento se compone de dos elementos independientes: la realista escultura en piedra del Tâ”śÂˇo Jorge, y un gran monolito en hormigâ”śâ”‚n y hierro de carâ”śĂ­cter surrealista y simbâ”śâ”‚lico. En la imagen, operarios municipales ultiman faenas antes de la inauguraciâ”śâ”‚n en la glorieta en que se instalâ”śâ”‚ el monumento, cerca del lâ”śÂˇmite norte del parque del Tâ”śÂˇo Jorge, junto a lo que pocos aâ”śâ–’os despuâ”śÂ®s se denominarâ”śĂ­ Valle de Broto (detrâ”śĂ­s de los â”śĂ­rboles). Fuente: www.zaragoza.es/ciudad/artepublico/detalle_ArtePublico?id=46', 1968, 1968, 1968, 'Anos 60', 'EL RABAL', 41.66522100, -0.87658300, '0101000020E61000009F58A7CAF70CECBF64CE33F625D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15796863045.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15796863045.webp', 'https://www.flickr.com/photos/zaragozaantigua/15796863045/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24750, 'Calle Molino de las Armas 1977', 'Vista de la calle Molino de Las Armas en el barrio de la Jota de Zaragoza, tramo comprendido entre Pascuala Periâ”śÂ® (tras el fotâ”śâ”‚grafo) y Marquâ”śÂ®s de la Cadena (al fondo). Con una enorme torre elâ”śÂ®ctrica en la acera de los pares y una pancarta reivindicativa de su desapariciâ”śâ”‚n. Al fondo, la torre de la Seo. Fuente: La orilla izquierda del Ebro zaragozano, Marâ”śÂˇa Carmen Faus, 1988.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.66109600, -0.86342500, '0101000020E6100000C58F31772DA1EBBF1AC231CB9ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18620703834.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18620703834.webp', 'https://www.flickr.com/photos/zaragozaantigua/18620703834/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24751, 'Calle Villacampa 1977', 'Vista de la calle de Pedro Villacampa en 1988. Al fondo, la calle Sobrarbe. La toma estâ”śĂ­ hecha desde la plaza del Rosario. Fuente: La orilla izquierda del Ebro zaragozano, Marâ”śÂˇa Carmen Faus, 1988.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.66015900, -0.87452900, '0101000020E610000029EACC3D24FCEBBF7D94111780D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18998193180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18998193180.webp', 'https://www.flickr.com/photos/zaragozaantigua/18998193180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24757, 'Azucarera de Aragâ”śâ”‚n 1899', 'Fâ”śĂ­brica "La Azucarera de Aragâ”śâ”‚n" en el Camino de las Torrecillas del Arrabal de Zaragoza. Fue la primera azucarera de la regiâ”śâ”‚n y funcionâ”śâ”‚ de 1897 a 1966. Los edificios que perviven y las dos chimeneas que tuvo son hoy dependencias municipales: depâ”śâ”‚sito de bienes embargados a finales del siglo XX y "Zaragoza activa" tras su remozo en 2004, Su domicilio actual es calle Mas de las Matas 20. Fuente: Mâ”¬Â¬ Pilar Biel Ibâ”śĂ­â”śâ–’ez, Zaragoza y la industrializaciâ”śâ”‚n: la arquitectura industrial 1875-1926, IFC, 2004.', 1899, 1899, 1899, 'Siglo XIX', 'EL RABAL', 41.66350700, -0.86804800, '0101000020E610000071766B990CC7EBBF63D520CCEDD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19674203876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19674203876.webp', 'https://www.flickr.com/photos/zaragozaantigua/19674203876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24762, 'Calle Sobrarbe 1977', 'Imagen de la calle Sobrarbe con el antiguo arranque de la calle Villacampa, y los locales comerciales establecidos en sus bajos. De izquierda a derecha, los antiguos nâ”śâ•‘meros 49, 51 y 53 de Sobrarbe, y los 1 y 2 de Villacampa, con esa tipologâ”śÂˇa de viviendas de los siglos XVII-XVIII, con leves reformas en el XIX, que caracterizaban las calles del "casco viejo" del arrabal de Altabâ”śĂ­s, cuando Sobrarbe era "Monjas" y "Tintes", Villacampa era "Tejar", Ibort era "Medio"... Aâ”śâ–’os despuâ”śÂ®s, estas casonas serâ”śÂˇan derribadas para levantar otras mâ”śĂ­s modernas, y la manzana de los pares de Villacampa, retranqueada y alineada con la de los impares. Fuente visual: amable aportaciâ”śâ”‚n del Archivo personal de Pablo Valdâ”śÂ®s.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.65998400, -0.87398100, '0101000020E61000007B698A00A7F7EBBF0FF10F5B7AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20110500032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20110500032.webp', 'https://www.flickr.com/photos/zaragozaantigua/20110500032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24764, 'Carretera de Huesca 1862', '"Plano topogrâ”śĂ­fico y nivelaciâ”śâ”‚n de la zona comprendida entre la Puerta del â”śĂĽngel de Zaragoza y la Venta de Tetuâ”śĂ­n en la Carretera de Huesca. Alumnos del Instituto de Zaragoza de Agrimensores y Peritos Tasadores de tierras. Curso 1861-1862". A la derecha, el râ”śÂˇo Ebro con las plantas de los edificios de la ribera derecha; hacia la izquierda, el Arrabal, la estaciâ”śâ”‚n del Norte y el convento de Jesâ”śâ•‘s; y a la izquierda la Venta de Tetuâ”śĂ­n. Fuente: AMZ.', 1862, 1862, 1862, 'Siglo XIX', 'EL RABAL', 41.66265900, -0.87263000, '0101000020E61000007845F0BF95ECEBBF35B39602D2D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20414926034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20414926034.webp', 'https://www.flickr.com/photos/zaragozaantigua/20414926034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24765, 'Estaciâ”śâ”‚n del Norte 1967', 'Estaciâ”śâ”‚n del Norte o del Arrabal, con un tren saliendo direcciâ”śâ”‚n Lâ”śÂ®rida. Al fondo, la torre de la Seo. Fuente visual: Colecciâ”śâ”‚n Cristina Rubio en "150 aâ”śâ–’os de ferrocarril en Zaragoza", 2011.', 1967, 1967, 1967, 'Anos 60', 'EL RABAL', 41.66016800, -0.87198600, '0101000020E6100000433C122F4FE7EBBFD0EE906280D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20630121101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20630121101.webp', 'https://www.flickr.com/photos/zaragozaantigua/20630121101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24768, 'Vista aâ”śÂ®rea norte 1967', 'Vista aâ”śÂ®rea del norte de la ciudad de Zaragoza en 1967. Fuente: www.facebook.com/photo.php?fbid=628462120596457&set=p...', 1967, 1967, 1967, 'Anos 60', 'EL RABAL', 41.66565600, -0.87247600, '0101000020E6100000CA6FD1C952EBEBBF6E313F3734D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21309774722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21309774722.webp', 'https://www.flickr.com/photos/zaragozaantigua/21309774722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24775, 'TACA c.1966', 'Aâ”śÂ®rea vista del moderno complejo fabril de la empresa TACA, inaugurada en 1965 con participaciâ”śâ”‚n de Mann+Hummel, y el Gobierno de Espaâ”śâ–’a, al ser una iniciativa integrada en el Polo de Desarrollo de Zaragoza. Luego denominada Filtros Mann S.A., en 2005 fue trasladada a PLAZA, donde perdura como Mann+Hummel Ibâ”śÂ®rica S.A.U., y estas antiguas instalaciones de la avenida de Cataluâ”śâ–’a fueron derribadas. Al fondo se destacan las cuatro torres del templo del Pilar.', 1966, 1966, 1966, 'Anos 60', 'EL RABAL', 41.66485900, -0.85391700, '0101000020E610000028F38FBE4953EBBFC3B986191AD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24578267369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24578267369.webp', 'https://www.flickr.com/photos/zaragozaantigua/24578267369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24778, 'Estaciâ”śâ”‚n del Norte 1977', 'Imagen de la fachada principal de acceso a la antigua estaciâ”śâ”‚n Norte en el Arrabal, que fuera la primera en activo de la ciudad, clausurada en sus funciones ferroviarias un par de aâ”śâ–’os antes de capturar esta fotografâ”śÂˇa. En el suelo, inmediatas, las vâ”śÂˇas del ramal que la lâ”śÂˇnea 4 del tranvâ”śÂˇa dispuso, a principios del siglo XX, tendidas desde el otro lado del Ebro. El edificio principal (que sustituyâ”śâ”‚ a unos provisionales anteriores) fue levantado en 1863, posiblemente segâ”śâ•‘n diseâ”śâ–’o del ingeniero Pedro Andrâ”śÂ®s y Puigdollers, que venâ”śÂˇa de hacer lo propio con la estaciâ”śâ”‚n de Barcelona. Fuente visual: amable aportaciâ”śâ”‚n personal de Pablo Valdâ”śÂ®s.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.66004600, -0.87178000, '0101000020E6100000F6D1A92B9FE5EBBF85ED27637CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26520402452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26520402452.webp', 'https://www.flickr.com/photos/zaragozaantigua/26520402452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24783, 'Vista Arrabal 1991', 'Foto: Rafael Margalâ”śÂ®. Vista aâ”śÂ®rea del Arrabal, partiendo de la confluencia de la calle del Sobrarbe con la avenida de Cataluâ”śâ–’a (abajo a la izquierda). En el centro, complejos fabriles junto a la Estaciâ”śâ”‚n del Norte, aâ”śâ•‘n sin derribar. Fuente: www.facebook.com/photo.php?fbid=1691428254414207&set=...', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.66086400, -0.87125700, '0101000020E610000080272D5C56E1EBBF478D093197D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27383444913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27383444913.webp', 'https://www.flickr.com/photos/zaragozaantigua/27383444913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24788, 'Av. de Cataluâ”śâ–’a 1965', 'Imagen aâ”śÂ®rea del entronque, en primer tâ”śÂ®rmino, de la calle del Alcalde Caballero (tambiâ”śÂ®n denominada "Enlace de Carreteras" del norte) con la avenida de Cataluâ”śâ–’a, con interesante perspectiva de la factorâ”śÂˇa de deshidrataciâ”śâ”‚n de alfalfa y fabricaciâ”śâ”‚n de piensos compuestos Arquero S.A. (vulgo Piensos Arquero), luego propiedad de Pygasa. Tras ella, el nuevo convento de San Josâ”śÂ® de las Carmelitas Descalzas, y casi confrontando, a la derecha de la avenida de Cataluâ”śâ–’a, las instalaciones de la novâ”śÂˇsima empresa TACA (Talleres Cataluâ”śâ–’a) Mann S.A. Fuente visual: Arxiu Nacional de Catalunya.', 1965, 1965, 1965, 'Anos 60', 'EL RABAL', 41.66615100, -0.85774600, '0101000020E61000004BCB48BDA772EBBF4E999B6F44D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31057248524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31057248524.webp', 'https://www.flickr.com/photos/zaragozaantigua/31057248524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24789, 'Ricardo del Arco 1933', 'Imagen del interior de la nave siniestrada en el incendio de la arrabalera fâ”śĂ­brica de curtidos de Policarpo Aramendâ”śÂˇa, sita en la calle de Ricardo del Arco, cerca del camino de las Balsas de Ebro Viejo. La captura se ha realizado cuando los bomberos municipales parecen estar terminando de sofocar el fuego. A la izquierda, algunas piezas de la curtiembre. Fuente visual: Alejandro de la Barrera, en "Revista Ahora" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'EL RABAL', 41.66005800, -0.87741300, '0101000020E61000005ABA826DC413ECBF49BBD1C77CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31766232014.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31766232014.webp', 'https://www.flickr.com/photos/zaragozaantigua/31766232014/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24808, 'Calle de Santa Fe 1989', 'Complejo fabril de Filtros Mann S.A. en una aâ”śÂ®rea vista en altura del entorno de la avenida de Cataluâ”śâ–’a centrada en las instalaciones de esta empresa dedicada a la fabricaciâ”śâ”‚n de filtros para automâ”śâ”‚viles y camiones. Fue inaugurada en 1965 con participaciâ”śâ”‚n de Taca, Mann+Hummel, y el Estado, como una iniciativa integrada en el Polo de Desarrollo de Zaragoza. En 2005 fue trasladada a la Plataforma Logâ”śÂˇstica de Zaragoza, Plaza, donde perdura como Mann+Hummel Ibâ”śÂ®rica S.A.U. Esta factorâ”śÂˇa fue por ello derribada, sin que hasta la fecha esta â”śĂĽrea de intervenciâ”śâ”‚n F-55-5 haya sido desarrollada, salvo un bloque de 45 viviendas en la calle de la Isla Dragonera. En la imagen, la fâ”śĂ­brica aparece flanqueada, a la izquierda, por la calle de Santa Fe, que recuerda la homâ”śâ”‚nima barriada, y el tendido ferroviario de Zaragoza a Huesca, a la derecha. Al fondo, el Polâ”śÂˇgono de El Pilar, de 1982.', 1989, 1989, 1989, 'Anos 80', 'EL RABAL', 41.66485900, -0.85391700, '0101000020E610000028F38FBE4953EBBFC3B986191AD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34517675850.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34517675850.webp', 'https://www.flickr.com/photos/zaragozaantigua/34517675850/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24811, 'Calle de Santa Fe 1932', 'Imagen capturada en la calle de Santa Fe, en la barriada del mismo nombre, que junto con las barriadas de Costa y de Escudero conformaban la denominada Explanada del Gâ”śĂ­llego. Se trataba de tres parcelaciones particulares discontinuas, de urbanizaciâ”śâ”‚n privada, en el entorno de la carretera de Madrid a Francia por la Junquera y en direcciâ”śâ”‚n al puente del Gâ”śĂ­llego que, como era costumbre carecâ”śÂˇan de servicios e infraestructuras. La mâ”śĂ­s cercana a la ciudad era la barriada de Costa, a la izquierda y cercana al camino de las Torrecillas, con viales anâ”śâ”‚nimos que mâ”śĂ­s tarde recibirâ”śĂ­n los nombres de Aurora, Esquedas, Santa Quiteria y Sierra de Alcubierre. La barriada de Escudero se encontraba a la derecha, articulada en torno a las calles de Escudero (luego Ruiseâ”śâ–’or, y Pedro Lâ”śĂ­zaro) y de Liria (luego, Once de Julio). Finalmente, la barriada de Santa Fe, tambiâ”śÂ®n a la derecha de la carretera, vertebrada por las paralelas calles de Mallorca y de Santa Fe, que la imagen ilustra.', 1932, 1932, 1932, 'Anos 30', 'EL RABAL', 41.66562800, -0.85563400, '0101000020E6100000AE0FEB8D5A61EBBFA4A65D4C33D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34896993934.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34896993934.webp', 'https://www.flickr.com/photos/zaragozaantigua/34896993934/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24814, 'San Juan de la Peâ”śâ–’a 1977', 'Imagen capturada desde cierta altura en la calle de San Juan de la Peâ”śâ–’a (antigua carretera de Huesca), centrada en el tramo posterior al cruce con la calle del Marquâ”śÂ®s de la Cadena. En primer tâ”śÂ®rmino, modernas instalaciones de Hierros Alfonso SA. Detrâ”śĂ­s, a la derecha, la antigua fâ”śĂ­brica de la Uniâ”śâ”‚n Alcoholera Espaâ”śâ–’ola, y al fondo y a la izquierda el creciente recinto de la veterana papelera Sociedad Anâ”śâ”‚nima Industrias Celulosa Aragonesa (SAICA).', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.66725500, -0.87115800, '0101000020E6100000B5C2F4BD86E0EBBFD68BA19C68D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39856865572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39856865572.webp', 'https://www.flickr.com/photos/zaragozaantigua/39856865572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24815, 'Picarral 1965', 'Aâ”śÂ®rea visual parcial del barrio del Picarral con detalle de la zona comprendida entre la avenida de San Juan de la Peâ”śâ–’a, el antiguo camino de Juslibol y los terrenos de cultivo por donde poco despuâ”śÂ®s serâ”śÂˇa trazada la nueva avenida de los Pirineos. Desde la parte inferior derecha encontramos vistas de los grupos de viviendas "Balsas de Ebro Viejo", del "Teniente Polanco", del "General Franco", y el de San Juan de la Peâ”śâ–’a 181-195, ademâ”śĂ­s de las empresas TACA y CAITASA, el colegio de San Braulio y la parroquia de Belâ”śÂ®n. Fuente visual: TAF Helicâ”śâ–“pters SA, en Arxiu Nacional de Catalunya.', 1965, 1965, 1965, 'Anos 60', 'EL RABAL', 41.66847400, -0.87459200, '0101000020E6100000C2FBAA5CA8FCEBBFF81C588E90D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40662952280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40662952280.webp', 'https://www.flickr.com/photos/zaragozaantigua/40662952280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24822, 'Av. de Cataluâ”śâ–’a 1991', 'Imagen en altura .desde la calle del Marquâ”śÂ®s de la Cadena centrada en el gran solar dejado tras el derribo de la Casa Cuartel de la Guardia Civil sita en la avenida de Cataluâ”śâ–’a (a la derecha) y que fue objeto de terrible atentado terrorista el 11 de diciembre de 1987. A la izquierda, la calle de Josâ”śÂ® Oto. El Ayuntamiento acordâ”śâ”‚ ubicar sobre este solar una nueva plaza-parque cuyo elemento central serâ”śÂˇa un grupo escultâ”śâ”‚rico que en principio iba a denominarse "Juego de niâ”śâ–’os", y finalmente serâ”śÂˇa "Monumento a los niâ”śâ–’os", con diseâ”śâ–’o del tallista aragonâ”śÂ®s Carlos Pâ”śÂ®rez de Albâ”śÂ®niz Navarro para homenajear a la infancia como sâ”śÂˇmbolo de la paz. En paralelo, un nuevo cuartel de la Guardia Civil fue ubicado en el barrio de Casetas. En 1992 serâ”śÂˇa inaugurado el Parque de la Esperanza, tras una inversiâ”śâ”‚n de casi 36 millones de pesetas.', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.66141800, -0.86523700, '0101000020E6100000BC40498105B0EBBF2C7E5358A9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50378156076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50378156076.webp', 'https://www.flickr.com/photos/zaragozaantigua/50378156076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24824, 'Azucarera de Aragâ”śâ”‚n 1899', 'Imagen de la Azucarera de Aragâ”śâ”‚n capturada junto al ramal ferroviario que enlazaba con la estaciâ”śâ”‚n del Norte y por el que transitaban tambiâ”śÂ®n vagonetas de mercancâ”śÂˇas a tracciâ”śâ”‚n de sangre de la lâ”śÂˇnea Arrabal-Estaciâ”śâ”‚n, por donde se transportaba hasta aquâ”śÂˇ la remolacha azucarera de que se surtâ”śÂˇa esta fâ”śĂ­brica, que fue la primera azucarera de la regiâ”śâ”‚n y que estuvo activa desde 1897 y hasta 1966. Los edificios que aquâ”śÂˇ figuran son los originales que fueron proyectados por Luis Aladrâ”śÂ®n en 1893, entre los que destacan el horno de cal, el secadero de pulpas, el cuarto de calderas y la gran chimenea, ademâ”śĂ­s de la torre de filtros, la estructura de mâ”śĂ­s altura (seis pisos) tras la chimenea. A la derecha, la nave de falsos pisos y tejado a doble vertiente donde se encontraba la zona de lavado, difusiâ”śâ”‚n, evaporizaciâ”śâ”‚n, cristalizaciâ”śâ”‚n y turbinaciâ”śâ”‚n. Al fondo y a la derecha, la casa del director de la fâ”śĂ­brica, inmediata al acceso desde el camino de las Torrecillas.', 1899, 1899, 1899, 'Siglo XIX', 'EL RABAL', 41.66347800, -0.86888500, '0101000020E6100000CB845FEAE7CDEBBFC8CEDBD8ECD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50399927348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50399927348.webp', 'https://www.flickr.com/photos/zaragozaantigua/50399927348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25102, 'Av. de Cataluâ”śâ–’a 1992', 'Imagen capturada durante la inauguraciâ”śâ”‚n oficial del parque de la Esperanza el 21 de mayo de 1992 por el director general de la Guardia Civil, Luis Roldâ”śĂ­n y el alcalde de Zaragoza, Antonio Gonzâ”śĂ­lez Triviâ”śâ–’o. En primer tâ”śÂ®rmino, figura del niâ”śâ–’o con monopatâ”śÂˇn integrante del Monumento a los niâ”śâ–’os, como recuerdo a las vâ”śÂˇctimas, especialmente las infantiles, del atentado terrorista contra la Casa Cuartel de la Guardia Civil en la avenida de Cataluâ”śâ–’a el 11 de diciembre de 1987. Al fondo, entorno de la plaza de W. Amadeus Mozart donde se cruzan la avenida de Cataluâ”śâ–’a y la calle del Marquâ”śÂ®s de la Cadena.', 1992, 1992, 1992, 'Anos 90', 'EL RABAL', 41.66131400, -0.86538700, '0101000020E61000000F46EC1340B1EBBF8731E9EFA5D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50451350938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50451350938.webp', 'https://www.flickr.com/photos/zaragozaantigua/50451350938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25965, 'ACTUR 1982', 'Visual aâ”śÂ®rea centrada en el â”śĂĽrea de Actuaciâ”śâ”‚n Urbanâ”śÂˇstica Urgente en los barrios de Zalfonada y Picarral.', 1982, 1982, 1982, 'Anos 80', 'EL RABAL', 41.66847100, -0.87659200, '0101000020E61000006CED7DAA0A0DECBF86A92D7590D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701394097.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701394097.webp', 'https://www.flickr.com/photos/zaragozaantigua/14701394097/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26030, 'Vista barrio La Jota 1955', 'Vista aâ”śÂ®rea centrada en el Grupo de Viviendas Parcelaciâ”śâ”‚n Daman, en el barrio de La Jota, con la avenida de Cataluâ”śâ–’a a la izquierda y el Ebro y el Pilar al fondo. Fuente: TAF Helicâ”śâ–“pters. Arxiu Nacional de Catalunya.', 1955, 1955, 1955, 'Anos 50', 'EL RABAL', 41.66248600, -0.86103600, '0101000020E61000008DB7955E9B8DEBBF68075C57CCD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30538225114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30538225114.webp', 'https://www.flickr.com/photos/zaragozaantigua/30538225114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26042, 'Balsas del Ebro Viejo c.1927', 'Desde la zona de las balsas del Ebro Viejo, en la margen izquierda, un dibujo de la arboleda de Macanaz, al fondo, con la destacada emergencia de la basâ”śÂˇlica del Pilar, al otro lado del râ”śÂˇo Ebro. A la izquierda, parcelas del final de la calle de Ricardo del Arco, esquineras con el camino de las Balsas del Ebro Viejo. Ese dibujo formaba parte de una colecciâ”śâ”‚n de postales editadas por la tipogrâ”śĂ­fica del Heraldo de Aragâ”śâ”‚n, con diversas localizaciones de Zaragoza. Fuente visual: www.ebay.es/', 1927, 1927, 1927, 'Anos 20', 'EL RABAL', 41.66102500, -0.87711300, '0101000020E6100000B4AF3C484F11ECBF516B9A779CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31261738421.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31261738421.webp', 'https://www.flickr.com/photos/zaragozaantigua/31261738421/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26048, 'Balsas de Ebro Viejo 1963', 'Imagen aâ”śÂ®rea del despejado espacio preparado para la construcciâ”śâ”‚n del enorme Grupo de Viviendas "Balsas de Ebro Viejo", entre la avenida de San Juan de la Peâ”śâ–’a (izquierda), y el camino de Juslibol y la arboleda del parque de Ibort (derecha). En primer tâ”śÂ®rmino, la parroquia de Nâ”¬Â¬ Sâ”¬Â¬ de Belâ”śÂ®n, y a su izquierda, el reciente colegio pâ”śâ•‘blico San Braulio, junto al Grupo de Viviendas "Teniente Ortâ”śÂˇz de Zâ”śĂ­rate". Inmediata a la parroquia, ya fuera de plano, comenzaba la zona industrial de esta parte del Picarral, con empresas como la CAITASA. Al fondo, Zaragoza. Fuente visual: Arxiu Nacional de Catalunya', 1963, 1963, 1963, 'Anos 60', 'EL RABAL', 41.66555200, -0.87435900, '0101000020E61000000FD3BEB9BFFAEBBFC9E4D4CE30D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31750378425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31750378425.webp', 'https://www.flickr.com/photos/zaragozaantigua/31750378425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23197, 'Vista aâ”śÂ®rea 2010', 'Foto: Esther Casas. Vista aâ”śÂ®rea de Zaragoza, con las naves del polâ”śÂˇgono del Camino del Vado en pie, en primer tâ”śÂ®rmino. Serâ”śĂ­n derribadas en 2010 para la construcciâ”śâ”‚n de viviendas. El inicio de la nueva urbanizaciâ”śâ”‚n ha sido anunciado en 2016. Fuente visual: Heraldo de Aragâ”śâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'EL RABAL', 41.65639800, -0.86204200, '0101000020E6100000EAE8B81AD995EBBF759483D904D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25615047231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25615047231.webp', 'https://www.flickr.com/photos/zaragozaantigua/25615047231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23205, 'Polâ”śÂˇgono Camino del Vado 2010', 'Foto: Josâ”śÂ® Miguel Marco. Vista parcial del proceso de derribo de las naves del polâ”śÂˇgono industrial del Camino del Vado, en junio de 2010. Al fondo a la izquierda, edificios del barrio Jesâ”śâ•‘s, entre las calles de Paniza y Pedro Arnal Cavero. A la derecha, bloques del paseo de Longares. Esta â”śĂ­rea tiene prevista su urbanizaciâ”śâ”‚n con un parque y 900 viviendas. Fuente: Heraldo de Aragâ”śâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'EL RABAL', 41.65639800, -0.86204200, '0101000020E6100000EAE8B81AD995EBBF759483D904D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32779252024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32779252024.webp', 'https://www.flickr.com/photos/zaragozaantigua/32779252024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24776, 'Vista Vadorrey 1976', 'Vista de la margen izquierda del râ”śÂˇo Ebro, en terrenos del Polâ”śÂˇgono 51, cuyo Plan Parcial estaba transitando de las musas al teatro, con el inicio de la construcciâ”śâ”‚n de la Urbanizaciâ”śâ”‚n Vadorrey, en primer plano. A la izquierda, desembocadura del râ”śÂˇo Huerva. Al fondo, la ciudad consolidada. Fuente visual: dezaragozaalzierzo.blogspot.com', 1976, 1976, 1976, 'Anos 70', 'EL RABAL', 41.65415300, -0.85725700, '0101000020E6100000DB8B683BA66EEBBF47CA1649BBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25483925060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25483925060.webp', 'https://www.flickr.com/photos/zaragozaantigua/25483925060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20934, 'Carretera de Cataluâ”śâ–’a 1778', '"Plano en que se manifiesta la entrada de Zaragoza por el Camino nuebo". Joaquâ”śÂˇn de Villanueva, Zaragoza, 31 de marzo de 1778. Trazado de la que serâ”śĂ­ carretera y hoy avenida de Cataluâ”śâ–’a. Fuente: Archivo General de Simancas.', 1778, 1778, 1778, 'Siglo XIX', 'EL RABAL', 41.65897900, -0.87214900, '0101000020E6100000BDA60705A5E8EBBF1AE0826C59D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27926146914.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27926146914.webp', 'https://www.flickr.com/photos/zaragozaantigua/27926146914/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21215, 'Convento de Jesâ”śâ•‘s 1907', 'Postal. "Colecciâ”śâ”‚n Patria y Fe nâ”śâ•‘m. 1, Zaragoza 1908 - Centenario de los Sitios", 1907. "Hoy en ruinas dedicado a provisiones militares. El convento evacuado en el primer sitio fue refugio de Palafox, cuando en la memorable jornada del 4 de agosto, resolviâ”śâ”‚ allâ”śÂˇ salir hacia Pina en busca de refuerzos. Durante el segundo sitio, fue el 8 de febrero acometido por los franceses, que acabaron aquel dâ”śÂˇa presos en â”śÂ®l." Convento de Jesâ”śâ•‘s, en la margen izquierda del Ebro. Desaparecido. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'EL RABAL', 41.65807700, -0.87101300, '0101000020E6100000D481ACA756DFEBBFF99FFCDD3BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15106850914.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15106850914.webp', 'https://www.flickr.com/photos/zaragozaantigua/15106850914/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21460, 'Huelga General 1911', 'Imagen posiblemente capturada en el Arrabal y centrada en el estratâ”śÂ®gico cruce entre la calle de Jesâ”śâ•‘s y su continuidad hacia la derecha por el camino del Vado, y el camino que desde la carretera de Madrid a Francia (al fondo) conducâ”śÂˇa al puente del Pilar o de Hierro, durante la Huelga General del verano de 1911 cuando guardiaciviles a pie y a caballo, guardias del cuerpo de seguridad y tropas de caballerâ”śÂˇa de los regimientos de los Castillejos y Lanceros patrullaban las calles y zonas de acceso a la ciudad, ademâ”śĂ­s de ejercer vigilancia en las principales fâ”śĂ­bricas y talleres.', 1911, 1911, 1911, 'Anos 10', 'EL RABAL', 41.65772500, -0.86948500, '0101000020E6100000179AEB34D2D2EBBF7C61325530D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52185910678.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52185910678.webp', 'https://www.flickr.com/photos/zaragozaantigua/52185910678/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21647, 'Calle de la Estaciâ”śâ”‚n 1925', 'Imagen capturada en el gran patio de la casa del industrial Sancerni en la calle de la Estaciâ”śâ”‚n nâ”¬â•‘ 3-5 durante una verbena particular celebrada con motivo de las fiestas del barrio de Jesâ”śâ•‘s organizadas a mediados del mes de junio. Posan en ella algunas muchachas de las familias de bien que participaron engalanadas con los muy tradicionales y espaâ”śâ–’oles mantones de Manila: Marâ”śÂˇa Luisa y Alicia Sancerni, Maurita Sandoval, Conchita y Teresa Lanuza, Teresita Villegas, Marâ”śÂˇa y Emilia Aguelo, Conchita Villena, Elvira y Pilar del Râ”śÂˇo, Marâ”śÂˇa Redondo, la seâ”śâ–’ora de Caâ”śâ–’averal, Aurora y Pilar Gutiâ”śÂ®rrez, Emilia y Pilar Echegoyen, y Marâ”śÂˇa Redondo. Alguna niâ”śâ–’a se ha colado en el posado, y son las â”śâ•‘nicas que miran al objetivo. Julio Sancerni habilitâ”śâ”‚ en la calle de la Estaciâ”śâ”‚n una importante fundiciâ”śâ”‚n de hierro, bronce y cobre de la que salieron hasta campanas de iglesia, y unos talleres de fabricaciâ”śâ”‚n de caldererâ”śÂˇa, cocinas econâ”śâ”‚micas, mâ”śĂ­quinas agrâ”śÂˇcolas, construcciones y telas metâ”śĂ­licas.', 1925, 1925, 1925, 'Anos 20', 'EL RABAL', 41.65878900, -0.87151400, '0101000020E61000005532005471E3EBBF76FBAC3253D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51344611414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51344611414.webp', 'https://www.flickr.com/photos/zaragozaantigua/51344611414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21845, 'Plaza de Jesâ”śâ•‘s 1934', 'Imagen de la plaza de Jesâ”śâ•‘s capturada con su nuevo aspecto tras la reciente reforma y adoquinado de la calle de Jesâ”śâ•‘s, que continâ”śâ•‘a por la derecha hasta el cruce con la avenida del Puente del Pilar, tras el que continâ”śâ•‘a como camino del Vado. Hacia la izquierda de la plaza, fuera de plano, inicio de la calle de Valimaâ”śâ–’a, que luego continâ”śâ•‘a como camino homâ”śâ”‚nimo. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'EL RABAL', 41.65817400, -0.87068600, '0101000020E6100000C7B8E2E2A8DCEBBFEC89AE0B3FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35654391044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35654391044.webp', 'https://www.flickr.com/photos/zaragozaantigua/35654391044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22157, 'Franciscanos 1955', 'Procesiâ”śâ”‚n de San Antonio de Padua, con alumnos del colegio de San Francisco de Asâ”śÂˇs (convento ubicado, desde 1940 en el camino del Vado nâ”¬â•‘ 9, con residencia, colegio e iglesia), por el barrio de Jesâ”śâ•‘s. La imagen se ha obtenido, en un natural posado, en la plaza de Jesâ”śâ•‘s. Al fondo, a la derecha, la calle de Funes, con una pequeâ”śâ–’a vista lateral del cuartel de la Guardia Civil de la calle de Jesâ”śâ•‘s. Fuente: www.ofmval.org/', 1955, 1955, 1955, 'Anos 50', 'EL RABAL', 41.65812400, -0.87097700, '0101000020E6100000A12E52280BDFEBBF3A5B40683DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30370689333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30370689333.webp', 'https://www.flickr.com/photos/zaragozaantigua/30370689333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22399, 'Calle Estaciâ”śâ”‚n c.1966', 'Vista de la calle de la Estaciâ”śâ”‚n, con la plaza de Jesâ”śâ•‘s al fondo. Fuente: www.facebook.com/photo.php?fbid=10204966991847910&set...', 1966, 1966, 1966, 'Anos 60', 'EL RABAL', 41.65859600, -0.87148200, '0101000020E61000007DAF21382EE3EBBF62A3ACDF4CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23239319049.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23239319049.webp', 'https://www.flickr.com/photos/zaragozaantigua/23239319049/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22447, 'C.â”¬â•‘ del Vado 1966', 'Imagen aâ”śÂ®rea durante la construcciâ”śâ”‚n del nuevo enlace para derivar las comunicaciones ferroviarias entre Zaragoza y Huesca desde el empalme de Miraflores. Hasta ese momento, la conexiâ”śâ”‚n se realizaba a travâ”śÂ®s del puente de la Almozara y la estaciâ”śâ”‚n del Norte. Las obras finalizaron en julio de 1968, y con esta nueva ruta, el antiguo trazado iniciâ”śâ”‚ su cuenta atrâ”śĂ­s para ser desmantelado como infraestructura ferroviaria. La captura se ha realizado a la altura del camino del Vado que, en primer plano, transita de derecha a izquierda hacia el Gâ”śĂ­llego. En este punto se estâ”śĂ­ emplazando la empresa Prefabricados Moldeados S.A. (Premolsa). Al fondo, y al otro lado del Ebro, la huerta de las Fuentes, desde donde proviene el despejado amojonamiento que indica el trazado de este nuevo enlace ferroviario. Fuente visual: Arxiu Nacional de Catalunya', 1966, 1966, 1966, 'Anos 60', 'EL RABAL', 41.65688600, -0.85236000, '0101000020E6100000D8648D7A8846EBBFA29927D714D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31069263344.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31069263344.webp', 'https://www.flickr.com/photos/zaragozaantigua/31069263344/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22462, 'Calle Sobrarbe 1968', 'Febrero de 1968. Entrada del colegio Câ”śĂ­ndido Domingo en la calle del Sobrarbe 8, junto a la iglesia de Altabâ”śĂ­s (izquierda). Edificio de Ricardo Magdalena de 1909 que fue derribado en 1970 para construir el actual. Fuente visual: www.facebook.com/photo.php?fbid=425484417477116&set=a...', 1968, 1968, 1968, 'Anos 60', 'EL RABAL', 41.65923500, -0.87415500, '0101000020E6100000F05014E813F9EBBF75B0FECF61D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32491020753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32491020753.webp', 'https://www.flickr.com/photos/zaragozaantigua/32491020753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22920, 'Calle de Balbino Orensanz c.1980', 'Imagen capturada en la calle de Balbino Orensanz, antes del Colector, con una escena flanqueada a la izquierda por la fâ”śĂ­brica de Amado Laguna Rins y a la derecha por las dos veteranas y gemelas naves industriales que confrontaban con ella, seguidas por el colegio nacional de EGB "La Jota" activo desde 1972. Tras â”śÂ®l, la calle de Joaquâ”śÂˇn Numancia, los dos bloques promovidos por "Hogar Cristiano" y mâ”śĂ­s al fondo los bloques recayentes a la avenida de la Jota. En primer tâ”śÂ®rmino y hacia la derecha, la calle del pintor Manuel Viola.', 1980, 1980, 1980, 'Anos 80', 'EL RABAL', 41.65939000, -0.85900400, '0101000020E61000000B43E4F4F57CEBBF9CA73AE466D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27717343550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27717343550.webp', 'https://www.flickr.com/photos/zaragozaantigua/27717343550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23250, 'Calle de Jesâ”śâ•‘s c.1935', 'Imagen capturada en el gran lavadero al aire del Puente del Pilar centrado en el acceso, al fondo, desde la calle de Jesâ”śâ•‘s, con vista de las parcelas de los nâ”śâ•‘meros 33, 35 y 37. En primer tâ”śÂ®rmino, la pila de lavar ropa con jabâ”śâ”‚n de "tajo". A la izquierda, pila de lavar a cubierto. A la derecha, alameda y arranque de la extensa zona de los tendederos. Este lavadero se abastecâ”śÂˇa de uno de los brazales de Jope de la acequia del Rabal.', 1935, 1935, 1935, 'Anos 30', 'EL RABAL', 41.65782700, -0.87036500, '0101000020E610000044A852B307DAEBBF80B6D5AC33D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060928093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060928093.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060928093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23666, 'Calle de Jesâ”śâ•‘s c.1972', 'Imagen capturada junto a la achaflanada esquina del final de la calle de la Estaciâ”śâ”‚n (en primer plano), con vista parcial del primer tramo de la calle de Jesâ”śâ•‘s, donde destaca el antiguo y enorme cuartel de la Guardia Civil sito en el moderno nâ”¬â•‘ 8 (antiguo 16), caracterâ”śÂˇstico por su entrante zona aprovechada como aparcamiento por los menudos coches de la â”śÂ®poca. A la izquierda, la esquina de ingreso a la calle de Funes. Inmediato, un llamativo contraste de firmes: adoquinado desde la calle de la Estaciâ”śâ”‚n, asfaltado, en la calle de Jesâ”śâ•‘s. Fuente visual: "Asociaciâ”śâ”‚n de Vecinos Barrio de Jesâ”śâ•‘s. 30 aâ”śâ–’os de Historia".', 1972, 1972, 1972, 'Anos 70', 'EL RABAL', 41.65814200, -0.87139400, '0101000020E6100000ACC77DAB75E2EBBFE00F3FFF3DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30467393542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30467393542.webp', 'https://www.flickr.com/photos/zaragozaantigua/30467393542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23950, 'Cine Norte 1960', 'En la calle de Jesâ”śâ•‘s, del barrio del mismo nombre. Esta sala se inaugurâ”śâ”‚ el 14 de octubre de 1953 con la proyecciâ”śâ”‚n de la pelâ”śÂˇcula "El sâ”śÂ®ptimo cielo" . Fue clausurada en noviembre de 1981 y el edificio derribado en febrero de 2007. Fuente visual: Asociaciâ”śâ”‚n de Vecinos del Barrio de Jesâ”śâ•‘s.', 1960, 1960, 1960, 'Anos 60', 'EL RABAL', 41.65802800, -0.87099200, '0101000020E6100000F67B629D2ADFEBBF18EDF1423AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700983029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700983029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700983029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24039, 'Marquâ”śÂ®s de la Cadena 2003', 'Imagen, desde altura, de la paloma de la paz formada por alumnado y padres de los colegios Hilariâ”śâ”‚n Gimeno, la Purâ”śÂˇsima y San Antonio, y la Asociaciâ”śâ”‚n de Vecinos Barrio de Jesâ”śâ•‘s, durante las movilizaciones sociales contra la implicaciâ”śâ”‚n explâ”śÂˇcita de Espaâ”śâ–’a en la segunda Guerra de Irak ("el trâ”śÂˇo de las Azores", Bush, Blair, Aznar). El solar donde tuvo lugar este acto, ademâ”śĂ­s, estaba siendo reivindicado para la construcciâ”śâ”‚n de un nuevo equipamiento educativo pâ”śâ•‘blico, que luego serâ”śÂˇa denominado CEIP Marie Curie, con entrada principal por la calle Molino de las Armas (a la izquierda). Al fondo, densa circulaciâ”śâ”‚n rodada por la calle del Marquâ”śÂ®s de la Cadena, y detrâ”śĂ­s, los bloques de viviendas junto a la calle Mâ”¬Â¬ Pilar de las Heras Dopereiro. Fuente visual: "Asociaciâ”śâ”‚n de Vecinos Barrio de Jesâ”śâ•‘s. 30 aâ”śâ–’os de Historia".', 2003, 2003, 2003, 'Siglo XXI', 'EL RABAL', 41.65972100, -0.86402400, '0101000020E6100000FBB0DEA815A6EBBF01BEDBBC71D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30246407290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30246407290.webp', 'https://www.flickr.com/photos/zaragozaantigua/30246407290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24178, 'Choque de trenes 1913', 'Choque de trenes a la salida de la Estaciâ”śâ”‚n del Norte en la curva que llevaba al tâ”śâ•‘nel de San Lâ”śĂ­zaro. Se trata de un tren correo que colisionâ”śâ”‚ con una locomotora. Al fondo, câ”śâ•‘pula mayor de la Basâ”śÂˇlica del Pilar.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.65906100, -0.87288800, '0101000020E61000006344A2D0B2EEEBBFD788601C5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15282120374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15282120374.webp', 'https://www.flickr.com/photos/zaragozaantigua/15282120374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24180, 'Estaciâ”śâ”‚n del Norte 1930', 'Vista del Arrabal zaragozano, con la Estaciâ”śâ”‚n del Norte ferroviaria presidiendo el entorno. Fuente: Zaragoza 1908-2008. FCC.', 1930, 1930, 1930, 'Anos 30', 'EL RABAL', 41.65968100, -0.87189300, '0101000020E6100000009013268CE6EBBF7365506D70D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15523934069.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15523934069.webp', 'https://www.flickr.com/photos/zaragozaantigua/15523934069/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24181, 'Estaciâ”śâ”‚n del Norte 1935', 'Plano de la zona de la Estaciâ”śâ”‚n del Norte realizado por el Instituto Geogrâ”śĂ­fico y Catastral, coloreado posteriormente. Fuente visual: eszaragoza.blogspot.com.es/2014/02/la-estacion-del-norte-...', 1935, 1935, 1935, 'Anos 30', 'EL RABAL', 41.65968100, -0.87189300, '0101000020E6100000009013268CE6EBBF7365506D70D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15659723188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15659723188.webp', 'https://www.flickr.com/photos/zaragozaantigua/15659723188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24196, 'Estaciâ”śâ”‚n del Norte c.1920', 'Acceso a la estaciâ”śâ”‚n ferroviaria del Norte o del Arrabal. Fuente: Foto Jesâ”śâ•‘s Cormâ”śĂ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.65968100, -0.87189300, '0101000020E6100000009013268CE6EBBF7365506D70D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24797241492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24797241492.webp', 'https://www.flickr.com/photos/zaragozaantigua/24797241492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24214, 'Arrabal 1935', 'Imagen capturada junto a las vâ”śÂˇas ferroviarias de la curva que hacia la derecha se dirigen a la estaciâ”śâ”‚n del Arrabal. Circula una locomotora vaporosa, posiblemente una "Chaleco". En primer tâ”śÂ®rmino, el convento de la terciarias franciscanas de Altabâ”śĂ­s con ingreso desde la calle del Sobrarbe. Hacia el fondo, el puente de Piedra y el templo del Pilar con andamios sobre sus câ”śâ•‘pulas orientales, entre ellas la de la capilla de la Virgen.', 1935, 1935, 1935, 'Anos 30', 'EL RABAL', 41.65882900, -0.87310100, '0101000020E61000004F5B238271F0EBBF0454388254D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50978794727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50978794727.webp', 'https://www.flickr.com/photos/zaragozaantigua/50978794727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24496, 'Harinas Gavâ”śÂˇn 1912', 'Cabecera de factura de "La Moderna" Fâ”śĂ­brica de Harinas Francisco Gavâ”śÂˇn y Compaâ”śâ–’â”śÂˇa, con sede en "Carretera del Puente del Gâ”śĂ­llego nâ”śâ•‘meros 239 y 240, frente a la estaciâ”śâ”‚n del Norte". La ilustraciâ”śâ”‚n reproduce sus instalaciones, en la que serâ”śĂ­ avenida de Cataluâ”śâ–’a, en la manzana entre las calles de la Estaciâ”śâ”‚n ( a la derecha), y del Norte (a la izquierda). Esta fâ”śĂ­brica formaba parte, junto con las de Solâ”śĂ­ns, y Guiu, del nâ”śâ•‘cleo molinero del Arrabal en la segunda dâ”śÂ®cada del siglo XX, y hay constancia de su actividad desde 1912, y hasta 1922. Fuente: www.todocoleccion.net', 1912, 1912, 1912, 'Anos 10', 'EL RABAL', 41.65985700, -0.87047700, '0101000020E61000003672DD94F2DAEBBFB284B53176D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29975587684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29975587684.webp', 'https://www.flickr.com/photos/zaragozaantigua/29975587684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24780, 'Calle de Jesâ”śâ•‘s 1977', 'Imagen del desemboque de la calle de Jesâ”śâ•‘s, desde la izquierda, en la avenida del Puente del Pilar, con una interesante panorâ”śĂ­mica de las antiguas y simpares viviendas impares que aquâ”śÂˇ se levantaban, hasta el inmediato 43 que, aun con una altura menos, tenâ”śÂˇa una envidiable visual del entorno por su esquinera ubicaciâ”śâ”‚n, y ademâ”śĂ­s era un "Bar-Churrerâ”śÂˇa". Al fondo, a la izquierda, sesenteros y sobresalientes edificios de la calle de Valimaâ”śâ–’a, recayentes a la plaza de Jesâ”śâ•‘s, heraldos del futuro porvenir. La mutaciâ”śâ”‚n de esta manzana entre las calles de Jesâ”śâ•‘s, Valimaâ”śâ–’a, y Corralâ”śÂ®, ha sido notable, entre derribos, nuevas construcciones, y un buen repertorio de solares. De las parcelas de la imagen, no queda ni una. Y pensar que esta calle llegâ”śâ”‚ a tener incluso â”śĂ­rboles, cuando en la acera de enfrente estaban los grandes lavaderos y tendederos que fueran de Modesto Andrâ”śÂ®s. Fuente visual: amable aportaciâ”śâ”‚n personal de Pablo Valdâ”śÂ®s.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.65778100, -0.86958100, '0101000020E61000009F2287889BD3EBBF1077F52A32D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26939145335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26939145335.webp', 'https://www.flickr.com/photos/zaragozaantigua/26939145335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24781, 'Calle Sobrarbe 1977', 'Crepuscular, despejada e insâ”śâ”‚lita imagen del tramo de la calle de Sobrarbe en torno a la iglesia parroquial de Nâ”¬Â¬ Sâ”¬Â¬ de Altabâ”śĂ­s, cuya nueva planta fue inaugurada en 1892. Al fondo, a la derecha, el cimborrio del metropolitano templo de El Salvador, una filigrana de Mahoma Ramâ”śÂˇ, anuncia que, aun con el Ebro de por medio, esta parte del antiguo Arrabal de Altabâ”śĂ­s formaba parte de la ciudad desde muchos siglos ha, con edificios tan representativos como el mercedario convento de San Lâ”śĂ­zaro, y los franciscanos de Nâ”¬Â¬ Sâ”¬Â¬ de Jesâ”śâ•‘s, y el de Santa Isabel. Pese a la cercanâ”śÂˇa, la natural trinchera fluvial marcâ”śâ”‚ un devenir diferenciado, autâ”śâ”‚nomo. No podâ”śÂˇa ser de otra forma, con un râ”śÂˇo tan irregular en su caudal, tan mediterrâ”śĂ­neo, como el Ebro, pese a los delirios de quien se lo imagina ubâ”śÂ®rrimo en nautas y navâ”śÂˇos. Sus monumentales salidas de madre, siempre noticia, eclipsaban con sus tremendas afecciones las largas temporadas en que, durante el resto del aâ”śâ–’o, se podâ”śÂˇa vadear con relativa facilidad. Eso del dragado es una cosa muy reciente. En la luminosa imagen, la fachada de los pares nos alumbra, en primer tâ”śÂ®rmino, una casona que ya no estâ”śĂ­, muestra de la arquitectura popular de esta veterana zona. A su lado, perduran el elaborado nâ”¬â•‘ 16, el humildâ”śÂˇsimo nâ”¬â•‘ 14, el nâ”¬â•‘ 12 de la iglesia, y el nâ”¬â•‘ 10. Luego, el colegio "Câ”śĂ­ndido Domingo", con su nueva fâ”śĂ­brica de 1970, que sustituyâ”śâ”‚ a la inaugurada en 1909 con diseâ”śâ–’o de Ricardo Magdalena. Despuâ”śÂ®s, el convento de Santa Isabel reconstruido tras el asedio de 1808, que llegaba hasta la antigua plaza de san Lâ”śĂ­zaro. Tras pasar las vâ”śÂˇas del ferrocarril, quedaba el cuartel de ese mismo nombre. Fuente visual: amable aportaciâ”śâ”‚n personal de Pablo Valdâ”śÂ®s.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.65941600, -0.87396900, '0101000020E61000006AF816D68DF7EBBFC53A55BE67D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27257313276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27257313276.webp', 'https://www.flickr.com/photos/zaragozaantigua/27257313276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24784, 'Arrabal c.1967', 'Esplendorosa locomotoca anglosajona "Avonside" que, compuesta allâ”śĂ­ por 1865, seguâ”śÂˇa traqueteando de forma funcional un siglo despuâ”śÂ®s, en este caso desde la estaciâ”śâ”‚n del Norte (al fondo, inaugurada tambiâ”śÂ®n al principio de esa decimonâ”śâ”‚nica dâ”śÂ®cada) en direcciâ”śâ”‚n al enlace ferroviario hacia Alsasua, durante una tarde luminosa, con la tripulaciâ”śâ”‚n sonriendo al objetivo. A la derecha, asoma el remate con reloj del edificio de de las oficinas principales de la Maquinista y Fundiciones del Ebro S.A., junto a la avenida de Cataluâ”śâ–’a. Fuente visual: Javier Santamarâ”śÂˇa, en www.spanishrailway.com/', 1967, 1967, 1967, 'Anos 60', 'EL RABAL', 41.65940000, -0.87259600, '0101000020E610000073DA53724EECEBBFBF7D1D3867D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29988346264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29988346264.webp', 'https://www.flickr.com/photos/zaragozaantigua/29988346264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24801, 'Calle Alfonso Zapater 2009', 'Vista del solar entre las calles de Alfonso Zapater Cerdâ”śĂ­n (desde donde estâ”śĂ­ tomada la foto), Mariano Cebollero (derecha), Jorge Sâ”śĂ­nchez Candial (al fondo) y Antonio Royo (izquierda, fuera de plano). Mâ”śĂ­s al fondo, los bloques de la calle Nobleza Baturra, en direcciâ”śâ”‚n hacia el Ebro. Aquâ”śÂˇ se construirâ”śĂ­ en 2011 el Colegio Pâ”śâ•‘blico de Infantil y Primaria Vadorrey-Les Allâ”śÂ®es. Fuente visual: Heraldo de Aragâ”śâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'EL RABAL', 41.65673400, -0.85654900, '0101000020E6100000F67CCD72D968EBBFEC1516DC0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33105317192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33105317192.webp', 'https://www.flickr.com/photos/zaragozaantigua/33105317192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24819, 'Avenida del puente del Pilar 1992', 'Imagen centrada en el antiguo inmueble del nâ”¬â•‘ 19 de la avenida del Puente del Pilar, esquinero con el principio de la calle de Jacinto Corralâ”śÂ®. Esta calle recibiâ”śâ”‚ su nombre de la homâ”śâ”‚nima Torre pegada al sur del convento de Jesâ”śâ•‘s por donde fue trazada cuando la reparcelaciâ”śâ”‚n de esa zona en los aâ”śâ–’os 20 del pasado siglo XX. Esta vivienda se construyâ”śâ”‚ en esa â”śÂ®poca, y serâ”śÂˇa derribada aâ”śâ–’os despuâ”śÂ®s de tomada esta fotografâ”śÂˇa, como su vecina del nâ”¬â•‘ 21 a la derecha, para ensanchar la avenida.', 1992, 1992, 1992, 'Anos 90', 'EL RABAL', 41.65818800, -0.86932500, '0101000020E6100000E10B93A982D1EBBF514F1F813FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50199796771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50199796771.webp', 'https://www.flickr.com/photos/zaragozaantigua/50199796771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24829, 'Calle del Sobrarbe c.1900', 'â”śĂ´leo del pintor navarro Leopoldo Albesa Membrado que representa una escena urbana localizada en la calle del Sobrarbe vertebradora del Arrabal zaragozano en su ascenso hacia la carretera de Huesca. A la izquierda, el largo tramo de este vial comprendido entre el convento de Altabâ”śĂ­s al fondo y el luminoso ingreso al patio de carros de la estaciâ”śâ”‚n del Norte. A la derecha, el tramo articulado por el camino de Juslibol y las calles del Horno, de Jorge Ibort y de Villacampa. Al fondo y en la margen derecha, la barroca torre de la Seo emerge tras el edificio del Seminario conciliar.', 1900, 1900, 1900, 'Anos 1900', 'EL RABAL', 41.65911900, -0.87426300, '0101000020E6100000884A2366F6F9EBBF0B96EA025ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54588999160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54588999160.webp', 'https://www.flickr.com/photos/zaragozaantigua/54588999160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24752, 'Calle Horno 1977', 'Vista de la estrecha calle del Horno de Zaragoza. Al fondo, la calle de Manuel Lacruz. A la espalda, la calle del Sobrarbe. Fuente: La orilla izquierda del Ebro zaragozano, Marâ”śÂˇa Carmen Faus, 1988.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.65938100, -0.87496900, '0101000020E61000003F7100FDBEFFEBBF494DBB9866D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18998507100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18998507100.webp', 'https://www.flickr.com/photos/zaragozaantigua/18998507100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24821, 'Calle de Mariano Gracia c.1992', 'Imagen capturada desde la calle de Manuel Lacruz (originalmente del Rosario) y centrada en los seriados inmuebles del siglo XVII correspondientes a los nâ”śâ•‘meros 1, 3 y 5 del principio de la calle de Mariano Gracia, antigua de Cantarranas. A finales de dâ”śÂ®cada, estos edificios fueron rehabilitados e integrados al actual nâ”¬â•‘ 24-28 de la calle de Sixto Celorrio. Al fondo, el setentero bloque del nâ”¬â•‘ 1, 3, 5 de la calle de Gregorio Garcâ”śÂˇa Arista, radical contraste con el caserâ”śÂˇo tradicional de esta zona del casco histâ”śâ”‚rico del Arrabal.', 1992, 1992, 1992, 'Anos 90', 'EL RABAL', 41.65961500, -0.87531200, '0101000020E6100000B77BB94F8E02ECBFBC79AA436ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50213249743.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50213249743.webp', 'https://www.flickr.com/photos/zaragozaantigua/50213249743/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24798, 'Vista aâ”śÂ®rea Norte c.1968', 'Vista aâ”śÂ®rea parcial del norte de Zaragoza, con el Pilar abajo y la margen izquierda al fondo. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'EL RABAL', 41.66138300, -0.87986300, '0101000020E6100000FDBB3E73D627ECBFB090B932A8D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32876805253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32876805253.webp', 'https://www.flickr.com/photos/zaragozaantigua/32876805253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20935, 'Acequia de Santa Bâ”śĂ­rbara 1769', '"Plano demonstrativo del curso que tiene y lleva la Acequia de Santa Bâ”śĂ­rbara, con los riegos dependientes de ella, partida de Val de Espartera y demâ”śĂ­s que en el mismo se expresan". Orientado de sur a norte, el plano incluye el recorrido de la acequia de Santa Bâ”śĂ­rbara, junto a los terrenos de Valdespartera. Fuente: AHPZ.', 1769, 1769, 1769, 'Siglo XIX', 'CASABLANCA', 41.62839000, -0.93496200, '0101000020E61000008B16A06D35EBEDBF159161156FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31114453490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31114453490.webp', 'https://www.flickr.com/photos/zaragozaantigua/31114453490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21082, 'Esclusas Casablanca c.1878', 'Imagen de las ilustradas esclusas de San Carlos, o de Casablanca, en el Canal Imperial. La captura se ha realizado desde el puente que salvaba el Canal para dar paso a la carretera de Zaragoza a Valencia, y la lâ”śÂˇnea de ferrocarril a Caminreal. Los edificios del fondo, una antigua harinera reconvertida en dependencias militares, unos aâ”śâ–’os antes de ser habilitados en convento de los padres Pasionistas. Fuente visual: "Zaragoza dos milenios de agua", Carlos Blâ”śĂ­zquez. Aunque esta imagen figura como "Archivo Coyne", su autor fue Venancio Villas Langa.', 1878, 1878, 1878, 'Siglo XIX', 'CASABLANCA', 41.62833800, -0.90888200, '0101000020E6100000CE893DB48F15EDBFC26A2C616DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26089781651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26089781651.webp', 'https://www.flickr.com/photos/zaragozaantigua/26089781651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21120, 'Embarcadero Casablanca 1880', 'Imagen de las gradas que conformaban el antiguo embarcadero recreativo de Casa Blanca, inmediatas al puente de piedra por el que la carretera de Zaragoza a Valencia por Teruel salvaba el Canal Imperial, justo a la izquierda, fuera de plano. Las barcazas de transporte utilizaban las esclusas, luego auxiliadas por las caballerâ”śÂˇas que por el camino de sirga, a la derecha, tiraban de ellas. Al fondo, la Fuente de los Incrâ”śÂ®dulos en su original ubicaciâ”śâ”‚n, y construcciones junto a la carretera de Teruel. Unos pocos aâ”śâ–’os despuâ”śÂ®s se habilitarâ”śÂˇa otro paso sobre el Canal para el camino de hierro del ferrocarril de Cariâ”śâ–’ena a Zaragoza, cuyo trazado fue establecido por detrâ”śĂ­s de la fuente. Fuente visual: Foto Venancio Villas Langa, AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CASABLANCA', 41.62806000, -0.90801200, '0101000020E610000086048C2E6F0EEDBF7FF6234564D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30919041124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30919041124.webp', 'https://www.flickr.com/photos/zaragozaantigua/30919041124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21663, 'Valdespartera 1920', 'Imagen capturada a finales del mes de septiembre durante el concurso de tractores organizado por el Consejo provincial de Fomento y la cooperaciâ”śâ”‚n de la Diputaciâ”śâ”‚n provincial, el Ayuntamiento y todas las entidades locales de carâ”śĂ­cter agrâ”śÂˇcola en el entorno del campo de Valdespartera. Si bien no fue la primera prueba de este tipo, sâ”śÂˇ fue la mâ”śĂ­s importante realizada hasta la fecha por el nâ”śâ•‘mero de marcas inscritas (hasta 34). Al objeto de facilitar el acceso de pâ”śâ•‘blico asistente, la organizaciâ”śâ”‚n dispuso un "camiâ”śâ”‚n automâ”śâ”‚vil" que cada hora partâ”śÂˇa desde la plaza de la Constituciâ”śâ”‚n hasta el lugar del concurso. En la escena, posiblemente un tractor-tanque Holt 23/40 de la marca estadounidense Caterpillar realiza una prueba de arada bajo la atenta mirada de los miembros del jurado.', 1920, 1920, 1920, 'Anos 20', 'CASABLANCA', 41.61982400, -0.92727100, '0101000020E610000056EF703B34ACEDBF51A3906456CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54960928426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54960928426.webp', 'https://www.flickr.com/photos/zaragozaantigua/54960928426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21863, 'Casablanca 1934', 'Imagen de una de las dos terrazas del bar restaurant El Caserâ”śÂˇo Aragonâ”śÂ®s, muy frecuentado establecimiento de restauraciâ”śâ”‚n ubicado en el barrio de Casablanca, cerca de las homâ”śâ”‚nimas esclusas, junto a la carretera de Valencia y el Canal Imperial. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASABLANCA', 41.62820400, -0.90766900, '0101000020E61000000DFAD2DB9F0BEDBFB29B19FD68D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36328624161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36328624161.webp', 'https://www.flickr.com/photos/zaragozaantigua/36328624161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21876, 'Esclusas Casablanca 1935', '"Doble resclosa de Casablanca, al canal Imperial, prop de Saragossa". Imagen capturada desde el antiguo puente de la carretera de Zaragoza a Valencia, con una interesante visual, en primer tâ”śÂ®rmino, del metâ”śĂ­lico puente ferroviario, el complejo de las esclusas de Casablanca, donde se salva un importante desnivel del Canal Imperial que Elâ”śÂ®ctricas Reunidas aprovechaba para una fâ”śĂ­brica de electricidad que allâ”śÂˇ tenâ”śÂˇa. Al fondo, al otro lado del Canal Imperial, el convento y colegio de los PP. Pasionistas de Casablanca, Fuente visual: Fotografâ”śÂˇa de S. Gosâ”śÂ® en Arxiu Nacional de Catalunya.', 1935, 1935, 1935, 'Anos 30', 'CASABLANCA', 41.62817000, -0.90843200, '0101000020E6100000D57954FCDF11EDBF062AE3DF67D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40560874800.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40560874800.webp', 'https://www.flickr.com/photos/zaragozaantigua/40560874800/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21911, 'Casablanca 1938', 'Imagen centrada en el edificio de la falangista emisora "Radio Zaragoza E.A.J. 101" junto al Canal Imperial de Aragâ”śâ”‚n y en la parte alta de Casablanca, el dâ”śÂˇa de su solemne inauguraciâ”śâ”‚n cuando desde sus micrâ”śâ”‚fonos se radiâ”śâ”‚ el "histâ”śâ”‚rico" discurso del "Caudillo" Francisco Franco con motivo del I aniversario del Decreto de unificaciâ”śâ”‚n de FET y de la JONS, escuchado en Zaragoza por una gran reuniâ”śâ”‚n de "73.457" falangistas y "la poblaciâ”śâ”‚n toda" de la ciudad, concentrada en el Campo de la Victoria. En primer tâ”śÂ®rmino, uno de los miembros de la guardia personal del "Generalâ”śÂˇsimo", con su reconocible "turbante blanco y capa roja".', 1938, 1938, 1938, 'Anos 30', 'CASABLANCA', 41.63570800, -0.91619900, '0101000020E6100000CA17B4908051EDBF1DE736E15ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51884261905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51884261905.webp', 'https://www.flickr.com/photos/zaragozaantigua/51884261905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22064, 'Isabel la Catâ”śâ”‚lica 1956', 'Vista aâ”śÂ®rea de Isabel la Catâ”śâ”‚lica desde las esclusas de Casablanca y el Canal Imperial (en primer tâ”śÂ®rmino). A la izquierda, aâ”śâ•‘n quedan rastros del antiguo trazado del ferrocarril de Cariâ”śâ–’ena por Casablanca. En el centro, construcciâ”śâ”‚n del Hospital Militar que supondrâ”śĂ­ el abandono de las instalaciones del recinto junto a la Iglesia de Santiago el Mayor.', 1956, 1956, 1956, 'Anos 50', 'CASABLANCA', 41.63074200, -0.90444200, '0101000020E6100000641F645930F1ECBF581B6327BCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15056716205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15056716205.webp', 'https://www.flickr.com/photos/zaragozaantigua/15056716205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22288, 'Vâ”śÂˇa de la Hispanidad 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 02/04/1965. "Inauguraciâ”śâ”‚n de la Vâ”śÂˇa Hispanidad." El presidente del "Instituto de Cultura Hispâ”śĂ­nica", Gregorio Maraâ”śâ–’â”śâ”‚n Moya, fue nombrado "caballero del Pilar" en la capilla de la Virgen por el arzobispo Cantero. Aprovechando viaje, inaugurâ”śâ”‚ la avenida de la "Vâ”śÂˇa de la Hispanidad", hasta entonces "carretera de Los Enlaces", pues el Instituto que presidâ”śÂˇa puso el dinero para las monumentales placas que, como la de la imagen, seâ”śâ–’alaban la nueva vâ”śÂˇa. En la imagen, inauguraciâ”śâ”‚n junto a una de las placas, donde la nueva carretera de Valencia (desde 1975, Vâ”śÂˇa Ibâ”śÂ®rica) se abre a la izquierda hacia la Vâ”śÂˇa de la Hispanidad.', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.63222000, -0.90573900, '0101000020E61000009BC6F65AD0FBECBF45F0BF95ECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15206601647.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15206601647.webp', 'https://www.flickr.com/photos/zaragozaantigua/15206601647/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22305, 'Canal Imperial 1967', 'Acampada libre en Valdefierro, a orillas del Canal Imperial. Esta barriada deriva su nombre de la zona del Brazal de Fierro, que estaba surtida por el riego homâ”śâ”‚nimo de agua procedente del Huerva derivado de la acequia del Medio. El puente acueducto sobre el Canal de la imagen, llamado de Enmedio, servâ”śÂˇa desde finales del siglo XVIII para dar continuidad a ese riego. El campin municipal de Casablanca se encontraba a espaldas del fotâ”śâ”‚grafo. Fuente visual: Ediciones Arribas, en www.facebook.com/photo.php?fbid=400711503426853&set=o...', 1967, 1967, 1967, 'Anos 60', 'CASABLANCA', 41.63489800, -0.92607600, '0101000020E61000002F89B3226AA2EDBFDD25715644D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15619035777.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15619035777.webp', 'https://www.flickr.com/photos/zaragozaantigua/15619035777/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22328, 'Parroquia de San Vicente de Paâ”śâ•‘l 1967', 'El Arzobispo Cantero dio en 1965 el placet para que una antigua capilla-ermita del Canal Imperial de Aragâ”śâ”‚n fuera cedida y se convirtiera en la provisional iglesia parroquial de San Vicente de Paâ”śâ•‘l (Padres Paâ”śâ•‘les) de Casablanca. Con una grey estimada en 4.000 almas, estuvo activa hasta que las obras de ensanchamiento para el trâ”śĂ­fico rodado de la antigua carretera de Valencia, que en este tramo serâ”śĂ­ denominada "Vâ”śÂˇa ibâ”śÂ®rica", requirieron su necesaria demoliciâ”śâ”‚n, y el retranqueamiento de la Fuente de los Incrâ”śÂ®dulos, que se tuvo que apartar de su original ubicaciâ”śâ”‚n, para no molestar. Esta modesta capilla habâ”śÂˇa sido construida en formas neoclâ”śĂ­sicas con ocasiâ”śâ”‚n de la llegada de las aguas del Canal Imperial a Zaragoza en 1787, bajo la advocaciâ”śâ”‚n de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, y ofrecâ”śÂˇa ceremonias los dâ”śÂˇas festivos. Fuese, y luego ya no hubo nada. En la imagen, fachadita de la parroquia, con su exclusiva espadaâ”śâ–’a, capturada desde una tranquila y adoquinada carretera de Valencia. A la izquierda, a unas decenas de metros, la Fuente de los Incrâ”śÂ®dulos en su original ubicaciâ”śâ”‚n. A la derecha, la calle Embarcadero, antigua de La Ermita. Fuente visual: pauleszaragoza.org/', 1967, 1967, 1967, 'Anos 60', 'CASABLANCA', 41.62920500, -0.90765900, '0101000020E61000002A711DE38A0BEDBF66BD18CA89D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17715692140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17715692140.webp', 'https://www.flickr.com/photos/zaragozaantigua/17715692140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22351, 'Stadium Casablanca 1969', 'Barcas a la entrada del Stadium Casablanca de Acciâ”śâ”‚n Catâ”śâ”‚lica de Zaragoza, en el Canal Imperial de Aragâ”śâ”‚n. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CASABLANCA', 41.62447300, -0.90662400, '0101000020E61000003999B8551003EDBF151E34BBEECF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20558391611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20558391611.webp', 'https://www.flickr.com/photos/zaragozaantigua/20558391611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22457, 'Isabel la Catâ”śâ”‚lica 1965', 'Imagen volandera centrada en la primera fase constructiva del proyecto de torres de viviendas en la confluencia del paseo de Isabel la Catâ”śâ”‚lica con el enlace de carreteras. A su izquierda, el murete que delimita el nuevo Hospital Militar. A su derecha, el Colegio-Residencia de Nuestra Seâ”śâ–’ora del Pilar para Huâ”śÂ®rfanos e Hijos del Magisterio. Al otro lado del paseo, vista parcial del convento de Jerusalâ”śÂ®n, y los campos de herbâ”śĂ­ceas y torres agrâ”śÂˇcolas en el feraz entorno del Seminario. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.63242200, -0.90360200, '0101000020E6100000C634D3BD4EEAECBFADA23F34F3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31800429245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31800429245.webp', 'https://www.flickr.com/photos/zaragozaantigua/31800429245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22478, 'Ctra. de Valencia c.1965', 'Imagen capturada en la carretera de Zaragoza a Valencia, en el tramo previo a la fuente de los Incrâ”śÂ®dulos y las esclusas de Casablanca, con una vista parcial de los edificios de los nâ”śâ•‘meros 83 a 86, ubicados frente a la antigua casa de San Carlos y la capilla-ermita de Nuestra Seâ”śâ–’ora del Pilar. A la derecha, un pedazo de la fachada de la casa de Miguel Rived recayente a la carretera de Valencia. Ninguna de estas estructuras perdura. Fuente visual: Nuria Asâ”śÂˇn Garcâ”śÂˇa, "Recuerdos de Casablanca", Ediciones 94, (2015).', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.62941500, -0.90696000, '0101000020E610000012F758FAD005EDBF514EB4AB90D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34950276292.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34950276292.webp', 'https://www.flickr.com/photos/zaragozaantigua/34950276292/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22479, 'Calle del Embarcadero c.1965', 'Imagen capturada en la calle del Embarcadero del barrio de Casablanca, y orientada hacia su arranque, al fondo, por donde pasa la carretera de Zaragoza a Valencia. En el lado izquierdo de la calle, donde aparece estacionado un joven vecino sobre una motoneta Lambretta, muros de la antigua casa de San Carlos. En el lado derecho, y fuera de plano, la dieciochesca capilla-ermita de Nuestra Seâ”śâ–’ora del Pilar, que proyecta su leve sombra al atardecer. El firme de la calle, terrestre a mâ”śĂ­s no poder. Fuente visual: Nuria Asâ”śÂˇn Garcâ”śÂˇa, "Recuerdos de Casablanca", Ediciones 94, (2015).', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.62964000, -0.90752900, '0101000020E61000009E7DE5417A0AEDBF7120240B98D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35144364095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35144364095.webp', 'https://www.flickr.com/photos/zaragozaantigua/35144364095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22524, 'Vâ”śÂˇa de la Hispanidad 1970', 'Junto a la estaciâ”śâ”‚n de servicio de Casablanca, a la derecha de la imagen, un rebaâ”śâ–’o de ovejas, a rueda de las cabras, cruza por la Vâ”śÂˇa de la Hispanidad, reciente denominaciâ”śâ”‚n de la antigua carretera de Los Enlaces. A la izquierda, el nuevo polâ”śÂˇgono de la Gran Vâ”śÂˇa, redenominado de la Romareda. La imagen capta un momento de transiciâ”śâ”‚n pactada entre el mundo rural que caracterizâ”śâ”‚ esta periferia de la ciudad, con el moderno de los altos bloques y las carreteras para vehâ”śÂˇculos a gran velocidad. Un camiâ”śâ”‚n procedente de la gasolinera espera paciente. Por este entorno cruzaba antaâ”śâ–’o la antigua lâ”śÂˇnea ferrovaria de Cariâ”śâ–’ena, hasta 1933. A la derecha, la calle de La Vâ”śÂˇa recuerda el paso de este tren de vâ”śÂˇa estrecha. Al fondo, una glorieta, actual rotonda de Toulouse, en la confluencia del paseo de Isabel la Catâ”śâ”‚lica, la Vâ”śÂˇa Ibâ”śÂ®rica y la propia Vâ”śÂˇa de la Hispanidad.', 1970, 1970, 1970, 'Anos 70', 'CASABLANCA', 41.63382400, -0.90816300, '0101000020E6100000F0FD0DDAAB0FEDBFBFB5132521D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665038980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665038980.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665038980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22528, 'Almenara del Pilar 1970', 'Desde 1961, el "Paseo de los Reyes de Aragâ”śâ”‚n" comenzaba en el Rincâ”śâ”‚n de Goya y desembocaba en la Carretera de Valencia, donde las esclusas de Casablanca. La imagen recoge un despejado pedazo de este Paseo, en la pronunciada y cerrada curva donde la Almenara de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar seâ”śâ–’ala el punto donde se cruzan el Canal Imperial y el râ”śÂˇo Huerva. El Puente de un ojo seâ”śâ–’ala el cauce del Canal por encima del râ”śÂˇo. A su izquierda, la Almenara y, escalonado, el aporte de agua del Canal al râ”śÂˇo. A la derecha, el Paseo asciende poco a poco hasta la Fuente de los Incrâ”śÂ®dulos y las Esclusas. Detalle de la carretera que deriva y que conducirâ”śĂ­ pronto a la Urbanizaciâ”śâ”‚n "Fuentes Claras". Todo el entorno estâ”śĂ­ mucho menos poblado de vegetaciâ”śâ”‚n, â”śĂ­rboles, y exclusividad residencial. Al fondo, el cuartel de Valdespartera. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1970, 1970, 1970, 'Anos 70', 'CASABLANCA', 41.62225100, -0.90475700, '0101000020E61000006077BAF3C4F3ECBF9F73B7EBA5CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14704752439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14704752439.webp', 'https://www.flickr.com/photos/zaragozaantigua/14704752439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22805, 'Pasionistas 1976', 'Imagen aâ”śÂ®rea del moderno complejo formado por la residencia de los padres Pasionistas y la iglesia parroquial de Santa Gema construido junto a la Colonia de Nuestra Seâ”śâ–’ora de las Nieves y con ingreso por la calle de la Sagrada Familia, en primer tâ”śÂ®rmino. A la izquierda y tras la calle de Marcelino â”śĂĽlvarez, instalaciones de la fundiciâ”śâ”‚n de Ebroacero. Al fondo, la calle del Greco. A la derecha, vista tangencial del antiguo convento de los Pasionistas, derribado un par de aâ”śâ–’os despuâ”śÂ®s, junto al Canal Imperial de Aragâ”śâ”‚n.', 1976, 1976, 1976, 'Anos 70', 'CASABLANCA', 41.62878000, -0.91166100, '0101000020E6100000AC3C81B0532CEDBF7F30F0DC7BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49904753401.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49904753401.webp', 'https://www.flickr.com/photos/zaragozaantigua/49904753401/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22806, 'Pasionistas 1976', 'Imagen aâ”śÂ®rea centrada en el moderno complejo formado por la residencia de los padres Pasionistas y la iglesia parroquial de Santa Gema construido junto a la Colonia de Nuestra Seâ”śâ–’ora de las Nieves y con ingreso por la calle de la Sagrada Familia, a la derecha. Contrasta el antiguo convento de los Pasionistas, que serâ”śÂˇa derribado un par de aâ”śâ–’os despuâ”śÂ®s. En primer tâ”śÂ®rmino, la calle de Marcelino â”śĂĽlvarez. Hacia el fondo, la arboleda ribera del Canal Imperial de Aragâ”śâ”‚n, y tras â”śÂ®l el entorno edilicio de la calle de la Ermita, la del Embarcadero y la del Prado, en el barrio de Casablanca.', 1976, 1976, 1976, 'Anos 70', 'CASABLANCA', 41.62873900, -0.91174700, '0101000020E61000004F3C670B082DEDBF215C01857AD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49966610228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49966610228.webp', 'https://www.flickr.com/photos/zaragozaantigua/49966610228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22826, 'Cristo legionario 1973', 'Imagen del artista plâ”śĂ­stico Iâ”śâ–’aki Rodrâ”śÂˇguez Ruiz "Iâ”śâ–’aki" (Bilbao, 1940-Zaragoza, 2018) ultimando la imagen del "Cristo de la Buena Muerte" encargado por la Hermandad de Caballeros Legionarios que habrâ”śÂˇa de formar parte central del "paso" de Semana Santa del Santâ”śÂˇsimo Cristo de la Buena Muerte. La captura se ha realizado en los talleres de la Instituciâ”śâ”‚n Sindical de Formaciâ”śâ”‚n Profesional "Virgen del Pilar", dos de cuyos alumnos y profesores aparecen aquâ”śÂˇ colaborando en la faena. Realizado en hierro forjado, este bulto redondo se montarâ”śÂˇa luego sobre una ballesta, una alabarda y un arcabuz, elementos todos ellos en madera integrantes del emblema de la Legiâ”śâ”‚n Espaâ”śâ–’ola, y serâ”śÂˇa bendecido solemnemente por el arzobispo Pedro Cantero Cuadrado. Unos dâ”śÂˇas despuâ”śÂ®s se programâ”śâ”‚ la participaciâ”śâ”‚n de este "paso" con su cofradâ”śÂˇa en las procesiones de Semana Santa, aunque una carta del arzobispo recomendâ”śâ”‚ suprimir los artefactos bâ”śÂ®licos (las referidas ballesta, alabarda y arcabuz) al objeto de evitar que "pudieran dar lugar a errâ”śâ”‚neas interpretaciones"... Como buenos catâ”śâ”‚licos, desde la Hermandad de Caballeros Legionarios se procediâ”śâ”‚ a suprimir esos elementos, que tras procesionar solemnemente sin ellos le serâ”śÂˇan repuestos al depositar la imagen del Cristo de la Buena Muerte en la cripta del Monumento Nacional a los Caâ”śÂˇdos de la Legiâ”śâ”‚n que se alza en los pinares de Venecia.', 1973, 1973, 1973, 'Anos 70', 'CASABLANCA', 41.62572900, -0.90612000, '0101000020E6100000740CC85EEFFEECBF53944BE317D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52796033871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52796033871.webp', 'https://www.flickr.com/photos/zaragozaantigua/52796033871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22929, 'Vâ”śÂˇa de la Hispanidad 1987', 'Aragonesa de Bebidas Gaseosas, Arbega, S.A., en una imagen de sus instalaciones ubicadas en la Vâ”śÂˇa de la Hispanidad nâ”¬â•‘ 31-33, frente al Seminario Metropolitano de San Valero y San Braulio. Fue constituida en 1965 al objeto de embotellar y distribuir gaseosas y bebidas refrescantes analcohâ”śâ”‚licas (sin alcohol), como franquicia local de una potente multinacional norteamericana del sector. Al objeto de promocionar la fidelidad de nuevas generaciones de consumidores, entre otras iniciativas la empresa practicâ”śâ”‚ el fomento de la polâ”śÂˇtica de visitas de centros educativos a esta planta. En 1997 fue absorbida por la Compaâ”śâ–’â”śÂˇa de Bebidas Gaseosas, Cobega, que reconvirtiâ”śâ”‚ las instalaciones cerrâ”śĂ­ndolas. Este suelo industrial fue recalificado como urbanizable, y vendido a una promotora que sobre buena parte del solar resultante tras el derribo promoviâ”śâ”‚ una gran urbanizaciâ”śâ”‚n residencial privada.', 1987, 1987, 1987, 'Anos 80', 'CASABLANCA', 41.63485200, -0.91173500, '0101000020E61000003ECBF3E0EE2CEDBF6DE690D442D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30992968871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30992968871.webp', 'https://www.flickr.com/photos/zaragozaantigua/30992968871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23011, 'Cuartel de Sanidad aâ”śâ–’os 90', 'Vista de la fachada del antiguo Cuartel de Sanidad de Casablanca (Vâ”śÂˇa Ibâ”śÂ®rica 2), que albergaba las tropas de Sanidad Militar y Servicio Geogrâ”śĂ­fico del Ejâ”śÂ®rcito. Tras su derribo, la Agrupaciâ”śâ”‚n Sanitaria se halla en la Base San Jorge de San Juan de Mozarrifar. Fuente visual: www.nrdc-sp.nato.int/inicio.html', 1990, 1990, 1999, 'Anos 90', 'CASABLANCA', 41.63159100, -0.90581600, '0101000020E6100000723106D671FCECBF56B950F9D7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33009926772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33009926772.webp', 'https://www.flickr.com/photos/zaragozaantigua/33009926772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23081, 'Cuartel de Valdespartera 2003', 'Demoliciâ”śâ”‚n del antiguo cuartel de Valdespartera en 2003, como arranque de la denominada "operaciâ”śâ”‚n Valdespartera", que preveâ”śÂˇa la construcciâ”śâ”‚n del 10.000 viviendas de precio asequible en un nuevo barrio al sur de Zaragoza, en terrenos gestionados por la sociedad Ecociudad Valdespartera. El derribo estaba presupuestado en 663.603 euros, en unas instalaciones militares que alcanzaban los 3.4 kilâ”śâ”‚metros cuadrados. Fuente visual: Crâ”śâ”‚nica de Zaragoza. Ayuntamiento de Zaragoza, 2005.', 2003, 2003, 2003, 'Siglo XXI', 'CASABLANCA', 41.61966400, -0.93616300, '0101000020E61000003B35971B0CF5EDBF1841632651CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18149756583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18149756583.webp', 'https://www.flickr.com/photos/zaragozaantigua/18149756583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23117, 'Depâ”śâ”‚sitos de Casablanca 2006', 'Foto: Esther Casas. Obras de acondicionamiento del entorno del nuevo lago artificial lâ”śâ•‘dico (derecha) junto a los antiguos depâ”śâ”‚sitos de agua de Casablanca, en enero de 2006. Ese mismo aâ”śâ–’o, el proyecto estarâ”śĂ­ terminado y abierto al pâ”śâ•‘blico, aunque serâ”śĂ­ necesario esperar hasta el acondicionamiento del Canal Imperial (al fondo), dentro de las obras del Plan de Acompaâ”śâ–’amiento de la Expo 2008, para que estâ”śÂ® en pleno uso, integrado en el nuevo Parque del Canal. Un negocio de hostelerâ”śÂˇa y alquiler de barcas se instalâ”śâ”‚ allâ”śÂˇ en 2011. Fuente: Heraldo de Aragâ”śâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CASABLANCA', 41.63615900, -0.91815600, '0101000020E6100000A20914B18861EDBF2D077AA86DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31067460233.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31067460233.webp', 'https://www.flickr.com/photos/zaragozaantigua/31067460233/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23160, 'Cuartel de Valdespartera 2003', 'Aspecto de las edificaciones del cuartel de Valdespartera en 2003, antes de su derribo ese mismo aâ”śâ–’o para iniciar la creaciâ”śâ”‚n de un nuevo barrio. Fuente: Heraldo de Aragâ”śâ”‚n.', 2003, 2003, 2003, 'Siglo XXI', 'CASABLANCA', 41.62008100, -0.93672100, '0101000020E6100000CD3E8F519EF9EDBF7CEF6FD05ECF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32495841592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32495841592.webp', 'https://www.flickr.com/photos/zaragozaantigua/32495841592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23172, 'Centro comercial Lumier 2008', 'Recreaciâ”śâ”‚n infogrâ”śĂ­fica del exterior del centro comercial Lumier, en la calle Manhattan de Valdespartera. El proyecto fue presentado en 2008 y su inauguraciâ”śâ”‚n anunciada para aâ”śâ–’os sucesivos, hasta 2011. Habrâ”śÂˇa tenido una superficie de 74.000 metros cuadrados, 33.600 de superficie comercial, con un gran hipermercado, 94 tiendas y 5,9 millones de visitas anuales previstas. No se construyâ”śâ”‚. Fuente visual: www.a4arquitectos.es', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.62336000, -0.92545200, '0101000020E6100000C19140834D9DEDBF39D1AE42CACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33165525215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33165525215.webp', 'https://www.flickr.com/photos/zaragozaantigua/33165525215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23202, 'Calle El Greco 2010', 'Foto: Andrâ”śÂ®s Aguilar. Aspecto en enero de 2010 de la calle El Greco, en el barrio de Casablanca, tramo comprendido entre las calles de Encinacorba (a la espalda) y Marcelino â”śĂĽlvarez. Segâ”śâ•‘n sus vecinos, el plan para su asfaltado se remonta a 1970. Se produjo en 2015. Al fondo, fâ”śĂ­brica Ebroacero, en la calle Argualas. Fuente: Heraldo de Aragâ”śâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASABLANCA', 41.62999500, -0.91328300, '0101000020E6100000C1C41F459D39EDBF5FD218ADA3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32546422873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32546422873.webp', 'https://www.flickr.com/photos/zaragozaantigua/32546422873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23211, 'Cocheras Valdespartera 2010', 'Foto: Oliver Duch. Construcciâ”śâ”‚n de las cocheras de los tranvâ”śÂˇas, en la prolongaciâ”śâ”‚n de la avenida Gâ”śâ”‚mez Laguna 160. Al fondo, bloques de la calle de Volver a empezar. Fuente: Heraldo de Aragâ”śâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASABLANCA', 41.62301000, -0.91454900, '0101000020E610000037DDB243FC43EDBF5D8AABCABECF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33553317661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33553317661.webp', 'https://www.flickr.com/photos/zaragozaantigua/33553317661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23219, 'Vâ”śÂˇa Ibâ”śÂ®rica 2015', 'Imagen capturada en la Vâ”śÂˇa Ibâ”śÂ®rica poco antes de llegar a la rotonda de conexiâ”śâ”‚n con la prolongaciâ”śâ”‚n de la avenida de Gâ”śâ”‚mez Laguna, y centrada en los edificios mudâ”śÂ®jares de mediados de los aâ”śâ–’os cincuenta del siglo XX que formaban parte de la subestaciâ”śâ”‚n de Elâ”śÂ®ctricas Reunidas de Zaragoza (actual Endesa) allâ”śÂˇ ubicada. El "Edificio Torreâ”śâ”‚n" de la imagen oculta otro edificio algo menos alto situado justo detrâ”śĂ­s de â”śÂ®l, levemente visible a la izquierda. A pesar de la solicitud de su catalogaciâ”śâ”‚n como interesante muestra de la arquitectura industrial de la segunda mitad del siglo XX en la ciudad, realizada en 2015 por Apudepa, en 2016 estos edificios fueron derribados. Fuese, y no hubo nada. En primer tâ”śÂ®rmino, moderno tendido tranviario de la lâ”śÂˇnea 1, Valdespartera-Parque Goya.', 2015, 2015, 2015, 'Siglo XXI', 'CASABLANCA', 41.62381900, -0.91244400, '0101000020E61000003ACE6DC2BD32EDBFCCCF0D4DD9CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50676947697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50676947697.webp', 'https://www.flickr.com/photos/zaragozaantigua/50676947697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23226, 'Recinto ferial de Valdespartera (virtual) 2019', 'Imagen virtual que recrea una vista nocturna y en altura del recinto ferial de Valdespartera, habilitado para esas funciones en 2006 para sustituir al veterano recinto instalado al final de la calle de Miguel Servet desde 1982, y que desde 2007 ejerce como tal.', 2019, 2019, 2019, 'Siglo XXI', 'CASABLANCA', 41.61966400, -0.93616300, '0101000020E61000003B35971B0CF5EDBF1841632651CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52494578958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52494578958.webp', 'https://www.flickr.com/photos/zaragozaantigua/52494578958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23264, 'Râ”śÂˇo Huerva 1922', 'Inâ”śÂ®dita imagen capturada a espaldas de la Almenara de Nâ”¬Â¬. Sâ”¬Â¬. del Pilar, donde el Canal Imperial de Aragâ”śâ”‚n desagua para reforzar el caudal del râ”śÂˇo Huerva (en primer tâ”śÂ®rmino) y de los riegos de las Adulas y Romareda. A la derecha, alturas de los montes de Torrero en la zona de los Pinares de Venecia, a cuyos pies va fluyendo el cauce del canal en descenso hasta llegar, a la izquierda, a Zaragoza, que se vislumbra tenuemente al fondo.', 1922, 1922, 1922, 'Anos 20', 'CASABLANCA', 41.62280500, -0.90432200, '0101000020E6100000BBB4E1B034F0ECBF84640113B8CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51400490057.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51400490057.webp', 'https://www.flickr.com/photos/zaragozaantigua/51400490057/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23355, 'Esclusas de Casablanca 1934', 'Autovâ”śÂˇa o automotor diesel tipo "Zaragoza", en un viaje de prueba por la lâ”śÂˇnea de ferrocarril de Cariâ”śâ–’ena. La imagen estâ”śĂ­ capturada desde el puente que da continuidad a la carretera de Zaragoza a Valencia, y centrada en el puente del ferrocarril con el fondo de las esclusas y central de Casablanca.', 1934, 1934, 1934, 'Anos 30', 'CASABLANCA', 41.62817000, -0.90843200, '0101000020E6100000D57954FCDF11EDBF062AE3DF67D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15001990735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15001990735.webp', 'https://www.flickr.com/photos/zaragozaantigua/15001990735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23356, 'Fuente de los Incrâ”śÂ®dulos 1930', 'Sociedad Fotogrâ”śĂ­fica de Zaragoza/Sebastiâ”śĂ­n Gâ”śâ”‚mez Cortâ”śÂ®s, 1930. Este monumento fue levantado junto a las esclusas de Casablanca por orden de Ramâ”śâ”‚n Pignatelli, impulsor del Canal Imperial de Aragâ”śâ”‚n, en respuesta a las gentes que no confiaban en que pudiese llevarse a buen tâ”śÂ®rmino la magna obra hidrâ”śĂ­ulica. En su frontal, la inscripciâ”śâ”‚n: "Incredulorum convictioni et viatorum commodo. Anno MDCCLXXXVI", que traducimos: "Para convencimiento de los incrâ”śÂ®dulos y alivio de los caminantes. Aâ”śâ–’o 1786". NOTA: hemos volteado horizontalmente la imagen original, porque las cercanas parcelas que aparecen, quedaban a su derecha. Fuente visual: www.rsfz.es/', 1930, 1930, 1930, 'Anos 30', 'CASABLANCA', 41.62844400, -0.90811100, '0101000020E61000005169C4CC3E0FEDBF08AF5DDA70D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15003804870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15003804870.webp', 'https://www.flickr.com/photos/zaragozaantigua/15003804870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23360, 'Molino de San Carlos aâ”śâ–’os 20', 'AHPZ. Gabriel Faci. Aâ”śâ–’os 20. "Molino de agua." La "Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad" fue constituida en 1893, tras la compra de la concesiâ”śâ”‚n del antiguo molino de San Carlos en Casablanca como generador de electricidad aprovechando el salto de agua, para suministrarla al alumbrado de la ciudad. En el antiguo molino se instalâ”śâ”‚ una nueva turbina de Averly, cuya fuerza serâ”śÂˇa transportada a la estaciâ”śâ”‚n central de la compaâ”śâ–’â”śÂˇa, sita en la calle San Miguel. En la imagen, molino de San Carlos turbinando agua. A la izquierda, las esclusas de Casablanca del Canal Imperial, en cuyo entorno habâ”śÂˇa un amplio conjunto de construcciones anexas que incluâ”śÂˇan puerto fluvial, noria con molino y batanes ademâ”śĂ­s de la Casa de San Carlos (la Casa Blanca, de la que mucho despuâ”śÂ®s tomarâ”śÂˇa su nombre el barrio), que se utilizâ”śâ”‚ como almacâ”śÂ®n y posada y que fue el lugar donde se firmaron las capitulaciones de Zaragoza de 1809, segâ”śâ•‘n informa una placa colocada en su fachada, porque Zaragoza no se rinde, pero sâ”śÂˇ capitula. Vamos, que nos ganaron.', 1920, 1920, 1929, 'Anos 20', 'CASABLANCA', 41.62863500, -0.90876400, '0101000020E61000005307793D9814EDBF7C0F971C77D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15482041181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15482041181.webp', 'https://www.flickr.com/photos/zaragozaantigua/15482041181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23361, 'Ojo del Canal 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" Imagen de "El Ojo del Canal", o puente-acueducto por medio del cual el Canal Imperial salva el râ”śÂˇo Huerva, tras haber pasado por las esclusas de Casablanca. En el momento de capturar la imagen, la almenara de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar estâ”śĂ­ derivando agua sobrante desde el Canal hacia el râ”śÂˇo Huerva. Este paraje era muy apreciado durante los meses de los calores, para refresco, alivio y regocijo ciudadano, y durante todo el aâ”śâ–’o para paseos, excursiones, aventuras. Era cuando el agua del Huerva era agua. Fuente visual: Fotografâ”śÂˇa de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASABLANCA', 41.62253200, -0.90502300, '0101000020E6100000011764CBF2F5ECBF535BEA20AFCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16732611104.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16732611104.webp', 'https://www.flickr.com/photos/zaragozaantigua/16732611104/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23362, 'Esclusas de Casablanca 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" El tâ”śÂˇtulo (la fuente visual asâ”śÂˇ lo cataloga) no se corresponde exactamente con la captura: se trata de una imagen parcial del complejo de las esclusas de Casablanca, donde se salva un importante desnivel del Canal Imperial, que "Elâ”śÂ®ctrica Reunidas" aprovechaba tambiâ”śÂ®n para una "fâ”śĂ­brica de electricidad" que allâ”śÂˇ tenâ”śÂˇa. Muy cerca quedaba la carretera de Zaragoza a Valencia, y la lâ”śÂˇnea de ferrocarril a Cariâ”śâ–’ena, con un andâ”śÂ®n junto a la Fuente de los Incrâ”śÂ®dulos. La carretera y el ferrocarril salvaban el Canal por medio de sendos puentes. Los edificios del fondo, al otro lado del Canal Imperial, se corresponden con el convento y colegio de los Padres Pasionistas de Casablanca, que en 1928 allâ”śÂˇ se habâ”śÂˇan instalado, tras adecuar las previas instalaciones de lo que habâ”śÂˇa sido una harinera, y luego dependencias militares. Entre diciembre de 1939 y junio de 1940, como forma de descongestionar la atestada câ”śĂ­rcel de Torrero, fue reconvertido en "Prisiâ”śâ”‚n Habilitada de Casablanca", hasta que fue desalojado por la oposiciâ”śâ”‚n de los PP. Pasionistas. En 1978 se culminâ”śâ”‚ su derribo. Fuente visual: Fotografâ”śÂˇa de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASABLANCA', 41.62833800, -0.90888200, '0101000020E6100000CE893DB48F15EDBFC26A2C616DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17353076001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17353076001.webp', 'https://www.flickr.com/photos/zaragozaantigua/17353076001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23363, 'Fuente de los Incrâ”śÂ®dulos 1786', 'Fuente de los incrâ”śÂ®dulos, â”śâ”‚leo sobre lienzo, Joaquâ”śÂˇn Pallarâ”śÂ®s, 1928. Colecciâ”śâ”‚n Canal Imperial de Aragâ”śâ”‚n. Representaciâ”śâ”‚n, siglo y medio despuâ”śÂ®s, del momento en que Ramâ”śâ”‚n de Pignatelli, impulsor de las obras del Canal, inaugura junto a las esclusas de Casablanca la llamada Fuente de los Incrâ”śÂ®dulos, erigida en respuesta a quienes no confiaban en que esa infraestructura hidrâ”śĂ­ulica fuese construida.En su frontal, la inscripciâ”śâ”‚n: "Incredulorum convictioni et viatorum commodo. Anno MDCCLXXXVI", que traducimos: "Para convencimiento de los incrâ”śÂ®dulos y alivio de los caminantes. Aâ”śâ–’o 1786". Fuente: Ramâ”śâ”‚n Pignatelli y su â”śÂ®poca, Gobierno de Aragâ”śâ”‚n, 1993.', 1786, 1786, 1786, 'Siglo XIX', 'CASABLANCA', 41.62844400, -0.90811100, '0101000020E61000005169C4CC3E0FEDBF08AF5DDA70D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19260108735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19260108735.webp', 'https://www.flickr.com/photos/zaragozaantigua/19260108735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23364, 'Molino de la Casa Blanca 1833', '"Molino de la Casa Blanca", litografâ”śÂˇa de Faramundo Blanchard. El molino harinero de San Carlos o de la Casa Blanca genera desde 1893 electricidad. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'CASABLANCA', 41.62863500, -0.90876400, '0101000020E61000005307793D9814EDBF7C0F971C77D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19304604860.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19304604860.webp', 'https://www.flickr.com/photos/zaragozaantigua/19304604860/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23366, 'Esclusas de Casablanca 1833', '"Esclusas de San Carlos", litografâ”śÂˇa de Faramundo Blanchard. Esclusas de Casablanca o de San Carlos, junto al Molino del mismo nombre en el Canal Imperial. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'CASABLANCA', 41.62833800, -0.90888200, '0101000020E6100000CE893DB48F15EDBFC26A2C616DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19307474648.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19307474648.webp', 'https://www.flickr.com/photos/zaragozaantigua/19307474648/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23370, 'Almenara del Pilar 1833', '"La almenara Pilar y paso del Canal sobre el râ”śÂˇo Huerva", litografâ”śÂˇa de Faramundo Blanchard. Instalaciones de la almenara de Nuestra Seâ”śâ–’ora del Pilar (que sirve de desagâ”śâ•ťe del Canal al râ”śÂˇo Huerva) y del acueducto que lleva las aguas del Canal sobre las del Huerva, paraje conocido como Ojo del Canal. Permanecen en servicio. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'CASABLANCA', 41.62253200, -0.90502300, '0101000020E6100000011764CBF2F5ECBF535BEA20AFCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19486016262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19486016262.webp', 'https://www.flickr.com/photos/zaragozaantigua/19486016262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23378, 'Puente Caminreal - Canal Imperial 1933', 'Imagen del nuevo puente construido sobre el Canal Imperial, para salvar el paso de las vâ”śÂˇas del ferrocarril de Caminreal a Zaragoza. Hacia la derecha las vâ”śÂˇas conducen a la novâ”śÂˇsima estaciâ”śâ”‚n de Caminreal, en la Almozara, pasando por Miralbueno el Viejo, la carretera de Madrid a Francia por La Junquera, Val del Fierro, Miralbueno, y la carretera de Logroâ”śâ–’o. A la espalda del fotâ”śâ”‚grafo quedarâ”śÂˇan los depâ”śâ”‚sitos de agua de Casablanca. Hacia la izquierda, todo recto hasta Valdespartera, donde la vâ”śÂˇa gira para ponerse paralela a la carretera de Zaragoza a Teruel. Fuente visual: &quot;Ingenierâ”śÂˇa y Construcciâ”śâ”‚n&quot; (Madrid).', 1933, 1933, 1933, 'Anos 30', 'CASABLANCA', 41.63594000, -0.92283000, '0101000020E6100000D690B8C7D287EDBFEF1B5F7B66D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21722907949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21722907949.webp', 'https://www.flickr.com/photos/zaragozaantigua/21722907949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23382, 'Râ”śÂˇo Huerva 1860', '"Almenara de Nuestra Seâ”śâ–’ora del Pilar y paso del Canal Imperial sobre el râ”śÂˇo Huerva." Fotâ”śâ”‚grafo: Mariano Jâ”śâ•‘dez y Ortiz, Esta esplâ”śÂ®ndida fotografâ”śÂˇa, de una calidad sobresaliente, captura el paraje denominado "el Ojo del Canal" (de 13 metros de anchura y 35 metros de altura), por medio del cual el Canal salva mediante un acueducto-puente el cauce del râ”śÂˇo Huerva, y cayendo por gravedad en la Almenara del Pilar, desagua al râ”śÂˇo caudales de agua, y ayuda al vaciado del Canal. Unas decenas de metros a la derecha, del Canal Imperial deriva la acequia de la "Romarera", luego "Romareda". Fuente visual: Museo del Prado.', 1860, 1860, 1860, 'Siglo XIX', 'CASABLANCA', 41.62225100, -0.90475700, '0101000020E61000006077BAF3C4F3ECBF9F73B7EBA5CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23747473619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23747473619.webp', 'https://www.flickr.com/photos/zaragozaantigua/23747473619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23383, 'Ojo del Canal 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" Imagen de "el Ojo del Canal", o puente-acueducto por medio del cual el Canal Imperial salva el râ”śÂˇo Huerva, tras haber pasado por las esclusas de Casablanca (a la izquierda). La imagen se ha capturado desde la orilla del Huerva, cuando este râ”śÂˇo era aâ”śâ•‘n una corriente fluvial natural en torno a la cual habâ”śÂˇa un buen puâ”śâ–’ado de ubicaciones donde la gente pescaba, se baâ”śâ–’aba, hacâ”śÂˇan paseos... y todo sin tener que ponerles etiquetas de "corredor verde", "andador", u otras postmodernas etiquetas. Por encima, el Canal continâ”śâ•‘a aâ”śÂ®reo hacia la derecha, hacia el parque de Buenavista. Fuente visual: Fotografâ”śÂˇa de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASABLANCA', 41.62206100, -0.90508300, '0101000020E6100000554CA59F70F6ECBFFC8EE1B19FCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26794344485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26794344485.webp', 'https://www.flickr.com/photos/zaragozaantigua/26794344485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23384, 'Carretera de Valencia c.1925', 'Puente de la carretera de Zaragoza a Valencia, a su paso sobre el Canal Imperial de Aragâ”śâ”‚n. Fue inaugurado en 1786. Al fondo, las esclusas de Casablanca. Fuente visual: Foto: Josep Gaspar i Serra, Arxiu Generalitat de Catalunya.', 1925, 1925, 1925, 'Anos 20', 'CASABLANCA', 41.62807900, -0.90826200, '0101000020E6100000BB6246787B10EDBFF62686E464D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27585999193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27585999193.webp', 'https://www.flickr.com/photos/zaragozaantigua/27585999193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23391, 'Canal Imperial 2008', 'Vista aâ”śÂ®rea de las obras de acondicionamiento del Canal Imperial de Aragâ”śâ”‚n en 2008. Se trata del tramo en el que â”śÂ®ste pasa sobre el râ”śÂˇo Huerva, junto a la almenara del Pilar. Fuente: Ayuntamiento de Zaragoza.', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.62287200, -0.90552200, '0101000020E610000055DFF94509FAECBF0CCC0A45BACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33125109391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33125109391.webp', 'https://www.flickr.com/photos/zaragozaantigua/33125109391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23396, 'Canal Imperial 1934', 'Autovâ”śÂˇa o automotor diesel tipo "Zaragoza" en un viaje de prueba por la lâ”śÂˇnea del clausurado ferrocarril de Cariâ”śâ–’ena. La imagen estâ”śĂ­ capturada desde el puente que da continuidad a la carretera de Zaragoza a Valencia, y centrada en el ferroviario puente tendido sobre el cauce del Canal Imperial de Aragâ”śâ”‚n junto a las esclusas y la fâ”śĂ­brica de electricidad de Casablanca de Elâ”śÂ®ctricas Reunidas de Zaragoza. A la derecha y fuera de plano quedaba el convento y colegio de los Padres Pasionistas de Casablanca. Tras el automotor, arbolado panorama sobre el que emergen al fondo los montes de Valdespartera y la altura de la ermita de Santa Bâ”śĂ­rbara.', 1934, 1934, 1934, 'Anos 30', 'CASABLANCA', 41.62820200, -0.90846400, '0101000020E6100000ADFC32182312EDBF12A452EC68D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49621359021.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49621359021.webp', 'https://www.flickr.com/photos/zaragozaantigua/49621359021/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23400, 'Valdespartera 1912', 'Foto: Lorenzo Almarza. ''"Un monoplano militar en Valdespartera". Varios de los primeros aviones que maniobraron en la ciudad fueron pilotados por militares franceses como Teixier y Garnier, que en el marco de unas "Fiestas de la Aviaciâ”śâ”‚n" celebradas en el Campo de Valdespartera el 6 de octubre de 1912, volaron los aparatos por el cielo sobre Zaragoza. Fuente visual: Archivo Diputaciâ”śâ”‚n Provincial de Huesca.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14942623399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14942623399.webp', 'https://www.flickr.com/photos/zaragozaantigua/14942623399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23402, 'Valdespartera 1911', 'Imagen capturada en el aerâ”śâ”‚dromo de Valdespartera durante la semana de aviaciâ”śâ”‚n de abril de 1911.', 1911, 1911, 1911, 'Anos 10', 'CASABLANCA', 41.62469400, -0.93180800, '0101000020E61000005ED6C4025FD1EDBFF30016F9F5CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15206485345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15206485345.webp', 'https://www.flickr.com/photos/zaragozaantigua/15206485345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23404, 'Valdespartera 1912', 'Fotografâ”śÂˇa aâ”śÂ®rea tomada en el aerâ”śâ”‚dromo de Valdespartera de Zaragoza. Fuente: Fotografâ”śÂˇa de Aurelio Grasa publicada en la pâ”śĂ­gina 50 del catâ”śĂ­logo "Aurelio Grasa reportero grâ”śĂ­fico 1910-1917", RSFZ, Galerâ”śÂˇa Costa,3. Zaragoza 2000. www.barbozagrasa.es/primera-foto-aerea-de-aurelio-grasa-e...', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19264829971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19264829971.webp', 'https://www.flickr.com/photos/zaragozaantigua/19264829971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23409, 'Valdespartera 2002', 'Plano mediante infografâ”śÂˇa del proyecto del barrio de Valdespartera de Zaragoza en 2002. En 2001, las 243 hectâ”śĂ­reas del Acuartelamiento de Valdespartera fueron cedidas por el Ministerio de Defensa al Ayuntamiento de Zaragoza, para construir un barrio, aprobado en pleno en noviembre de 2002, enmarcado en las polâ”śÂˇticas de expansiâ”śâ”‚n urbanâ”śÂˇstica salvaje propias de la â”śÂ®poca. El proyecto original incluâ”śÂˇa como atractivo principal el nuevo campo de fâ”śâ•‘tbol de la ciudad (zona gris a la derecha), que pronto fue desestimado y borrado de las representaciones grâ”śĂ­ficas. No asâ”śÂˇ la pista de esquâ”śÂˇ cubierta junto a un anfiteatro y una pista de hielo (arriba a la izquierda, hoy recinto ferial). Valdespartera se sitâ”śâ•‘a entre el Cuarto Cinturâ”śâ”‚n (izquierda), Montecanal y la avenida Gâ”śâ”‚mez Laguna (derecha), y la carretera de Valencia (abajo). Estâ”śĂ­ atravesado de norte a sur por la autovâ”śÂˇa Mudâ”śÂ®jar (en la imagen, de izquierda a derecha). Fuente: www.valdespartera.es/', 2002, 2002, 2002, 'Siglo XXI', 'CASABLANCA', 41.62413000, -0.93065700, '0101000020E61000001F645930F1C7EDBFEB39E97DE3CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22001742031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22001742031.webp', 'https://www.flickr.com/photos/zaragozaantigua/22001742031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23410, 'Valdespartera 2002', 'Zaragoza. Plan parcial del sector 89/4 Valdespartera. Ramâ”śâ”‚n Betrâ”śĂ­n. Ayuntamiento de Zaragoza, 2002. En 2001, las 243 hectâ”śĂ­reas del Acuartelamiento de Valdespartera fueron cedidas por el Ministerio de Defensa al Ayuntamiento de Zaragoza, para construir un barrio, aprobado en pleno en noviembre de 2002, enmarcado en las polâ”śÂˇticas de expansiâ”śâ”‚n urbanâ”śÂˇstica salvaje propias de la â”śÂ®poca. El proyecto original incluâ”śÂˇa como atractivo principal el nuevo campo de fâ”śâ•‘tbol de la ciudad (arriba a la derecha), que pronto fue desestimado y borrado de las representaciones grâ”śĂ­ficas (ver www.flickr.com/photos/zaragozaantigua/22001742031). No asâ”śÂˇ la pista de esquâ”śÂˇ cubierta junto a un anfiteatro y una pista de hielo (abajo, hoy recinto ferial). Valdespartera se sitâ”śâ•‘a entre el Cuarto Cinturâ”śâ”‚n (abajo), Montecanal y la avenida Gâ”śâ”‚mez Laguna (arriba), y la carretera de Valencia (derecha). Estâ”śĂ­ atravesado de norte a sur por la autovâ”śÂˇa Mudâ”śÂ®jar. Fuente: Zaragoza 1908-2008. Colegio Oficial de Arquitectos de Aragâ”śâ”‚n, 2009.', 2002, 2002, 2002, 'Siglo XXI', 'CASABLANCA', 41.62413000, -0.93065700, '0101000020E61000001F645930F1C7EDBFEB39E97DE3CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22340119396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22340119396.webp', 'https://www.flickr.com/photos/zaragozaantigua/22340119396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23412, 'Fuente de la Junquera 2008', 'Otra de las promesas de la Expo 2008 que quedâ”śâ”‚ sin cumplir fue la "integraciâ”śâ”‚n final" del râ”śÂˇo Huerva en la ciudad. "Tres nuevas pasarelas, y una red de andadores que hacen accesibles sus riberas", un poco de magia, abracadabra, y ya estâ”śĂ­. Esta era la visiâ”śâ”‚n del asunto que transmitiâ”śâ”‚ la Confederaciâ”śâ”‚n Hidrogrâ”śĂ­fica del Ebro mediante los medios creadores de opiniâ”śâ”‚n para las masas. En el caso que ocupa la imagen, se trataba del tramo del râ”śÂˇo Huerva donde el nuevo parque de la Fuente de la Junquera, un muy interesante paraje fluvial (quâ”śÂ® recuerdos), sâ”śâ”‚lo que a unos cinco kilâ”śâ”‚metros del "centro" de la ciudad consolidada. Los ciudadanos que lo queremos disfrutar, tenemos un agradable y natural paseo hasta â”śÂ®l, a no ser que se emplee algâ”śâ•‘n vehâ”śÂˇculo motorizado. No hay grandes aglomeraciones, parece ser. Como quiera que sea la cosa, este nuevo parque, de dos hectâ”śĂ­reas de extensiâ”śâ”‚n, incluâ”śÂˇa una pasarela de madera de 13 metros de largo, 7000 metros cuadrados de câ”śÂ®sped en rollos, 1000 metros de riego por goteo, 2500 metros de caminos, ademâ”śĂ­s de numerosos â”śĂ­rboles y especies mediterrâ”śĂ­neas. En la imagen, aspecto parcial del nuevo parque, con el râ”śÂˇo Huerva a la derecha, la pasarela, los distintos niveles de terraza, los rollos de câ”śÂ®sped, y las nuevas especies plantadas. Al fondo, la urbanizaciâ”śâ”‚n Fuente de la Junquera y sus rojas techumbres, y de telâ”śâ”‚n escâ”śÂ®nico, tras la carretera de Valencia, los megabloques en construcciâ”śâ”‚n de Valdespartera, correspondientes al entorno de la plaza de "Cleopatra", y las calles "El maquinista de La General", "Los pâ”śĂ­jaros", y "La Reina de â”śĂĽfrica". Lo que es propiamente la Fuente de la Junquera, la pobre queda a unos pocos metros hacia la derecha, fuera de plano. Fuente visual: â”śĂĽlvaro Calvo, para Heraldo de Aragâ”śâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.61479400, -0.91540400, '0101000020E61000002B155454FD4AEDBF76E3DD91B1CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24483199260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24483199260.webp', 'https://www.flickr.com/photos/zaragozaantigua/24483199260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23414, 'CAE 1895', 'Imagen del antiguo molino de San Carlos en Casablanca, desde 1893 de la Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad (CAE), turbinando agua del Canal Imperial para generar electricidad con destino al suministro urbano. A finales de 1904 esta empresa se fusionâ”śâ”‚ con la Electra Peral Zaragozana, y con Fuerzas Motrices del Gâ”śĂ­llego, un paso para la gran integraciâ”śâ”‚n de 1911 que dio como resultado Elâ”śÂ®ctricas Reunidas de Zaragoza. En la imagen, las dos turbinas a pleno funcionamiento. Fuente visual: Foto Estudio Coyne, AHPZ.', 1895, 1895, 1895, 'Siglo XIX', 'CASABLANCA', 41.62863500, -0.90876400, '0101000020E61000005307793D9814EDBF7C0F971C77D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30857496524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30857496524.webp', 'https://www.flickr.com/photos/zaragozaantigua/30857496524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23415, 'Câ”śĂ­mping 2008', 'Vista aâ”śÂ®rea centrada en el Câ”śĂ­mping Municipal "Ciudad de Zaragoza", inaugurado en 2008 en la finca El Gracijo, en el lâ”śÂˇmite del barrio de Casablanca junto al Canal Imperial. Arriba a la derecha, Valdefierro. Abajo a la derecha, tras la calle San Juan Bautista de la Salle, Rosales del Canal. Fuente: eszaragoza.blogspot.com', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.63864400, -0.94186700, '0101000020E6100000EECF4543C623EEBFB0E42A16BFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30913077652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30913077652.webp', 'https://www.flickr.com/photos/zaragozaantigua/30913077652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23417, 'Casa Blanca c.1900', 'Imagen del complejo dieciochesco con las esclusas (izquierda) y antiguo molino de San Carlos en Casablanca (derecha), instalaciâ”śâ”‚n que la Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad (CAE), y mediante el turbinado de agua del Canal Imperial, utilizaba para generar electricidad con destino al suministro urbano. En primer tâ”śÂ®rmino, el trazado del primitivo ferrocarril de vâ”śÂˇa mâ”śÂ®trica que unâ”śÂˇa desde 1887 Cariâ”śâ–’ena con Zaragoza, y que en 1913 pasarâ”śÂˇa a formar parte del Ferrocarril Central de Aragâ”śâ”‚n. En este punto se ubicaba el apeadero de Casablanca.', 1900, 1900, 1900, 'Anos 1900', 'CASABLANCA', 41.62863500, -0.90876400, '0101000020E61000005307793D9814EDBF7C0F971C77D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31575799160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31575799160.webp', 'https://www.flickr.com/photos/zaragozaantigua/31575799160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23418, 'El Gracijo 2007', 'En 2004, el Ayuntamiento de Zaragoza permutâ”śâ”‚ los terrenos de la finca El Gracijo por los del antiguo câ”śĂ­mping de la ciudad (con derecho a elevar allâ”śÂˇ 72 viviendas), para construir en aquella finca el nuevo câ”śĂ­mping, inaugurado en 2008. La familia Escoriaza utilizaba como entrada a su villa de recreo la original puerta de rejerâ”śÂˇa del Gran Hotel, construido en 1929 y reformado en 1981, tras su compra por Arturo Beltrâ”śĂ­n. Pese a que estaba previsto que esta puerta permaneciese en el nuevo câ”śĂ­mping, en 2010 se trasladâ”śâ”‚ al Pabellâ”śâ”‚n de Ceremonias del Parque del Agua Luis Buâ”śâ–’uel. En la foto, obras de acondicionamiento en agosto de 2007 de la finca El Gracijo para su conversiâ”śâ”‚n en nuevo câ”śĂ­mping, con la puerta del Gran Hotel en el centro. La ubicaciâ”śâ”‚n es en la calle San Juan Bautista de la Salle s/n, en el lâ”śÂˇmite del barrio de Casablanca, junto al Canal Imperial y cerca de Valdefierro. Fuente visual: Heraldo de Aragâ”śâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'CASABLANCA', 41.63864400, -0.94186700, '0101000020E6100000EECF4543C623EEBFB0E42A16BFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31628700266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31628700266.webp', 'https://www.flickr.com/photos/zaragozaantigua/31628700266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23420, 'Pre San Juan Bautista de la Salle 2008', 'Foto: Juan Carlos Arcos. Construcciâ”śâ”‚n del vial que serâ”śĂ­ denominado calle de San Juan Bautista de la Salle, entre los barrios de Valdefierro (izquierda) y Montecanal (derecha). Unirâ”śĂ­ la carretera de Madrid (luego avenida de Manuel Rodrâ”śÂˇguez Ayuso) con la avenida de Gâ”śâ”‚mez Laguna (al fondo). Sobre el horizonte, la torre de la Cooperativa de Auto Taxi y el centro de formaciâ”śâ”‚n profesional La Salle Santo â”śĂĽngel. Esta infraestructura serâ”śĂ­ inaugurada en diciembre de 2008 con la denominaciâ”śâ”‚n provisional de vâ”śÂˇa Parque del Canal. Fuente: Heraldo de Aragâ”śâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.63267800, -0.93066600, '0101000020E6100000ECF82F1004C8EDBF0873BB97FBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31990889483.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31990889483.webp', 'https://www.flickr.com/photos/zaragozaantigua/31990889483/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23422, 'Valdespartera 1912', 'Imagen capturada durante las "fiestas de aviaciâ”śâ”‚n" incluidas como profana actividad en las fiestas del Pilar de ese aâ”śâ–’o. Los pilotos franceses Teixier y Garnier, pioneros de la aviaciâ”śâ”‚n, realizaron magnâ”śÂˇficos vuelos de exhibiciâ”śâ”‚n en el aerâ”śâ”‚dromo de Valdespartera, alcanzando alturas vertiginosas de hasta 1000 metros, ante la entregada parroquia venida a estos esteparios parajes del suroeste de la ciudad. Al atardecer, y sobre el fondo de los escarpados vales, aterrizaje de uno de los aparatos utilizados, un monoplano Blâ”śÂ®riot modelo XI pilotado por Lâ”śÂ®once Garnier que, ademâ”śĂ­s de protagonizar hazaâ”śâ–’as civiles como la de sobrevolar por primera vez los Pirineos, ese mismo aâ”śâ–’o estaba siendo utilizado como arma de guerra por el reino de Italia en su invasiâ”śâ”‚n colonialista de la Libia otomana, operaciâ”śâ”‚n que los agresores denominaron "pacificaciâ”śâ”‚n de Libia". Fuente visual: foto Luis Gandâ”śâ•‘ Mercadal, en patrimoniocultural.unizar.es/node/3344', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34571695595.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34571695595.webp', 'https://www.flickr.com/photos/zaragozaantigua/34571695595/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23423, 'Apeadero de Casablanca 1912', 'Imagen capturada desde el camino que en paralelo al Canal Imperial ascendâ”śÂˇa hasta el entorno de la esclusas de Casablanca. A la izquierda, el puente por el que cruza la carretera de Zaragoza a Valencia. Al fondo, a la izquierda, el camino de sirga y el convento de los PP. Pasionistas. De fondo, el antiguo molino de San Carlos que desde 1893 turbinaba agua del Canal como central de electricidad, en ese momento para la reciente empresa Elâ”śÂ®ctricas Reunidas de Zaragoza. A la derecha, el apeadero de Casablanca del ferrocarril de vâ”śÂˇa estrecha de Zaragoza a Cariâ”śâ–’ena. Fuente visual: El fotâ”śâ”‚grafo Luis Gandâ”śâ•‘ Mercadal. Una crâ”śâ”‚nica visual 1910-1930.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.62806000, -0.90801200, '0101000020E610000086048C2E6F0EEDBF7FF6234564D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35966619934.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35966619934.webp', 'https://www.flickr.com/photos/zaragozaantigua/35966619934/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23424, 'Valdespartera 1912', 'Imagen capturada durante las "fiestas de aviaciâ”śâ”‚n" que fueron incluidas en el programa de actos de las locales fiestas del mes de octubre, en la que los pilotos franceses pioneros de la aviaciâ”śâ”‚n Teixier y Garnier realizaron magnâ”śÂˇficos vuelos de exhibiciâ”śâ”‚n en el aerâ”śâ”‚dromo de Valdespartera. En la imagen, instalaciones del aerâ”śâ”‚dromo en los esteparios parajes del suroeste de la ciudad, y uno de los aparatos utilizados, un monoplano Blâ”śÂ®riot modelo XI pilotado por Lâ”śÂ®once Garnier, rodeado de curiosos y pâ”śâ•‘blico asistente a las exhibiciones. Fuente visual: El fotâ”śâ”‚grafo Luis Gandâ”śâ•‘ Mercadal. Una crâ”śâ”‚nica visual 1910-1930.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37246219881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37246219881.webp', 'https://www.flickr.com/photos/zaragozaantigua/37246219881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23425, 'Valdespartera 2007', 'Vista aâ”śÂ®rea parcial de la construcciâ”śâ”‚n del barrio de Valdespartera en 2007. A la derecha, la autovâ”śÂˇa a Valencia y el râ”śÂˇo Huerva. Abajo, el Cuarto Cinturâ”śâ”‚n de ronda. Fuente: www.valdespartera.es', 2007, 2007, 2007, 'Siglo XXI', 'CASABLANCA', 41.61982400, -0.92727100, '0101000020E610000056EF703B34ACEDBF51A3906456CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39795780815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39795780815.webp', 'https://www.flickr.com/photos/zaragozaantigua/39795780815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23426, 'Valdespartera 2007', 'Vista aâ”śÂ®rea del suroeste de Zaragoza, con el barrio de Valdespartera en construcciâ”śâ”‚n en el centro. Abajo, urbanizaciâ”śâ”‚n Fuente de La Junquera. Arriba, Montecanal, el futuro Arcosur, la Plataforma Logâ”śÂˇstica PLAZA y el aeropuerto. Fuente: www.valdespartera.es', 2007, 2007, 2007, 'Siglo XXI', 'CASABLANCA', 41.61982400, -0.92727100, '0101000020E610000056EF703B34ACEDBF51A3906456CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40690939811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40690939811.webp', 'https://www.flickr.com/photos/zaragozaantigua/40690939811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23429, 'Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad 1895', 'Imagen capturada en el interior del antiguo molino de San Carlos en Casablanca, cuya concesiâ”śâ”‚n habâ”śÂˇa comprado en 1893 la reciâ”śÂ®n constituida Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad para producir electricidad de orâ”śÂˇgen hidrâ”śĂ­ulico y suministrarla al alumbrado nocturno de Zaragoza. En la imagen, tres operarios posan alrededor del alternador monofâ”śĂ­sico Brown Boveri accionado en la estancia de la derecha por una turbina Fountain-Girard. Desde este alternador se transportaba luego la fuerza producida a la estaciâ”śâ”‚n subsidiaria de la compaâ”śâ–’â”śÂˇa sita en la calle de San Miguel, en la manzana entre las calles de Porcell y de Blancas. Allâ”śÂˇ, dos dinamos eran accionadas por esta energâ”śÂˇa y durante la noche proporcionaban corriente continua a la red elâ”śÂ®ctrica. En 1904 esta compaâ”śâ–’â”śÂˇa, junto con la Electra Peral y Fuerzas Motrices del Gâ”śĂ­llego, se agruparon y formaron Elâ”śÂ®ctricas Reunidas de Zaragoza.', 1895, 1895, 1895, 'Siglo XIX', 'CASABLANCA', 41.62886800, -0.90871000, '0101000020E6100000878A71FE2614EDBF1EC022BF7ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50294596893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50294596893.webp', 'https://www.flickr.com/photos/zaragozaantigua/50294596893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23430, 'Esclusas Casablanca c.1900', 'Imagen capturada con el fondo del antiguo molino de San Carlos en Casablanca utilizado por la Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad (CAE) para turbinar agua del Canal Imperial y generar electricidad con destino al suministro urbano. En primer tâ”śÂ®rmino, desde donde se ha tirado la fotografâ”śÂˇa, estaba el trazado del primitivo ferrocarril de vâ”śÂˇa mâ”śÂ®trica que unâ”śÂˇa desde 1887 Cariâ”śâ–’ena con Zaragoza. A la izquierda y fuera de plano, las esclusas de Casablanca.', 1900, 1900, 1900, 'Anos 1900', 'CASABLANCA', 41.62844400, -0.90811100, '0101000020E61000005169C4CC3E0FEDBF08AF5DDA70D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50941523413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50941523413.webp', 'https://www.flickr.com/photos/zaragozaantigua/50941523413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23432, 'Leoncio Garnier 1912', 'El francâ”śÂ®s Leoncio Garnier estaba establecido desde 1905 en San Sebastiâ”śĂ­n, donde regentaba un garaje de autos. Cuando poco despuâ”śÂ®s comenzâ”śâ”‚ la eclosiâ”śâ”‚n de la aviaciâ”śâ”‚n, Leoncio se volcâ”śâ”‚ en ella con el espâ”śÂˇritu de los locos pioneros, construyâ”śÂ®ndose un aparato monoplano volador que serâ”śÂˇa el primero de sus caracterâ”śÂˇsticas realizado en Espaâ”śâ–’a. Desde entonces, y aunque mantenâ”śÂˇa su negocio del garaje, se dedicâ”śâ”‚ completamente a volar en las denominadas "fiestas de la aviaciâ”śâ”‚n" que proliferaron como un innovador componente de la programaciâ”śâ”‚n festiva en muchas ciudades espaâ”śâ–’olas. De esta forma, en 1912 Leoncio ya llevaba realizados solo ese aâ”śâ–’o 209 vuelos a lo largo y ancho de la geografâ”śÂˇa peninsular, cuando en octubre recayâ”śâ”‚ en Zaragoza, contratado para volar durante las fiestas del Pilar en el campo de Valdespartera. Lo hizo con el aeroplano de la imagen: un monoplano Bleriot tipo XI con motor de 50 caballos de fuerza, capaz de llevar a un piloto que no sobrepasara los sesenta kilos de peso... En uno de los vuelos estuvo en el aire diecisâ”śÂ®is minutos, recorriendo treinta kilâ”śâ”‚metros a una altura mâ”śĂ­xima de doscientos metros. El pâ”śâ•‘blico llegado desde la ciudad y las primeras autoridades de la misma le felicitaron por la hazaâ”śâ–’a. Dos aâ”śâ–’os mâ”śĂ­s tarde y hasta 1918 Leoncio combatiâ”śâ”‚ como Lâ”śÂ®once bajo la bandera francesa en la Gran Guerra contra Alemania, sobreviviendo a este terrible conflicto.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61982400, -0.92727100, '0101000020E610000056EF703B34ACEDBF51A3906456CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53457709300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53457709300.webp', 'https://www.flickr.com/photos/zaragozaantigua/53457709300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23433, 'Valdespartera 1912', 'Fotograma de un breve e interesante reportaje dedicado a las fiestas de la Aviaciâ”śâ”‚n incluidas en el programa de las Fiestas del Pilar de 1912, cuando los pilotos franceses Henri Tixier y Lâ”śÂ®once Garnier fueron contratados para realizar varias demostraciones aâ”śÂ®reas en el improvisado aerâ”śâ”‚dromo de Valdespartera. Aquâ”śÂˇ posan ambos y el mecâ”śĂ­nico de Tixier ante un monoplano Blâ”śÂ®riot-XI utilizado por â”śÂ®ste para la ocasiâ”śâ”‚n, en la provisional estructura construida para albergarlo.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54656086264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54656086264.webp', 'https://www.flickr.com/photos/zaragozaantigua/54656086264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23722, 'Santa Inâ”śÂ®s 1965', 'Imagen desde las alturas para contemplar el moderno monasterio de Santa Inâ”śÂ®s de las Madres Dominicas contemplativas de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, que en 1949 traspasaron a las Madres Dominicas de la Anunciata su convento-colegio de la calle de Santa Inâ”śÂ®s, y se vinieron a recaer a la despejada ribera del Canal Imperial, cerca de la carretera de enlaces. A este complejo conventual, construido entre 1961-63 segâ”śâ•‘n diseâ”śâ–’o de fray Francisco Coello de Portugal, se accedâ”śÂˇa principalmente desde el antiguo camino de la Mosquetera (abajo, a la izquierda), y confrontaba, a la izquierda, con las instalaciones de la planta embotelladora Aragonesa de Bebidas Gaseosas (ARBEGA), S.A. Al otro lado del Canal, a la derecha, fuera de plano, el humedal de los depâ”śâ”‚sitos de agua de Casablanca. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.63460300, -0.91335500, '0101000020E6100000276BD443343AEDBFC478CDAB3AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31821087335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31821087335.webp', 'https://www.flickr.com/photos/zaragozaantigua/31821087335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23993, 'Valdespartera 1958', 'Rodaje del filme "Salomâ”śâ”‚n y la Reina de Saba" en los esteparios montes de Valdespartera, considerados por la MGM muy parecidos a los parajes de la penâ”śÂˇnsula del Sinaâ”śÂˇ. En una pausa, los actores principales (Tyrone Power, antes de su ataque al corazâ”śâ”‚n, Gina Lollobrigida, y George Sanders) estâ”śĂ­n comentando alguna cuestiâ”śâ”‚n relacionada con la prâ”śâ”‚xima escena. Pero con la incorporaciâ”śâ”‚n de la maquilladora, y el imprudente conductor del carro, estâ”śĂ­n a punto de constituirse en una reuniâ”śâ”‚n pâ”śâ•‘blica que supera el nâ”śâ•‘mero de tres personas, y como no tienen permiso previo de la Autoridad, un funcionario de la Guardia Civil atento centinela por si recibe orden de la Superioridad para intervenir. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1958, 1958, 1958, 'Anos 50', 'CASABLANCA', 41.62413000, -0.93065700, '0101000020E61000001F645930F1C7EDBFEB39E97DE3CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19478470559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19478470559.webp', 'https://www.flickr.com/photos/zaragozaantigua/19478470559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24374, 'Parroquia paulista de Casablanca 1971', 'Imagen de la capilla que hacâ”śÂˇa las funciones, desde 1965, de iglesia parroquial de San Vicente de Paâ”śâ•‘l (Padres Paâ”śâ•‘les) en Casablanca, entre la carretera de los enlaces, y el Canal Imperial. En el momento de capturar la imagen, se estâ”śĂ­ procediendo a ensanchar la carretera de Valencia (luego Vâ”śÂˇa ibâ”śÂ®rica), lo que conllevarâ”śĂ­ la demoliciâ”śâ”‚n de edificios como el de esta parroquia (y las viviendas a su lado), y la remociâ”śâ”‚n de la Fuente de los Incrâ”śÂ®dulos, visible unas decenas de metros hacia la izquierda. La fuente fue desmontada y situada en su actual ubicaciâ”śâ”‚n, mâ”śĂ­s cerca de las esclusas de Casablanca. Ambos elementos (fuente y capilla) habâ”śÂˇan sido construidos con ocasiâ”śâ”‚n de la llegada de las aguas del Canal Imperial a Zaragoza en 1787, y esta capilla se levantâ”śâ”‚ bajo la invocaciâ”śâ”‚n (rarâ”śÂˇsima) de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, con ceremonias los dâ”śÂˇas festivos.', 1971, 1971, 1971, 'Anos 70', 'CASABLANCA', 41.62920500, -0.90765900, '0101000020E61000002A711DE38A0BEDBF66BD18CA89D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15711548616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15711548616.webp', 'https://www.flickr.com/photos/zaragozaantigua/15711548616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24853, 'Calle Argualas 1973', 'Imagen del novisimo polâ”śÂˇgono residencial de Argualas, barrio de Casablanca, en el entorno de la plaza de Nâ”¬Â¬ Sâ”¬Â¬ de las Nieves. La captura se ha realizado en el cruce de la calle Argualas, con la de Brazato. Al fondo, la calle de Riglos. Tras la supresiâ”śâ”‚n en 1971 de la lâ”śÂˇnea 15 del tranvâ”śÂˇa "Casablanca", la lâ”śÂˇnea 30 del autobâ”śâ•‘s urbano fue la designada para dar servicio a este barrio de la periferia, sobre todo a esta nueva zona, en la margen derecha del Canal Imperial. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'CASABLANCA', 41.62635400, -0.91242000, '0101000020E610000018EC866D8B32EDBF01DC2C5E2CD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30155372721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30155372721.webp', 'https://www.flickr.com/photos/zaragozaantigua/30155372721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24982, 'Depâ”śâ”‚sitos de Casablanca c.1990', 'Foto: Rafael Margalâ”śÂ®. Vista aâ”śÂ®rea de los depâ”śâ”‚sitos de agua de Casablanca, junto al Canal Imperial. Estas instalaciones fueron construidas en 1912 como principal reserva de agua potable de la ciudad. Entre 2006 y 2009, el recinto se reconvirtiâ”śâ”‚ en espacio lâ”śâ•‘dico, con un servicio de cafeterâ”śÂˇa inaugurado en 2011, luego cerrado y vuelto a licitar en 2015. Forma parte del Parque del Canal, concebido en el Plan de Acompaâ”śâ–’amiento de la Expo 2008. Cuenta con un lago y un gâ”śÂ®iser artificiales. Los actuales depâ”śâ”‚sitos se encuentran en la Vâ”śÂˇa Hispanidad. Fuente visual: www.facebook.com/photo.php?fbid=1711734895716876&set=...', 1990, 1990, 1990, 'Anos 90', 'CASABLANCA', 41.63508800, -0.91828300, '0101000020E6100000EA20AF079362EDBF810A47904AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24617860556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24617860556.webp', 'https://www.flickr.com/photos/zaragozaantigua/24617860556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25140, 'Seminario Conciliar 1945', 'Sello sin valor postal para recaudar fondos destinados a la construcciâ”śâ”‚n del "Nuevo Seminario Conciliar de Casablanca" en 1945. â”śĂ«ste fue el aâ”śâ–’o de la colocaciâ”śâ”‚n de su primera piedra, siendo inaugurado en 1952, segâ”śâ•‘n proyecto de Santiago Lagunas, Casimiro Lanaja y Manuel Martâ”śÂˇnez de Ubago, de formas historicistas neorromâ”śĂ­nicas y neogâ”śâ”‚ticas. La fachada principal, cuyo torreâ”śâ”‚n de acceso no se terminâ”śâ”‚ segâ”śâ•‘n lo previsto, se halla en las actuales traseras del edificio remodelado en 2008 para dependencias del Ayuntamiento, con acceso por Vâ”śÂˇa de la Hispanidad 20. Fuente visual: www.delcampe.net', 1945, 1945, 1945, 'Anos 40', 'CASABLANCA', 41.63542600, -0.91046000, '0101000020E6100000FC1D8A027D22EDBF9983A0A355D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22613192604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22613192604.webp', 'https://www.flickr.com/photos/zaragozaantigua/22613192604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25614, 'Vista legionaria 1973', 'A la entrada del Parque de Atracciones hay un monumento a los muertos propios del oximorâ”śâ”‚nico "Tercio de Extranjeros", o "Legiâ”śâ”‚n Espaâ”śâ–’ola", cuyo gran atractivo son unas vistas singulares de la ciudad, como la presente. De derecha a izquierda, y articulados por el paseo de Isabel la Catâ”śâ”‚lica: la Residencia Sanitaria "Josâ”śÂ® Antonio", el Colegio de Huâ”śÂ®rfanos de Magisterio, y el complejo de rascacielos de la "Residencial Isabel la Catâ”śâ”‚lica". Ya en la Vâ”śÂˇa Ibâ”śÂ®rica, el enorme complejo del Hospital Militar y las viviendas militares del otro lado; el Centro Regional de Estudios Teolâ”śâ”‚gicos de Aragâ”śâ”‚n; el reciente y privado Colegio Montearagâ”śâ”‚n; y el no menos reciente monasterio Cisterciense de Santa Lucâ”śÂˇa, aquâ”śÂˇ emigrado desde la plaza de Santo Domingo. A los pies de todo esto, el râ”śÂˇo Huerva fluye calladamente. En la mâ”śĂ­s despejada margen derecha, los viveros municipales. Fuente visual: Foto Monge, Diario "Amanecer", 24/01/1973.', 1973, 1973, 1973, 'Anos 70', 'CASABLANCA', 41.62928500, -0.90337800, '0101000020E6100000E0A0BDFA78E8ECBF836E2F698CD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19375162676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19375162676.webp', 'https://www.flickr.com/photos/zaragozaantigua/19375162676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
